{
  "version": 3,
  "sources": ["../src/atsDetector/platformRegistry.ts", "../src/atsDetector/index.ts", "../src/utils/fuzzy.ts", "../src/savedResponses/matcher.ts", "../src/fieldMatcher/index.ts", "../src/adapters/workday/index.ts", "../src/adapters/greenhouse/index.ts", "../src/adapters/lever/index.ts", "../src/adapters/smartrecruiters/index.ts", "../src/adapters/oraclecloud/index.ts", "../src/adapters/indeed/index.ts", "../src/adapters/linkedin/index.ts", "../src/adapters/generic/index.ts", "../src/adapters/index.ts", "../src/autoApply/tailoring.ts", "../src/answerBank/index.ts", "../src/smartFill/valueGuesser.ts", "../src/smartFill/fallbackFiller.ts", "../src/smartFill/successDetector.ts", "../src/smartFill/multiPageHandler.ts", "../src/smartFill/workdayAutomation.ts", "../src/content/main.ts"],
  "sourcesContent": ["/**\n * Canonical ATS Platform Registry\n * Single source of truth for all supported job application platforms.\n */\n\nimport type { ATSPlatformEntry, ATSType } from '../types/index';\n\nexport const PLATFORM_REGISTRY: ATSPlatformEntry[] = [\n  // \u2500\u2500\u2500 Existing Platforms \u2500\u2500\u2500\n  {\n    id: 'workday',\n    name: 'Workday',\n    domains: ['myworkdayjobs.com', 'myworkday.com', 'wd1.myworkdaysite.com', 'wd3.myworkdaysite.com', 'wd5.myworkdaysite.com'],\n    urlPatterns: [/myworkdayjobs\\.com/i, /myworkday\\.com/i, /myworkdaysite\\.com/i, /\\.wd\\d+\\.myworkdayjobs\\.com/i],\n    domSignals: ['[data-automation-id]', '[data-uxi-element-id]'],\n    metaSignals: [{ name: 'generator', pattern: /workday/i }],\n    enabled: true,\n    supportsAutoSubmit: true,\n    notes: 'Multi-step forms with React components. Handles combobox/listbox interactions.',\n  },\n  {\n    id: 'greenhouse',\n    name: 'Greenhouse',\n    domains: ['greenhouse.io', 'boards.greenhouse.io'],\n    urlPatterns: [/greenhouse\\.io/i, /boards\\.greenhouse\\.io/i],\n    domSignals: ['#greenhouse_application', '#grnhse_app', 'form#application_form'],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: true,\n    notes: 'Uses bracket notation for field names: job_application[first_name].',\n  },\n  {\n    id: 'lever',\n    name: 'Lever',\n    domains: ['lever.co', 'jobs.lever.co'],\n    urlPatterns: [/lever\\.co/i, /jobs\\.lever\\.co/i],\n    domSignals: ['.lever-application-form', '[data-qa=\"application-form\"]', '.posting-headline'],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: true,\n  },\n  {\n    id: 'smartrecruiters',\n    name: 'SmartRecruiters',\n    domains: ['smartrecruiters.com', 'jobs.smartrecruiters.com'],\n    urlPatterns: [/smartrecruiters\\.com/i],\n    domSignals: ['[class*=\"smartrecruiters\"]', '.st-apply-form', '[class*=\"ApplyButton\"]'],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: true,\n  },\n  {\n    id: 'icims',\n    name: 'iCIMS',\n    domains: ['icims.com', 'careers-icims.com'],\n    urlPatterns: [/icims\\.com/i, /careers-icims\\.com/i],\n    domSignals: ['#icims_content', '[class*=\"icims\"]', '.iCIMS_MainWrapper'],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: true,\n  },\n  {\n    id: 'taleo',\n    name: 'Taleo (Oracle)',\n    domains: ['taleo.net', 'taleoquickfind.com'],\n    urlPatterns: [/taleo\\.net/i, /taleoquickfind\\.com/i],\n    domSignals: ['[class*=\"taleo\"]', '#requisitionDescriptionInterface', '.taleoContent'],\n    metaSignals: [{ name: 'generator', pattern: /taleo/i }],\n    enabled: true,\n    supportsAutoSubmit: true,\n  },\n  {\n    id: 'ashby',\n    name: 'Ashby',\n    domains: ['ashbyhq.com', 'jobs.ashbyhq.com'],\n    urlPatterns: [/ashbyhq\\.com/i],\n    domSignals: ['[data-ashby-job-posting-id]', '.ashby-job-posting-brief-location'],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: true,\n  },\n  {\n    id: 'bamboohr',\n    name: 'BambooHR',\n    domains: ['bamboohr.com'],\n    urlPatterns: [/bamboohr\\.com/i],\n    domSignals: ['.BambooHR-ATS-board', '[class*=\"BambooHR\"]'],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: true,\n  },\n\n  // \u2500\u2500\u2500 Newly Added Platforms \u2500\u2500\u2500\n  {\n    id: 'oraclecloud',\n    name: 'Oracle Cloud HCM / Oracle Recruiting',\n    domains: ['oraclecloud.com', 'fa.oraclecloud.com'],\n    urlPatterns: [/oraclecloud\\.com/i, /fa\\..*\\.oraclecloud\\.com/i, /hcm\\d*.*\\.oraclecloud\\.com/i],\n    domSignals: [\n      '[class*=\"oracle\"]', '[id*=\"oj-\"]', '.oj-web-applcore-page',\n      '[data-oj-binding-provider]', '.oj-flex', '#ojAppRoot',\n    ],\n    metaSignals: [{ name: 'generator', pattern: /oracle/i }],\n    enabled: true,\n    supportsAutoSubmit: true,\n    notes: 'Oracle JET-based UI. Uses oj- prefixed component IDs. Dynamic SPA with knockout.js bindings.',\n  },\n  {\n    id: 'linkedin',\n    name: 'LinkedIn (Non-Easy Apply Only)',\n    domains: ['linkedin.com', 'www.linkedin.com'],\n    urlPatterns: [/linkedin\\.com\\/jobs/i, /linkedin\\.com\\/in/i],\n    domSignals: [\n      '.jobs-apply-button', '.jobs-unified-top-card',\n      '[data-job-id]', '.jobs-details',\n    ],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: false,\n    notes: 'Only for non-Easy Apply flows. Easy Apply is filtered out by detection logic.',\n  },\n  {\n    id: 'indeed',\n    name: 'Indeed',\n    domains: ['indeed.com', 'www.indeed.com', 'apply.indeed.com'],\n    urlPatterns: [/indeed\\.com/i, /apply\\.indeed\\.com/i],\n    domSignals: [\n      '#jobsearch-ViewJobButtons-container', '.jobsearch-ViewJobLayout',\n      '[data-testid=\"apply-button\"]', '#ia-container',\n    ],\n    metaSignals: [],\n    enabled: true,\n    supportsAutoSubmit: true,\n    notes: 'Indeed Apply flow uses iframe-based application forms.',\n  },\n];\n\n/** Get all enabled platforms */\nexport function getEnabledPlatforms(): ATSPlatformEntry[] {\n  return PLATFORM_REGISTRY.filter((p) => p.enabled);\n}\n\n/** Get platform by ID */\nexport function getPlatform(id: ATSType): ATSPlatformEntry | undefined {\n  return PLATFORM_REGISTRY.find((p) => p.id === id);\n}\n\n/** Get all platform domains for manifest host permissions */\nexport function getAllDomains(): string[] {\n  return PLATFORM_REGISTRY.flatMap((p) => p.domains);\n}\n\n/** Check if a URL matches any supported platform */\nexport function matchUrlToPlatform(url: string): ATSPlatformEntry | null {\n  for (const p of PLATFORM_REGISTRY) {\n    if (!p.enabled) continue;\n    for (const pat of p.urlPatterns) {\n      if (pat.test(url)) return p;\n    }\n  }\n  return null;\n}\n\n/** Check if a LinkedIn job is Easy Apply (to filter it out) */\nexport function isLinkedInEasyApply(doc: Document): boolean {\n  const easyApplyBtn = doc.querySelector('.jobs-apply-button--top-card .jobs-apply-button');\n  if (easyApplyBtn) {\n    const text = easyApplyBtn.textContent?.toLowerCase() || '';\n    return text.includes('easy apply');\n  }\n  const badge = doc.querySelector('[class*=\"easy-apply\"]') || doc.querySelector('[data-is-easy-apply=\"true\"]');\n  return !!badge;\n}\n\n/** Export registry as JSON for settings display */\nexport function registryToJSON(): Array<{ id: string; name: string; domains: string[]; enabled: boolean; supportsAutoSubmit: boolean }> {\n  return PLATFORM_REGISTRY.map((p) => ({\n    id: p.id,\n    name: p.name,\n    domains: p.domains,\n    enabled: p.enabled,\n    supportsAutoSubmit: p.supportsAutoSubmit,\n  }));\n}\n", "import type { ATSDetectionResult, ATSType } from '../types/index';\nimport { PLATFORM_REGISTRY, isLinkedInEasyApply } from './platformRegistry';\n\ninterface Sig {\n  type: ATSType;\n  urls: RegExp[];\n  dom: string[];\n  meta: { name: string; pat: RegExp }[];\n}\n\n// Build signatures from the canonical platform registry\nconst SIGS: Sig[] = PLATFORM_REGISTRY.filter((p) => p.enabled).map((p) => ({\n  type: p.id,\n  urls: p.urlPatterns,\n  dom: p.domSignals,\n  meta: p.metaSignals.map((m) => ({ name: m.name, pat: m.pattern })),\n}));\n\nexport function detectATS(doc: Document): ATSDetectionResult {\n  const url = doc.location?.href || '';\n  let best: ATSType = 'generic';\n  let bestConf = 0;\n  const bestSigs: string[] = [];\n\n  for (const s of SIGS) {\n    let conf = 0;\n    const found: string[] = [];\n\n    for (const p of s.urls) {\n      if (p.test(url)) { conf += 0.5; found.push(`url:${p.source}`); break; }\n    }\n    for (const sel of s.dom) {\n      try { if (doc.querySelector(sel)) { conf += 0.2; found.push(`dom:${sel}`); if (conf >= 0.9) break; } } catch {}\n    }\n    for (const m of s.meta) {\n      const el = doc.querySelector(`meta[name=\"${m.name}\"]`);\n      if (el && m.pat.test(el.getAttribute('content') || '')) { conf += 0.3; found.push(`meta:${m.name}`); }\n    }\n\n    conf = Math.min(conf, 1);\n\n    // Special case: filter out LinkedIn Easy Apply\n    if (s.type === 'linkedin' && conf > 0) {\n      if (isLinkedInEasyApply(doc)) {\n        continue; // Skip - we only support non-Easy Apply\n      }\n    }\n\n    if (conf > bestConf) { bestConf = conf; best = s.type; bestSigs.length = 0; bestSigs.push(...found); }\n  }\n\n  // \u2500\u2500\u2500 Universal form detection: if no known ATS, detect company career sites \u2500\u2500\u2500\n  if (best === 'generic' || bestConf < 0.3) {\n    const companySiteResult = detectCompanySite(doc, url);\n    if (companySiteResult.confidence > bestConf) {\n      return companySiteResult;\n    }\n  }\n\n  return { type: best, confidence: bestConf, signals: bestSigs };\n}\n\n/**\n * Detect any company career/job application page,\n * even if it doesn't match a known ATS.\n * This enables autofill on ANY job application form.\n */\nfunction detectCompanySite(doc: Document, url: string): ATSDetectionResult {\n  let conf = 0;\n  const signals: string[] = [];\n\n  // URL signals: career/job-related paths\n  const careerPatterns = [\n    /\\/careers?\\b/i, /\\/jobs?\\b/i, /\\/apply\\b/i, /\\/openings?\\b/i,\n    /\\/positions?\\b/i, /\\/hiring\\b/i, /\\/opportunities\\b/i,\n    /\\/recruit/i, /\\/talent\\b/i, /\\/work-with-us/i,\n    /\\/join-us/i, /\\/join-our-team/i, /\\/application\\b/i,\n  ];\n  for (const p of careerPatterns) {\n    if (p.test(url)) { conf += 0.25; signals.push(`url:career-path`); break; }\n  }\n\n  // Form presence: look for application-like forms\n  const forms = doc.querySelectorAll('form');\n  for (const form of forms) {\n    const formText = (form.textContent || '').toLowerCase();\n    const formHtml = (form.innerHTML || '').toLowerCase();\n\n    // Check for job-application-related fields\n    const appFieldCount = countApplicationFields(form);\n    if (appFieldCount >= 3) {\n      conf += 0.3;\n      signals.push(`form:${appFieldCount}-app-fields`);\n      break;\n    }\n\n    // Check form action or class for application hints\n    const action = form.getAttribute('action') || '';\n    const cls = form.className || '';\n    if (/apply|application|candidate|submit/i.test(action + ' ' + cls)) {\n      conf += 0.2;\n      signals.push('form:apply-action');\n    }\n  }\n\n  // Page title / h1 signals\n  const title = doc.title.toLowerCase();\n  const h1 = doc.querySelector('h1')?.textContent?.toLowerCase() || '';\n  if (/apply|application|career|job|position|opening/i.test(title + ' ' + h1)) {\n    conf += 0.15;\n    signals.push('page:career-title');\n  }\n\n  // File upload (resume/cv) presence\n  const fileInputs = doc.querySelectorAll('input[type=\"file\"]');\n  for (const fi of fileInputs) {\n    const accept = fi.getAttribute('accept') || '';\n    const name = fi.getAttribute('name') || '';\n    const label = getInputLabel(fi as HTMLElement, doc);\n    if (/resume|cv|curriculum|cover/i.test(accept + ' ' + name + ' ' + label)) {\n      conf += 0.2;\n      signals.push('form:resume-upload');\n      break;\n    }\n  }\n\n  conf = Math.min(conf, 1);\n\n  if (conf >= 0.3) {\n    return { type: 'companysite', confidence: conf, signals };\n  }\n\n  return { type: 'generic', confidence: 0, signals: [] };\n}\n\n/** Count how many application-related fields a form contains */\nfunction countApplicationFields(form: HTMLFormElement): number {\n  const fields = form.querySelectorAll('input, textarea, select');\n  let count = 0;\n  const appFieldHints = [\n    /name/i, /first/i, /last/i, /email/i, /phone/i, /resume/i, /cv/i,\n    /cover/i, /address/i, /city/i, /state/i, /zip/i, /country/i,\n    /experience/i, /education/i, /skill/i, /linkedin/i, /portfolio/i,\n    /website/i, /salary/i, /start.?date/i, /authorized/i, /sponsor/i,\n    /visa/i, /relocat/i, /referr/i,\n  ];\n\n  for (const field of fields) {\n    const name = field.getAttribute('name') || '';\n    const id = field.getAttribute('id') || '';\n    const placeholder = field.getAttribute('placeholder') || '';\n    const label = getInputLabel(field as HTMLElement, form.ownerDocument);\n    const combined = `${name} ${id} ${placeholder} ${label}`.toLowerCase();\n\n    if (appFieldHints.some((h) => h.test(combined))) count++;\n  }\n  return count;\n}\n\n/** Get the label text for a form field */\nfunction getInputLabel(el: HTMLElement, doc: Document): string {\n  if (el.id) {\n    const lbl = doc.querySelector(`label[for=\"${CSS.escape(el.id)}\"]`);\n    if (lbl?.textContent?.trim()) return lbl.textContent.trim();\n  }\n  const wrap = el.closest('label');\n  if (wrap?.textContent?.trim()) return wrap.textContent.trim();\n  return el.getAttribute('aria-label') || el.getAttribute('placeholder') || '';\n}\n\nexport function atsName(type: ATSType): string {\n  const m: Record<ATSType, string> = {\n    workday: 'Workday', greenhouse: 'Greenhouse', lever: 'Lever',\n    smartrecruiters: 'SmartRecruiters', icims: 'iCIMS', taleo: 'Taleo',\n    ashby: 'Ashby', bamboohr: 'BambooHR',\n    oraclecloud: 'Oracle Cloud', linkedin: 'LinkedIn', indeed: 'Indeed',\n    companysite: 'Company Site', generic: 'Generic',\n  };\n  return m[type] || type;\n}\n\n/** Check if current page is a supported application page (any ATS or company site) */\nexport function isApplicationPage(doc: Document): boolean {\n  const result = detectATS(doc);\n  return result.type !== 'generic' && result.confidence >= 0.3;\n}\n\n/** Check if page has ANY fillable form (even non-career pages if universal mode is on) */\nexport function hasApplicationForm(doc: Document): boolean {\n  const result = detectATS(doc);\n  if (result.type !== 'generic' && result.confidence >= 0.3) return true;\n\n  // Check for any substantial form\n  const forms = doc.querySelectorAll('form');\n  for (const form of forms) {\n    const fields = form.querySelectorAll('input:not([type=\"hidden\"]):not([type=\"submit\"]):not([type=\"button\"]), textarea, select');\n    if (fields.length >= 2) return true;\n  }\n  return false;\n}\n", "/** Normalize: lowercase, strip punctuation, collapse whitespace */\nexport function normalize(text: string): string {\n  return text.toLowerCase().replace(/[^\\w\\s]/g, ' ').replace(/\\s+/g, ' ').trim();\n}\n\n/** Tokenize normalized text */\nexport function tokenize(text: string): string[] {\n  return normalize(text).split(' ').filter(Boolean);\n}\n\n/** Levenshtein distance */\nexport function levenshtein(a: string, b: string): number {\n  const m = a.length, n = b.length;\n  if (m === 0) return n;\n  if (n === 0) return m;\n  let prev = Array.from({ length: n + 1 }, (_, i) => i);\n  let curr = new Array<number>(n + 1);\n  for (let i = 1; i <= m; i++) {\n    curr[0] = i;\n    for (let j = 1; j <= n; j++) {\n      curr[j] = Math.min(\n        prev[j] + 1,\n        curr[j - 1] + 1,\n        prev[j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1)\n      );\n    }\n    [prev, curr] = [curr, prev];\n  }\n  return prev[n];\n}\n\n/** Normalized similarity 0\u20131 */\nexport function stringSimilarity(a: string, b: string): number {\n  const na = normalize(a), nb = normalize(b);\n  if (na === nb) return 1;\n  const max = Math.max(na.length, nb.length);\n  return max === 0 ? 1 : 1 - levenshtein(na, nb) / max;\n}\n\n/** Token overlap (Jaccard) */\nexport function tokenOverlap(a: string[], b: string[]): number {\n  if (!a.length && !b.length) return 1;\n  if (!a.length || !b.length) return 0;\n  const sa = new Set(a), sb = new Set(b);\n  let inter = 0;\n  for (const t of sa) if (sb.has(t)) inter++;\n  return inter / new Set([...sa, ...sb]).size;\n}\n\n/** Fuzzy per-token match */\nexport function fuzzyTokenMatch(a: string[], b: string[]): number {\n  if (!a.length) return b.length === 0 ? 1 : 0;\n  let total = 0;\n  for (const ta of a) {\n    let best = 0;\n    for (const tb of b) best = Math.max(best, stringSimilarity(ta, tb));\n    total += best;\n  }\n  return total / a.length;\n}\n\n/** Combined hybrid similarity */\nexport function hybridSimilarity(query: string, target: string, keywords: string[]): number {\n  const qt = tokenize(query), tt = tokenize(target);\n  const direct = stringSimilarity(query, target) * 0.3;\n  const overlap = tokenOverlap(qt, tt) * 0.25;\n  const fuzzy = fuzzyTokenMatch(qt, tt) * 0.25;\n  let kw = 0;\n  if (keywords.length) {\n    const nq = normalize(query);\n    let hit = 0;\n    for (const k of keywords) if (nq.includes(normalize(k))) hit++;\n    kw = (hit / keywords.length) * 0.2;\n  }\n  return direct + overlap + fuzzy + kw;\n}\n\n/** Find near-duplicate pairs above threshold */\nexport function findDuplicates(\n  items: { id: string; question: string }[],\n  threshold = 0.75\n): { idA: string; idB: string; similarity: number }[] {\n  const out: { idA: string; idB: string; similarity: number }[] = [];\n  for (let i = 0; i < items.length; i++) {\n    for (let j = i + 1; j < items.length; j++) {\n      const sim = stringSimilarity(items[i].question, items[j].question);\n      if (sim >= threshold) out.push({ idA: items[i].id, idB: items[j].id, similarity: sim });\n    }\n  }\n  return out.sort((a, b) => b.similarity - a.similarity);\n}\n", "import type { SavedResponse, SuggestionItem, ATSType } from '../types/index';\nimport { hybridSimilarity, normalize, tokenize, tokenOverlap } from '../utils/fuzzy';\n\nexport interface MatchOptions {\n  domain?: string;\n  atsType?: ATSType;\n  maxResults?: number;\n}\n\n/** Score one response against a query string. Returns 0\u20131 and explanation. */\nexport function scoreResponse(\n  query: string,\n  resp: SavedResponse,\n  opts: MatchOptions = {}\n): { score: number; explanation: string } {\n  const parts: string[] = [];\n  let score = 0;\n\n  // 1. Hybrid text similarity vs question (0.45)\n  const qSim = hybridSimilarity(query, resp.question, resp.keywords);\n  score += qSim * 0.45;\n  parts.push(`q_sim=${qSim.toFixed(3)}`);\n\n  // 2. Key overlap (0.20)\n  const keyTokens = resp.key.split('|').filter(Boolean);\n  const qTokens = tokenize(query);\n  const keyOv = tokenOverlap(qTokens, keyTokens);\n  score += keyOv * 0.20;\n  parts.push(`key=${keyOv.toFixed(3)}`);\n\n  // 3. Popularity (0.10)\n  const pop = Math.min(Math.log2(1 + resp.appearances) / 10, 1);\n  score += pop * 0.10;\n  parts.push(`pop=${pop.toFixed(3)}`);\n\n  // 4. Recency (0.10)\n  let rec = 0;\n  if (resp.lastUsedAt) {\n    const days = (Date.now() - new Date(resp.lastUsedAt).getTime()) / 86_400_000;\n    rec = Math.max(0, 1 - days / 90);\n  }\n  score += rec * 0.10;\n  parts.push(`rec=${rec.toFixed(3)}`);\n\n  // 5. Domain / ATS hint (0.10)\n  let ctx = 0;\n  if (opts.domain && resp.domains?.includes(opts.domain)) { ctx += 0.5; parts.push('dom+'); }\n  if (opts.atsType && resp.atsTypes?.includes(opts.atsType)) { ctx += 0.5; parts.push('ats+'); }\n  score += Math.min(ctx, 1) * 0.10;\n\n  // 6. Keyword bonus (0.05)\n  let kwb = 0;\n  if (resp.keywords.length) {\n    const nq = normalize(query);\n    let hit = 0;\n    for (const k of resp.keywords) if (nq.includes(k.toLowerCase())) hit++;\n    kwb = hit / resp.keywords.length;\n  }\n  score += kwb * 0.05;\n  parts.push(`kw=${kwb.toFixed(3)}`);\n\n  return { score: Math.min(score, 1), explanation: parts.join(', ') };\n}\n\n/** Top N matches above threshold */\nexport function findMatches(query: string, responses: SavedResponse[], opts: MatchOptions = {}): SuggestionItem[] {\n  const max = opts.maxResults || 3;\n  if (!query.trim() || !responses.length) return [];\n  return responses\n    .map((r) => { const { score, explanation } = scoreResponse(query, r, opts); return { response: r, score, explanation }; })\n    .filter((s) => s.score > 0.15)\n    .sort((a, b) => b.score - a.score)\n    .slice(0, max);\n}\n\n/** Best single match for autofill (null if below confidence) */\nexport function findBestMatch(query: string, responses: SavedResponse[], opts: MatchOptions = {}): SuggestionItem | null {\n  const m = findMatches(query, responses, { ...opts, maxResults: 1 });\n  return m.length && m[0].score >= 0.3 ? m[0] : null;\n}\n", "import type { FieldInfo, FieldSignal, FieldMatchResult, SavedResponse } from '../types/index';\nimport { findBestMatch, type MatchOptions } from '../savedResponses/matcher';\n\n// \u2500\u2500\u2500 Signal Extraction \u2500\u2500\u2500\n\nexport function extractFieldSignals(element: HTMLElement): FieldSignal[] {\n  const signals: FieldSignal[] = [];\n\n  // 1. Explicit <label for>\n  if (element.id) {\n    const lbl = document.querySelector(`label[for=\"${CSS.escape(element.id)}\"]`);\n    if (lbl?.textContent?.trim()) signals.push({ source: 'label-for', value: lbl.textContent.trim(), weight: 1.0 });\n  }\n\n  // 2. Wrapping label\n  const wrap = element.closest('label');\n  if (wrap) {\n    const t = directText(wrap).trim();\n    if (t) signals.push({ source: 'label-wrap', value: t, weight: 0.95 });\n  }\n\n  // 3. aria-label\n  const al = element.getAttribute('aria-label');\n  if (al?.trim()) signals.push({ source: 'aria-label', value: al.trim(), weight: 0.9 });\n\n  // 4. aria-labelledby\n  const alb = element.getAttribute('aria-labelledby');\n  if (alb) {\n    const txt = alb.split(/\\s+/).map((id) => document.getElementById(id)?.textContent?.trim()).filter(Boolean).join(' ');\n    if (txt) signals.push({ source: 'aria-labelledby', value: txt, weight: 0.9 });\n  }\n\n  // 5. placeholder\n  if (element instanceof HTMLInputElement || element instanceof HTMLTextAreaElement) {\n    const ph = element.placeholder;\n    if (ph?.trim()) signals.push({ source: 'placeholder', value: ph.trim(), weight: 0.7 });\n  }\n\n  // 6. name\n  const name = element.getAttribute('name');\n  if (name?.trim()) signals.push({ source: 'name', value: humanize(name), weight: 0.6 });\n\n  // 7. id\n  if (element.id) signals.push({ source: 'id', value: humanize(element.id), weight: 0.5 });\n\n  // 8. autocomplete\n  const ac = element.getAttribute('autocomplete');\n  if (ac?.trim() && ac !== 'off') signals.push({ source: 'autocomplete', value: ac.trim(), weight: 0.85 });\n\n  // 9. role\n  const role = element.getAttribute('role'