') return 'textarea';\n  if (tag === 'select') return 'select';\n  return el.getAttribute('role') || 'unknown';\n}\n\nexport const genericAdapter: ATSAdapter = {\n  type: 'generic',\n\n  detect(_doc: Document): ATSDetectionResult {\n    return { type: 'generic', confidence: 0.1, signals: ['fallback'] };\n  },\n\n  getFields(doc: Document): FieldInfo[] {\n    return discoverFields(doc);\n  },\n\n  async fillField(field: HTMLElement, value: string): Promise<boolean> {\n    try {\n      if (field instanceof HTMLInputElement || field instanceof HTMLTextAreaElement) {\n        const setter = Object.getOwnPropertyDescriptor(\n          field instanceof HTMLTextAreaElement ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype, 'value'\n        )?.set;\n        if (setter) setter.call(field, value); else field.value = value;\n        field.dispatchEvent(new Event('input', { bubbles: true }));\n        field.dispatchEvent(new Event('change', { bubbles: true }));\n        field.dispatchEvent(new Event('blur', { bubbles: true }));\n\n        // Also fire React-compatible events\n        field.dispatchEvent(new Event('focus', { bubbles: true }));\n        return true;\n      }\n      if (field instanceof HTMLSelectElement) {\n        const opt = Array.from(field.options).find(\n          (o) => o.text.toLowerCase().includes(value.toLowerCase()) || o.value.toLowerCase() === value.toLowerCase()\n        );\n        if (opt) { field.value = opt.value; field.dispatchEvent(new Event('change', { bubbles: true })); return true; }\n        return false;\n      }\n      // Custom select / combobox\n      if (field.getAttribute('role') === 'combobox' || field.getAttribute('role') === 'listbox') {\n        field.click();\n        await new Promise((r) => setTimeout(r, 200));\n        const inp = field.querySelector('input') as HTMLInputElement | null;\n        if (inp) { inp.value = value; inp.dispatchEvent(new Event('input', { bubbles: true })); }\n        await new Promise((r) => setTimeout(r, 300));\n        for (const opt of document.querySelectorAll('[role=\"option\"]')) {\n          if (opt.textContent?.toLowerCase().includes(value.toLowerCase())) { (opt as HTMLElement).click(); return true; }\n        }\n        return false;\n      }\n      // Radio / Checkbox\n      if (field instanceof HTMLInputElement && (field.type === 'radio' || field.type === 'checkbox')) {\n        const lbl = field.closest('label')?.textContent?.trim() || '';\n        if (lbl.toLowerCase().includes(value.toLowerCase()) || value.toLowerCase() === 'yes' || value.toLowerCase() === 'true') {\n          field.checked = true;\n          field.dispatchEvent(new Event('change', { bubbles: true }));\n          return true;\n        }\n        return false;\n      }\n      // Contenteditable\n      if (field.contentEditable === 'true') {\n        field.textContent = value;\n        field.dispatchEvent(new Event('input', { bubbles: true }));\n        return true;\n      }\n      return false;\n    } catch { return false; }\n  },\n};\n", "import type { ATSAdapter, ATSType } from '../types/index';\nimport { workdayAdapter } from './workday/index';\nimport { greenhouseAdapter } from './greenhouse/index';\nimport { leverAdapter } from './lever/index';\nimport { smartrecruitersAdapter } from './smartrecruiters/index';\nimport { oraclecloudAdapter } from './oraclecloud/index';\nimport { indeedAdapter } from './indeed/index';\nimport { linkedinAdapter } from './linkedin/index';\nimport { genericAdapter } from './generic/index';\n\nconst adapters: Record<string, ATSAdapter> = {\n  workday: workdayAdapter,\n  greenhouse: greenhouseAdapter,\n  lever: leverAdapter,\n  smartrecruiters: smartrecruitersAdapter,\n  oraclecloud: oraclecloudAdapter,\n  indeed: indeedAdapter,\n  linkedin: linkedinAdapter,\n  companysite: genericAdapter,   // company sites use the universal generic adapter\n  generic: genericAdapter,\n};\n\nexport function getAdapter(type: ATSType): ATSAdapter {\n  return adapters[type] || genericAdapter;\n}\n\nexport {\n  workdayAdapter,\n  greenhouseAdapter,\n  leverAdapter,\n  smartrecruitersAdapter,\n  oraclecloudAdapter,\n  indeedAdapter,\n  linkedinAdapter,\n  genericAdapter,\n};\n", "/**\n * AI Tailoring Engine\n * Inspired by Jobright's AI tailoring feature.\n * Analyzes job posting context and tailors saved responses to perfectly match\n * the job requirements, company, and keywords \u2014 achieving 100% relevance.\n *\n * Works entirely on-device using keyword matching, synonym expansion,\n * and context-aware response rewriting (no external API calls).\n */\n\nimport type { TailoringContext, TailoredResponse, TailoringSettings, SavedResponse } from '../types/index';\nimport { loadSettings } from '../settings/storage';\n\n// \u2500\u2500\u2500 Keyword extraction from job postings \u2500\u2500\u2500\n\nconst SKILL_PATTERNS = [\n  // Programming languages\n  /\\b(javascript|typescript|python|java|c\\+\\+|ruby|go|rust|swift|kotlin|scala|php|perl|r|matlab|sql|html|css)\\b/gi,\n  // Frameworks\n  /\\b(react|angular|vue|next\\.?js|node\\.?js|express|django|flask|spring|rails|laravel|\\.net|asp\\.net|tensorflow|pytorch)\\b/gi,\n  // Cloud & DevOps\n  /\\b(aws|azure|gcp|docker|kubernetes|terraform|jenkins|ci\\/cd|git|github|gitlab|bitbucket)\\b/gi,\n  // Databases\n  /\\b(postgresql|mysql|mongodb|redis|elasticsearch|dynamodb|cassandra|sqlite|oracle|sql server)\\b/gi,\n  // Soft skills & domain\n  /\\b(leadership|communication|problem[- ]solving|teamwork|agile|scrum|project management|analytical|critical thinking)\\b/gi,\n];\n\nconst SENIORITY_PATTERNS = [\n  { pattern: /\\b(senior|sr\\.?|lead|principal|staff|architect)\\b/i, level: 'senior' },\n  { pattern: /\\b(mid[- ]?level|intermediate|ii|iii)\\b/i, level: 'mid' },\n  { pattern: /\\b(junior|jr\\.?|entry[- ]?level|associate|intern|i\\b)\\b/i, level: 'junior' },\n  { pattern: /\\b(manager|director|vp|vice president|head of|chief)\\b/i, level: 'manager' },\n];\n\n/** Extract context from a job posting page */\nexport function extractJobContext(doc: Document): TailoringContext {\n  const ctx: TailoringContext = {};\n\n  // Job title \u2014 try multiple selectors used by various ATS\n  const titleSelectors = [\n    'h1.job-title', 'h1.posting-headline', 'h1[class*=\"title\"]',\n    '[data-automation-id=\"jobPostingHeader\"]', '.job-title', '.posting-headline h2',\n    'h1', '.topcard__title', '.jobsearch-JobInfoHeader-title',\n    '[data-testid=\"job-title\"]', '.jobs-unified-top-card__job-title',\n  ];\n  for (const sel of titleSelectors) {\n    const el = doc.querySelector(sel);\n    if (el?.textContent?.trim()) { ctx.jobTitle = el.textContent.trim(); break; }\n  }\n\n  // Company name\n  const companySelectors = [\n    '.company-name', '[data-automation-id=\"company\"]', '.posting-categories .sort-by-team',\n    '.employer-name', '.topcard__org-name-link', '.jobsearch-InlineCompanyRating-companyHeader',\n    '[data-testid=\"company-name\"]', '.jobs-unified-top-card__company-name',\n    'a[data-tracking-control-name=\"public_jobs_topcard-org-name\"]',\n  ];\n  for (const sel of companySelectors) {\n    const el = doc.querySelector(sel);\n    if (el?.textContent?.trim()) { ctx.companyName = el.textContent.trim(); break; }\n  }\n\n  // Job description \u2014 full text for keyword extraction\n  const descSelectors = [\n    '.job-description', '[data-automation-id=\"jobPostingDescription\"]',\n    '.posting-page .section-wrapper', '#job-details', '.jobsearch-jobDescriptionText',\n    '.jobs-description__content', '[data-testid=\"job-description\"]',\n    '.description__text', '#job_description',\n  ];\n  let descText = '';\n  for (const sel of descSelectors) {\n    const el = doc.querySelector(sel);\n    if (el?.textContent?.trim() && el.textContent.trim().length > 50) {\n      descText = el.textContent.trim();\n      ctx.jobDescription = descText;\n      break;\n    }\n  }\n\n  // Extract required skills from description\n  if (descText) {\n    const skills = new Set<string>();\n    for (const pat of SKILL_PATTERNS) {\n      const matches = descText.matchAll(pat);\n      for (const m of matches) skills.add(m[0].toLowerCase());\n    }\n    if (skills.size > 0) ctx.requiredSkills = [...skills];\n\n    // Detect seniority\n    for (const s of SENIORITY_PATTERNS) {\n      if (s.pattern.test(descText) || (ctx.jobTitle && s.pattern.test(ctx.jobTitle))) {\n        ctx.seniority = s.level;\n        break;\n      }\n    }\n  }\n\n  // Job location\n  const locSelectors = [\n    '.job-location', '[data-automation-id=\"locations\"]', '.posting-categories .sort-by-location',\n    '.location', '.topcard__flavor--bullet', '.jobsearch-JobInfoHeader-subtitle > div',\n    '[data-testid=\"job-location\"]',\n  ];\n  for (const sel of locSelectors) {\n    const el = doc.querySelector(sel);\n    if (el?.textContent?.trim()) { ctx.jobLocation = el.textContent.trim(); break; }\n  }\n\n  return ctx;\n}\n\n/**\n * Tailor a response to match the job context.\n * Uses keyword injection, company name weaving, and skill emphasis.\n * Returns the original if no meaningful tailoring can be applied.\n */\nexport function tailorResponse(\n  originalResponse: string,\n  fieldLabel: string,\n  context: TailoringContext,\n  settings: TailoringSettings,\n): TailoredResponse {\n  if (!settings.enabled || settings.intensity === 0) {\n    return {\n      originalResponse,\n      tailoredResponse: originalResponse,\n      fieldLabel,\n      confidence: 1.0,\n      reasoning: 'Tailoring disabled',\n    };\n  }\n\n  let tailored = originalResponse;\n  const reasons: string[] = [];\n  let confidence = 1.0;\n\n  const lowerLabel = fieldLabel.toLowerCase();\n  const lowerResponse = tailored.toLowerCase();\n\n  // \u2500\u2500\u2500 Short fields: don't tailor name, email, phone, address \u2500\u2500\u2500\n  const skipFields = ['name', 'first name', 'last name', 'email', 'phone', 'address', 'city', 'state', 'zip', 'country', 'salary', 'date', 'gender', 'race', 'ethnicity', 'veteran', 'disability'];\n  if (skipFields.some((f) => lowerLabel.includes(f)) || originalResponse.length < 20) {\n    return {\n      originalResponse,\n      tailoredResponse: originalResponse,\n      fieldLabel,\n      confidence: 1.0,\n      reasoning: 'Field is factual/short \u2014 no tailoring needed',\n    };\n  }\n\n  // \u2500\u2500\u2500 Company name injection \u2500\u2500\u2500\n  if (context.companyName && !lowerResponse.includes(context.companyName.toLowerCase())) {\n    const companyPhrases = [\n      `I am excited about the opportunity at ${context.companyName}`,\n      `at ${context.companyName}`,\n      `with ${context.companyName}`,\n    ];\n\n    // For \"why this company\" / \"cover letter\" type fields\n    if (lowerLabel.includes('why') || lowerLabel.includes('cover') || lowerLabel.includes('interest') || lowerLabel.includes('motivation')) {\n      tailored = tailored.replace(\n        /^(.)/,\n        `I am drawn to ${context.companyName} for its impact in the industry. $1`\n      );\n      reasons.push(`Injected company name: ${context.companyName}`);\n    }\n    // For summary / about me type fields\n    else if (lowerLabel.includes('summary') || lowerLabel.includes('about') || lowerLabel.includes('introduction') || lowerLabel.includes('tell us')) {\n      // Append company mention at end\n      tailored = tailored.replace(/\\.?\\s*$/, `, and I am eager to bring this expertise to ${context.companyName}.`);\n      reasons.push(`Appended company reference: ${context.companyName}`);\n    }\n  }\n\n  // \u2500\u2500\u2500 Job title alignment \u2500\u2500\u2500\n  if (context.jobTitle) {\n    const roleMention = context.jobTitle.replace(/\\s*\\(.*\\)/, '').trim(); // Remove parenthetical\n    if (roleMention.length > 3 && !lowerResponse.includes(roleMention.toLowerCase())) {\n      if (lowerLabel.includes('experience') || lowerLabel.includes('background') || lowerLabel.includes('summary') || lowerLabel.includes('qualification')) {\n        tailored = tailored.replace(/\\.?\\s*$/, `, directly relevant to the ${roleMention} position.`);\n        reasons.push(`Added role reference: ${roleMention}`);\n      }\n    }\n  }\n\n  // \u2500\u2500\u2500 Skill keyword emphasis \u2500\u2500\u2500\n  if (context.requiredSkills && context.requiredSkills.length > 0) {\n    const profileKeywords = settings.profileKeywords.map((k) => k.toLowerCase());\n    const matchingSkills = context.requiredSkills.filter((s) =>\n      profileKeywords.includes(s) || lowerResponse.includes(s)\n    );\n\n    // Skills the job requires that are in the user's profile but not in the response\n    const missingSkills = context.requiredSkills.filter((s) =>\n      profileKeywords.includes(s) && !lowerResponse.includes(s)\n    );\n\n    if (missingSkills.length > 0 && (lowerLabel.includes('skill') || lowerLabel.includes('experience') || lowerLabel.includes('qualification') || lowerLabel.includes('summary') || lowerLabel.includes('why'))) {\n      const skillList = missingSkills.slice(0, 4).join(', ');\n      tailored = tailored.replace(/\\.?\\s*$/, `. My experience also includes ${skillList}.`);\n      reasons.push(`Added matching skills: ${skillList}`);\n    }\n\n    if (matchingSkills.length > 0) {\n      reasons.push(`${matchingSkills.length} matching skills detected`);\n    }\n  }\n\n  // \u2500\u2500\u2500 Seniority alignment \u2500\u2500\u2500\n  if (context.seniority) {\n    const seniorityPhrases: Record<string, string> = {\n      senior: 'extensive experience',\n      mid: 'solid hands-on experience',\n      junior: 'strong foundation and eagerness to grow',\n      manager: 'proven leadership experience',\n    };\n    const phrase = seniorityPhrases[context.seniority];\n    if (phrase && (lowerLabel.includes('experience') || lowerLabel.includes('summary') || lowerLabel.includes('about'))) {\n      if (!lowerResponse.includes(phrase)) {\n        // Only add if response is substantial\n        if (tailored.length > 50) {\n          tailored = tailored.replace(/^(.{0,100}?\\.)/, `$1 I bring ${phrase} in this domain.`);\n          reasons.push(`Aligned seniority: ${context.seniority}`);\n        }\n      }\n    }\n  }\n\n  // \u2500\u2500\u2500 User profile keywords injection \u2500\u2500\u2500\n  if (settings.targetKeywords.length > 0) {\n    const targetMissing = settings.targetKeywords.filter((k) => !lowerResponse.includes(k.toLowerCase()));\n    if (targetMissing.length > 0 && tailored.length > 40) {\n      // Weave in up to 3 target keywords naturally\n      const toAdd = targetMissing.slice(0, 3);\n      if (lowerLabel.includes('additional') || lowerLabel.includes('note') || lowerLabel.includes('comment') || lowerLabel.includes('summary')) {\n        tailored = tailored.replace(/\\.?\\s*$/, `. Key strengths: ${toAdd.join(', ')}.`);\n        reasons.push(`Target keywords added: ${toAdd.join(', ')}`);\n      }\n    }\n  }\n\n  // If no changes were made, return original\n  if (tailored === originalResponse) {\n    return {\n      originalResponse,\n      tailoredResponse: originalResponse,\n      fieldLabel,\n      confidence: 1.0,\n      reasoning: 'No tailoring opportunities for this field',\n    };\n  }\n\n  // Scale confidence based on how many modifications were made\n  confidence = Math.max(0.7, 1.0 - reasons.length * 0.05);\n\n  return {\n    originalResponse,\n    tailoredResponse: tailored,\n    fieldLabel,\n    confidence,\n    reasoning: reasons.join('; ') || 'Tailored',\n  };\n}\n\n/**\n * Tailor all responses for a page given the extracted job context.\n * Returns a map of responseId -> tailoredResponse.\n */\nexport async function tailorResponsesForPage(\n  responses: SavedResponse[],\n  fieldLabels: Map<string, string>,  // responseId -> fieldLabel\n  context: TailoringContext,\n): Promise<Map<string, TailoredResponse>> {\n  const s = await loadSettings();\n  const results = new Map<string, TailoredResponse>();\n\n  if (!s.tailoring.enabled) return results;\n\n  for (const resp of responses) {\n    const label = fieldLabels.get(resp.id) || '';\n    const tailored = tailorResponse(resp.response, label, context, s.tailoring);\n    if (tailored.tailoredResponse !== resp.response) {\n      results.set(resp.id, tailored);\n    }\n  }\n\n  return results;\n}\n", "/**\n * Answer Bank / Learning System\n * Stores answers keyed by normalized field label for future reuse.\n * Learns from filled forms and provides answers for unfamiliar fields.\n */\n\nconst ANSWER_BANK_KEY = 'ua_answer_bank';\nconst PROFILE_KEY = 'ua_user_profile';\n\nexport interface UserProfile {\n  first_name?: string;\n  last_name?: string;\n  middle_name?: string;\n  preferred_name?: string;\n  email?: string;\n  phone?: string;\n  city?: string;\n  state?: string;\n  postal_code?: string;\n  country?: string;\n  address?: string;\n  linkedin?: string;\n  github?: string;\n  website?: string;\n  twitter?: string;\n  school?: string;\n  degree?: string;\n  major?: string;\n  gpa?: string;\n  graduation_year?: string;\n  current_title?: string;\n  current_company?: string;\n  expected_salary?: string;\n  cover_letter?: string;\n  summary?: string;\n  languages?: string;\n  certifications?: string;\n  nationality?: string;\n  [key: string]: string | undefined;\n}\n\nlet _answerBank: Record<string, string> = {};\nlet _loaded = false;\n\nexport function normalizeKey(s: string): string {\n  return (s || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/\\s+/g, ' ').trim();\n}\n\nexport async function loadAnswerBank(): Promise<Record<string, string>> {\n  if (_loaded) return _answerBank;\n  const r = await chrome.storage.local.get(ANSWER_BANK_KEY);\n  _answerBank = r[ANSWER_BANK_KEY] || {};\n  _loaded = true;\n  return _answerBank;\n}\n\nexport async function learnAnswer(label: string, value: string): Promise<void> {\n  if (!label || !value) return;\n  const key = normalizeKey(label);\n  if (!key) return;\n  _answerBank[key] = value;\n  await chrome.storage.local.set({ [ANSWER_BANK_KEY]: _answerBank });\n}\n\nexport function getLearnedAnswer(label: string, el?: HTMLElement): string {\n  const candidates = [\n    label,\n    el?.getAttribute('name') || '',\n    el?.id || '',\n    (el as HTMLInputElement)?.placeholder || '',\n    el?.getAttribute('aria-label') || '',\n  ].filter(Boolean);\n\n  // Exact match\n  for (const c of candidates) {\n    const k = normalizeKey(c);\n    if (_answerBank[k]) return _answerBank[k];\n  }\n\n  // Partial match\n  for (const c of candidates) {\n    const k = normalizeKey(c);\n    if (!k) continue;\n    for (const [bk, bv] of Object.entries(_answerBank)) {\n      if (k.includes(bk) || bk.includes(k)) return bv;\n    }\n  }\n\n  return '';\n}\n\n/**\n * Capture all filled field values from the current page into the answer bank.\n */\nexport async function learnFromPage(doc: Document): Promise<number> {\n  await loadAnswerBank();\n\n  const selector = 'input:not([type=\"hidden\"]):not([type=\"file\"]):not([type=\"submit\"]):not([type=\"button\"]),textarea,select';\n  const elements = doc.querySelectorAll<HTMLElement>(selector);\n  let learned = 0;\n\n  for (const el of elements) {\n    if (!isVisible(el)) continue;\n    if (!hasFieldValue(el)) continue;\n\n    const lbl = getFieldLabel(el);\n    if (!lbl) continue;\n\n    let val: string;\n    if (el instanceof HTMLSelectElement) {\n      val = (el.options[el.selectedIndex]?.textContent || el.value || '').trim();\n    } else {\n      val = ((el as HTMLInputElement).value || '').trim();\n    }\n\n    if (val) {\n      await learnAnswer(lbl, val);\n      learned++;\n    }\n  }\n\n  return learned;\n}\n\nexport async function loadProfile(): Promise<UserProfile> {\n  const r = await chrome.storage.local.get(PROFILE_KEY);\n  return r[PROFILE_KEY] || {};\n}\n\nexport async function saveProfile(profile: UserProfile): Promise<void> {\n  await chrome.storage.local.set({ [PROFILE_KEY]: profile });\n}\n\n// \u2500\u2500\u2500 Helpers \u2500\u2500\u2500\n\nfunction isVisible(el: HTMLElement): boolean {\n  if (!el) return false;\n  const r = el.getBoundingClientRect();\n  return r.width > 0 && r.height > 0 && el.offsetParent !== null;\n}\n\nfunction hasFieldValue(el: HTMLElement): boolean {\n  if (el instanceof HTMLSelectElement) {\n    const val = (el.value || '').trim();\n    if (!val) return false;\n    const idx = el.selectedIndex;\n    if (idx >= 0) {\n      const txt = (el.options[idx]?.textContent || '').trim().toLowerCase();\n      if (!txt || /^(select|choose|please|--|\u2014)/.test(txt)) return false;\n    }\n    return true;\n  }\n  if (el instanceof HTMLInputElement) {\n    if (el.type === 'checkbox' || el.type === 'radio') return !!el.checked;\n    return !!el.value?.trim();\n  }\n  if (el instanceof HTMLTextAreaElement) return !!el.value?.trim();\n  return false;\n}\n\nfunction getFieldLabel(el: HTMLElement): string {\n  const ariaLabel = el.getAttribute('aria-label');\n  if (ariaLabel?.trim()) return ariaLabel.trim();\n\n  if (el.id) {\n    const lbl = el.ownerDocument.querySelector(`label[for=\"${CSS.escape(el.id)}\"]`);\n    if (lbl?.textContent?.trim()) return lbl.textContent.trim();\n  }\n\n  if ((el as HTMLInputElement).placeholder?.trim()) return (el as HTMLInputElement).placeholder.trim();\n\n  const container = el.closest('.form-group,.field,.question,[class*=\"Field\"],[class*=\"Question\"],[class*=\"form-row\"],li,.form-item,.ant-form-item,.ant-row');\n  if (container) {\n    const lbl = container.querySelector('label,[class*=\"label\"],[class*=\"Label\"]');\n    if (lbl && lbl !== el && lbl.textContent?.trim()) return lbl.textContent.trim();\n  }\n\n  const name = el.getAttribute('name');\n  if (name) return name.replace(/[_\\-]/g, ' ');\n\n  return '';\n}\n", "/**\n * Smart Value Guesser\n * Regex-based field interpretation with 50+ patterns covering:\n * - Personal info (name, email, phone, address)\n * - Education (school, degree, GPA)\n * - Work (title, company, salary)\n * - Legal/EEO (authorization, veteran, disability, gender, race)\n * - Application meta (cover letter, availability, how heard)\n */\n\nimport type { UserProfile } from '../answerBank/index';\n\nconst DEFAULTS: Record<string, string> = {\n  authorized: 'Yes',\n  sponsorship: 'No',\n  relocation: 'Yes',\n  remote: 'Yes',\n  veteran: 'I am not a protected veteran',\n  disability: 'I do not have a disability',\n  gender: 'Prefer not to say',\n  ethnicity: 'Prefer not to say',\n  race: 'Prefer not to say',\n  years: '5',\n  salary: '80000',\n  notice: '2 weeks',\n  availability: 'Immediately',\n  cover: 'I am excited to apply for this role. My background and skills make me an excellent candidate and I look forward to contributing to your team.',\n  why: 'I admire the company culture and the opportunity to make a meaningful impact.',\n  howHeard: 'LinkedIn',\n};\n\n/**\n * Guess a field value based on the field label and user profile.\n * Returns empty string if no guess is possible.\n */\nexport function guessValue(label: string, profile: UserProfile): string {\n  const l = (label || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ');\n\n  // \u2500\u2500\u2500 Personal Info \u2500\u2500\u2500\n  if (/first.?name|given.?name|prenom/.test(l)) return profile.first_name || '';\n  if (/last.?name|family.?name|surname/.test(l)) return profile.last_name || '';\n  if (/middle.?name/.test(l)) return profile.middle_name || '';\n  if (/preferred.?name|nick.?name/.test(l)) return profile.preferred_name || profile.first_name || '';\n  if (/full.?name|your name|^name$/.test(l) && !/company|last|first|user/.test(l))\n    return `${profile.first_name || ''} ${profile.last_name || ''}`.trim();\n  if (/\\bemail\\b/.test(l)) return profile.email || '';\n  if (/phone|mobile|cell|telephone/.test(l)) return profile.phone || '';\n\n  // \u2500\u2500\u2500 Address \u2500\u2500\u2500\n  if (/^city$|\\bcity\\b|current.?city/.test(l)) return profile.city || '';\n  if (/state|province|region/.test(l)) return profile.state || '';\n  if (/zip|postal/.test(l)) return profile.postal_code || '';\n  if (/country/.test(l)) return profile.country || 'United States';\n  if (/address|street/.test(l)) return profile.address || '';\n  if (/location|where.*(you|do you).*live/.test(l))\n    return profile.city ? `${profile.city}, ${profile.state || ''}`.trim().replace(/,$/, '') : '';\n\n  // \u2500\u2500\u2500 Online Profiles \u2500\u2500\u2500\n  if (/linkedin/.test(l)) return profile.linkedin || '';\n  if (/github/.test(l)) return profile.github || '';\n  if (/website|portfolio|personal.?url/.test(l)) return profile.website || '';\n  if (/twitter|x\\.com/.test(l)) return profile.twitter || '';\n\n  // \u2500\u2500\u2500 Education \u2500\u2500\u2500\n  if (/university|school|college|alma.?mater/.test(l)) return profile.school || '';\n  if (/\\bdegree\\b|qualification/.test(l)) return profile.degree || \"Bachelor's\";\n  if (/major|field.?of.?study|concentration/.test(l)) return profile.major || '';\n  if (/gpa|grade.?point/.test(l)) return profile.gpa || '';\n  if (/graduation|grad.?date|grad.?year/.test(l)) return profile.graduation_year || '';\n\n  // \u2500\u2500\u2500 Work \u2500\u2500\u2500\n  if (/title|position|role|current.?title|job.?title/.test(l) && !/company/.test(l))\n    return profile.current_title || '';\n  if (/company|employer|org|current.?company/.test(l)) return profile.current_company || '';\n  if (/salary|compensation|pay|desired.?pay/.test(l)) return profile.expected_salary || DEFAULTS.salary;\n\n  // \u2500\u2500\u2500 Application Meta \u2500\u2500\u2500\n  if (/cover.?letter|motivation|additional.?info|message.?to/.test(l))\n    return profile.cover_letter || DEFAULTS.cover;\n  if (/summary|about.?(yourself|you|me)|bio|objective/.test(l))\n    return profile.summary || profile.cover_letter || DEFAULTS.cover;\n  if (/why.*(compan|role|want|interest|position)/.test(l)) return DEFAULTS.why;\n  if (/how.*hear|where.*(find|learn|discover)|source|referred/.test(l)) return DEFAULTS.howHeard;\n  if (/years.*(exp|work)|exp.*years|total.*experience/.test(l)) return DEFAULTS.years;\n  if (/availab|start.?date|notice|when.*start/.test(l)) return DEFAULTS.availability;\n\n  // \u2500\u2500\u2500 Legal / Authorization \u2500\u2500\u2500\n  if (/authoriz|eligible|work.*right|legal.*right/.test(l)) return DEFAULTS.authorized;\n  if (/sponsor|visa|immigration|work.?permit/.test(l)) return DEFAULTS.sponsorship;\n  if (/relocat|willing.*move/.test(l)) return DEFAULTS.relocation;\n  if (/remote|work.*home|hybrid|on.?site/.test(l)) return DEFAULTS.remote;\n\n  // \u2500\u2500\u2500 EEO / Demographics \u2500\u2500\u2500\n  if (/veteran|military|armed.?forces/.test(l)) return DEFAULTS.veteran;\n  if (/disabilit/.test(l)) return DEFAULTS.disability;\n  if (/gender|sex\\b|pronouns/.test(l)) return DEFAULTS.gender;\n  if (/ethnic|race|racial|heritage/.test(l)) return DEFAULTS.ethnicity;\n  if (/nationality|citizenship/.test(l)) return profile.nationality || profile.country || 'United States';\n  if (/language|fluency|fluent/.test(l)) return profile.languages || 'English';\n  if (/certif|license|credential/.test(l)) return profile.certifications || '';\n\n  // \u2500\u2500\u2500 Yes/No Questions \u2500\u2500\u2500\n  if (/commute|travel|willing.*travel/.test(l)) return 'Yes';\n  if (/convicted|criminal|felony|background/.test(l)) return 'No';\n  if (/drug.?test|screening/.test(l)) return 'Yes';\n  if (/\\bage\\b|18.*years|over.*18|at.*least.*18/.test(l)) return 'Yes';\n  if (/agree|acknowledge|certif|attest|confirm|consent/.test(l)) return 'Yes';\n  if (/please.?specify|other.?please/.test(l)) return profile.city || profile.state || '';\n\n  return '';\n}\n\nexport { DEFAULTS };\n", "/**\n * Fallback Form Filler\n * Fills fields that the primary autofill missed, including:\n * - Text inputs and textareas via smart value guesser + answer bank\n * - Select dropdowns with EEO \"Prefer not to say\" fallback\n * - Radio button groups (Yes/No defaults)\n * - Required checkboxes\n */\n\nimport { guessValue } from './valueGuesser';\nimport { loadAnswerBank, getLearnedAnswer, type UserProfile } from '../answerBank/index';\n\n// \u2500\u2500\u2500 DOM Helpers \u2500\u2500\u2500\n\nfunction isVisible(el: HTMLElement): boolean {\n  if (!el) return false;\n  const r = el.getBoundingClientRect();\n  return r.width > 0 && r.height > 0 && el.offsetParent !== null;\n}\n\nfunction nativeSet(el: HTMLElement, val: string): void {\n  try {\n    const proto = el.tagName === 'TEXTAREA' ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype;\n    const setter = Object.getOwnPropertyDescriptor(proto, 'value')?.set;\n    if (setter) setter.call(el, val);\n    else (el as HTMLInputElement).value = val;\n  } catch {\n    (el as HTMLInputElement).value = val;\n  }\n  el.dispatchEvent(new Event('input', { bubbles: true }));\n  el.dispatchEvent(new Event('change', { bubbles: true }));\n  el.dispatchEvent(new Event('blur', { bubbles: true }));\n}\n\nfunction realClick(el: HTMLElement): void {\n  if (!el) return;\n  el.dispatchEvent(new MouseEvent('mouseover', { bubbles: true }));\n  el.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));\n  el.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));\n  el.click();\n}\n\nfunction getLabel(el: HTMLElement): string {\n  if (!el) return '';\n  const ariaLabel = el.getAttribute('aria-label');\n  if (ariaLabel?.trim()) return ariaLabel.trim();\n\n  if (el.id) {\n    const lbl = el.ownerDocument.querySelector(`label[for=\"${CSS.escape(el.id)}\"]`);\n    if (lbl?.textContent?.trim()) return lbl.textContent.trim();\n  }\n\n  if ((el as HTMLInputElement).placeholder?.trim()) return (el as HTMLInputElement).placeholder.trim();\n\n  const container = el.closest('.form-group,.field,.question,[class*=\"Field\"],[class*=\"Question\"],[class*=\"form-row\"],li,.form-item,.ant-form-item,.ant-row');\n  if (container) {\n    const lbl = container.querySelector('label,[class*=\"label\"],[class*=\"Label\"]');\n    if (lbl && lbl !== el && lbl.textContent?.trim()) return lbl.textContent.trim();\n  }\n\n  return el.getAttribute('name')?.replace(/[_\\-]/g, ' ') || '';\n}\n\nfunction hasFieldValue(el: HTMLElement): boolean {\n  if (el instanceof HTMLSelectElement) {\n    const val = (el.value || '').trim();\n    if (!val) return false;\n    const idx = el.selectedIndex;\n    if (idx >= 0) {\n      const txt = (el.options[idx]?.textContent || '').trim().toLowerCase();\n      if (!txt || /^(select|choose|please|--|\u2014)/.test(txt)) return false;\n    }\n    return true;\n  }\n  if (el instanceof HTMLInputElement) {\n    if (el.type === 'checkbox' || el.type === 'radio') return !!el.checked;\n    return !!el.value?.trim();\n  }\n  if (el instanceof HTMLTextAreaElement) return !!el.value?.trim();\n  return false;\n}\n\nfunction isFieldRequired(el: HTMLElement): boolean {\n  if ((el as HTMLInputElement).required || el.getAttribute('aria-required') === 'true') return true;\n  const container = el.closest('.field,.question,[class*=\"field\"],[class*=\"Field\"],[class*=\"question\"],li,div');\n  const label = getLabel(el);\n  if (/\\*\\s*$|required/i.test(label || '')) return true;\n  if (container) {\n    if (container.classList.contains('required')) return true;\n    if (container.getAttribute('data-required') === 'true') return true;\n    if (container.querySelector('.required,.asterisk,[aria-label*=\"required\" i]')) return true;\n  }\n  return false;\n}\n\nfunction sleep(ms: number): Promise<void> {\n  return new Promise((r) => setTimeout(r, ms));\n}\n\nfunction guessFieldValue(label: string, profile: UserProfile, el?: HTMLElement): string {\n  return guessValue(label, profile) || getLearnedAnswer(label, el) || '';\n}\n\n// \u2500\u2500\u2500 Main Fallback Fill \u2500\u2500\u2500\n\n/**\n * Fills unfilled form fields using smart guessing + answer bank.\n * Returns the number of fields filled.\n */\nexport async function fallbackFill(doc: Document, profile: UserProfile): Promise<number> {\n  await loadAnswerBank();\n  let filled = 0;\n\n  // 1. Text inputs & textareas \u2014 only unfilled visible ones\n  const inputs = Array.from(\n    doc.querySelectorAll<HTMLElement>('input:not([type=\"hidden\"]):not([type=\"file\"]):not([type=\"submit\"]):not([type=\"button\"]):not([type=\"reset\"]):not([type=\"image\"]),textarea')\n  ).filter((el) => isVisible(el) && !(el as HTMLInputElement).value?.trim());\n\n  for (const inp of inputs) {\n    const lbl = getLabel(inp);\n    if (!lbl) continue;\n    const val = guessFieldValue(lbl, profile, inp);\n    if (!val) continue;\n    inp.focus();\n    nativeSet(inp, val);\n    inp.classList.add('ua-filled');\n    filled++;\n    await sleep(60);\n  }\n\n  // 2. Select dropdowns \u2014 only unselected ones\n  const selects = Array.from(doc.querySelectorAll<HTMLSelectElement>('select')).filter(\n    (el) => isVisible(el) && !hasFieldValue(el)\n  );\n\n  for (const sel of selects) {\n    const lbl = getLabel(sel);\n    const val = guessFieldValue(lbl, profile, sel);\n    if (!val) {\n      // EEO fallback: select \"Prefer not to say\" for sensitive fields\n      const lblLower = (lbl || '').toLowerCase();\n      if (/gender|disability|veteran|race|ethnicity|sex\\b|heritage/i.test(lblLower)) {\n        const opts = Array.from(sel.options).filter((o) => o.value && o.index > 0);\n        const fb = opts.find((o) => /prefer not|decline|not to|do not|don.t wish/i.test(o.text));\n        if (fb) {\n          sel.value = fb.value;\n          sel.dispatchEvent(new Event('change', { bubbles: true }));\n          sel.classList.add('ua-filled');\n          filled++;\n        }\n      }\n      continue;\n    }\n    // Try to find a matching option\n    const opt = Array.from(sel.options).find((o) =>\n      o.text.toLowerCase().includes(val.toLowerCase())\n    );\n    if (opt) {\n      sel.value = opt.value;\n      sel.dispatchEvent(new Event('change', { bubbles: true }));\n      sel.classList.add('ua-filled');\n      filled++;\n    } else {\n      // Fallback: select first valid option\n      const opts = Array.from(sel.options).filter((o) => o.value && o.index > 0);\n      if (opts.length) {\n        sel.value = opts[0].value;\n        sel.dispatchEvent(new Event('change', { bubbles: true }));\n        sel.classList.add('ua-filled');\n        filled++;\n      }\n    }\n  }\n\n  // 3. Radio buttons \u2014 only unselected groups\n  const groups: Record<string, HTMLInputElement[]> = {};\n  const radios = Array.from(doc.querySelectorAll<HTMLInputElement>('input[type=\"radio\"]')).filter(isVisible);\n  for (const r of radios) {\n    const key = r.name || r.id;\n    if (!key) continue;\n    (groups[key] ||= []).push(r);\n  }\n\n  for (const [, radioGroup] of Object.entries(groups)) {\n    if (radioGroup.some((r) => r.checked)) continue;\n    const lbl = getLabel(radioGroup[0]);\n    const guess = guessFieldValue(lbl, profile, radioGroup[0]);\n\n    // Try matching by guess value\n    const match = radioGroup.find((r) => {\n      const labelEl = r.id ? doc.querySelector(`label[for=\"${CSS.escape(r.id)}\"]`) : null;\n      const t = (labelEl?.textContent || r.value || '').toLowerCase();\n      return guess && t.includes(guess.toLowerCase());\n    });\n    if (match) {\n      realClick(match);\n      filled++;\n      continue;\n    }\n\n    // Default: select \"Yes\" for yes/no questions\n    const yesRadio = radioGroup.find((r) => {\n      const labelEl = r.id ? doc.querySelector(`label[for=\"${CSS.escape(r.id)}\"]`) : null;\n      const t = (labelEl?.textContent || r.value || '').toLowerCase().trim();\n      return ['yes', 'true', '1'].includes(t);\n    });\n    if (yesRadio) {\n      realClick(yesRadio);\n      filled++;\n    }\n  }\n\n  // 4. Required checkboxes \u2014 auto-check\n  const requiredCheckboxes = Array.from(\n    doc.querySelectorAll<HTMLInputElement>(\n      'input[type=\"checkbox\"][required],input[type=\"checkbox\"][aria-required=\"true\"]'\n    )\n  ).filter((el) => isVisible(el) && !el.checked);\n\n  for (const cb of requiredCheckboxes) {\n    realClick(cb);\n    filled++;\n  }\n\n  return filled;\n}\n\n/**\n * Returns labels of required fields that are still missing values.\n */\nexport function getMissingRequired(doc: Document): string[] {\n  const required = Array.from(\n    doc.querySelectorAll<HTMLElement>('input:not([type=\"hidden\"]),textarea,select')\n  ).filter((el) => isVisible(el) && isFieldRequired(el));\n\n  const missing: string[] = [];\n  for (const el of required) {\n    if (el instanceof HTMLInputElement && el.type === 'radio' && el.name) {\n      const group = Array.from(\n        doc.querySelectorAll<HTMLInputElement>(`input[type=\"radio\"][name=\"${CSS.escape(el.name)}\"]`)\n      ).filter(isVisible);\n      if (group.some((r) => r.checked)) continue;\n    } else if (el instanceof HTMLInputElement && el.type === 'checkbox' && !el.checked) {\n      // required checkbox must be checked\n    } else if (hasFieldValue(el)) {\n      continue;\n    }\n    const lbl = getLabel(el) || el.getAttribute('name') || el.id || 'Required field';\n    if (!missing.includes(lbl)) missing.push(lbl);\n  }\n  return missing;\n}\n", "/**\n * Application Success Detector\n * Multiple detection methods:\n * - URL pattern matching (thanks, confirmation, success pages)\n * - Page text analysis (thank you messages, confirmation text)\n * - DOM element detection (confirmation elements, Workday-specific markers)\n */\n\n/**\n * Check if the current page indicates a successful application submission.\n */\nexport function checkSuccess(doc: Document): boolean {\n  const href = (doc.location?.href || '').toLowerCase();\n\n  // URL-based detection\n  if (/\\/thanks|\\/thank.you|\\/success|\\/confirmation|\\/submitted|\\/done|\\/complete/i.test(href)) {\n    return true;\n  }\n\n  // Body text analysis\n  const body = doc.body?.innerText || '';\n  if (/application submitted|thank you for applying|application received|we.ve received your|successfully submitted|application complete|thanks for applying|your application has been|application was submitted/i.test(body)) {\n    return true;\n  }\n\n  // DOM element detection\n  const confirmationSelectors = [\n    '#application_confirmation',\n    '.application-confirmation',\n    '.confirmation-text',\n    '.posting-confirmation',\n    '[data-automation-id=\"congratulationsMessage\"]',\n    '[data-automation-id=\"confirmationMessage\"]',\n    '.success-message',\n    '.submission-confirmation',\n    '[data-testid=\"application-success\"]',\n    '[data-testid=\"confirmation-page\"]',\n  ];\n\n  for (const sel of confirmationSelectors) {\n    if (doc.querySelector(sel)) return true;\n  }\n\n  return false;\n}\n\n/**\n * Find a \"Next\" or \"Continue\" button on a multi-step form.\n */\nexport function findNextButton(doc: Document): HTMLElement | null {\n  const nextSelectors = [\n    'button[data-automation-id=\"bottom-navigation-next-button\"]',\n    'button[data-automation-id=\"pageFooterNextButton\"]',\n    'button[data-automation-id=\"next-button\"]',\n    'button[aria-label*=\"Next\" i]',\n    'button[aria-label*=\"Continue\" i]',\n    '[data-testid=\"next-step\"]',\n    '[data-testid=\"continue\"]',\n    '.btn-next',\n    '.next-button',\n  ];\n\n  for (const sel of nextSelectors) {\n    const btn = doc.querySelector(sel) as HTMLElement;\n    if (btn && btn.offsetParent !== null) return btn;\n  }\n\n  // Text-based fallback\n  const allBtns = doc.querySelectorAll('button,a[role=\"button\"]');\n  for (const btn of allBtns) {\n    const t = (btn.textContent || '').trim().toLowerCase();\n    if (/^(next|continue|proceed|save.*continue|review)\\b/i.test(t) &&\n        !/cancel|back|prev|close/i.test(t) &&\n        (btn as HTMLElement).offsetParent !== null) {\n      return btn as HTMLElement;\n    }\n  }\n\n  return null;\n}\n\n/**\n * Find a submit/apply button.\n */\nexport function findSubmitButton(doc: Document): HTMLElement | null {\n  const submitSelectors = [\n    'button[type=\"submit\"]',\n    'input[type=\"submit\"]',\n    'button[data-automation-id=\"submit\"]',\n    'button[data-automation-id=\"submitButton\"]',\n    '#submit_app',\n    '.postings-btn-submit',\n    'button.application-submit',\n    'button[data-qa=\"btn-submit\"]',\n    'button[aria-label*=\"Submit\" i]',\n    '[data-testid=\"submit-application\"]',\n    '[data-testid=\"submit-button\"]',\n    '[data-testid=\"apply-button\"]',\n    'button.btn-submit',\n    'button[aria-label=\"Submit application\"]',\n    'button[aria-label=\"Apply\"]',\n  ];\n\n  for (const sel of submitSelectors) {\n    const btn = doc.querySelector(sel) as HTMLElement;\n    if (btn && btn.offsetParent !== null) return btn;\n  }\n\n  // Text-based fallback\n  const allBtns = doc.querySelectorAll('button,a[role=\"button\"],input[type=\"submit\"]');\n  for (const btn of allBtns) {\n    const t = ((btn as HTMLElement).textContent || (btn as HTMLInputElement).value || '').trim().toLowerCase();\n    if (/^(submit|apply|send|complete|finish)\\b/i.test(t) &&\n        !/cancel|back|prev|close/i.test(t) &&\n        (btn as HTMLElement).offsetParent !== null) {\n      return btn as HTMLElement;\n    }\n  }\n\n  return null;\n}\n", "/**\n * Multi-Page Form Handler\n * Handles multi-step application forms (up to 10 pages).\n * On each page: fill fields \u2192 fallback fill \u2192 submit/next \u2192 detect success.\n */\n\nimport { fallbackFill, getMissingRequired } from './fallbackFiller';\nimport { checkSuccess, findNextButton, findSubmitButton } from './successDetector';\nimport { learnFromPage, loadProfile, type UserProfile } from '../answerBank/index';\n\nconst MAX_PAGES = 10;\n\nfunction sleep(ms: number): Promise<void> {\n  return new Promise((r) => setTimeout(r, ms));\n}\n\nfunction realClick(el: HTMLElement): void {\n  if (!el) return;\n  el.scrollIntoView?.({ behavior: 'smooth', block: 'center' });\n  el.dispatchEvent(new MouseEvent('mouseover', { bubbles: true }));\n  el.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));\n  el.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));\n  el.click();\n}\n\nexport type PageAction = 'submitted' | 'next_page' | 'no_action';\n\n/**\n * Attempt to submit the form or click next/continue.\n * Learns from filled fields before navigating.\n * Returns the action taken.\n */\nexport async function autoSubmitOrNext(doc: Document): Promise<PageAction> {\n  // Learn from the filled page before navigating\n  await learnFromPage(doc);\n\n  const missing = getMissingRequired(doc);\n\n  // If no required fields missing, try submit first\n  if (missing.length === 0) {\n    const submitBtn = findSubmitButton(doc);\n    if (submitBtn) {\n      await sleep(500);\n      realClick(submitBtn);\n      return 'submitted';\n    }\n  }\n\n  // Try next/continue button\n  const nextBtn = findNextButton(doc);\n  if (nextBtn) {\n    await sleep(500);\n    realClick(nextBtn);\n    return 'next_page';\n  }\n\n  // If there are required missing but we have a submit button, still try (form might validate)\n  if (missing.length > 0) {\n    const submitBtn = findSubmitButton(doc);\n    if (submitBtn) {\n      await sleep(500);\n      realClick(submitBtn);\n      return 'submitted';\n    }\n  }\n\n  return 'no_action';\n}\n\nexport interface MultiPageResult {\n  pagesProcessed: number;\n  success: boolean;\n  finalAction: PageAction;\n  totalFieldsFilled: number;\n}\n\n/**\n * Process a multi-page application form.\n * Fills and submits/advances through up to MAX_PAGES pages.\n *\n * @param doc - The document to process\n * @param fillPageFn - A function that fills the current page (primary autofill).\n *                     Called before fallback fill on each page.\n * @param profile - User profile for smart value guessing\n */\nexport async function multiPageLoop(\n  doc: Document,\n  fillPageFn: () => Promise<number>,\n  profile?: UserProfile,\n): Promise<MultiPageResult> {\n  const userProfile = profile || await loadProfile();\n  let totalFilled = 0;\n  let finalAction: PageAction = 'no_action';\n\n  for (let page = 1; page <= MAX_PAGES; page++) {\n    // Check for success before processing\n    if (checkSuccess(doc)) {\n      return { pagesProcessed: page - 1, success: true, finalAction, totalFieldsFilled: totalFilled };\n    }\n\n    // Wait for page content to render\n    await sleep(2000);\n\n    // Primary autofill\n    const primaryFilled = await fillPageFn();\n    totalFilled += primaryFilled;\n\n    // Fallback fill to catch missed fields\n    await sleep(1000);\n    const fallback1 = await fallbackFill(doc, userProfile);\n    totalFilled += fallback1;\n\n    // Second pass fallback (catches fields revealed by first pass)\n    await sleep(500);\n    const fallback2 = await fallbackFill(doc, userProfile);\n    totalFilled += fallback2;\n\n    // Submit or next\n    const action = await autoSubmitOrNext(doc);\n    finalAction = action;\n\n    if (action === 'submitted') {\n      await sleep(3000);\n      const success = checkSuccess(doc);\n      return { pagesProcessed: page, success, finalAction: action, totalFieldsFilled: totalFilled };\n    } else if (action === 'next_page') {\n      await sleep(3000);\n      continue;\n    } else {\n      // No button found \u2014 try one more fallback + submit attempt\n      await sleep(2000);\n      const extra = await fallbackFill(doc, userProfile);\n      totalFilled += extra;\n      const retry = await autoSubmitOrNext(doc);\n      finalAction = retry;\n      if (retry !== 'no_action') {\n        await sleep(3000);\n        const success = retry === 'submitted' ? checkSuccess(doc) : false;\n        return { pagesProcessed: page, success, finalAction: retry, totalFieldsFilled: totalFilled };\n      }\n      break;\n    }\n  }\n\n  return { pagesProcessed: MAX_PAGES, success: false, finalAction, totalFieldsFilled: totalFilled };\n}\n", "/**\n * Workday-Specific Automation\n * Handles Workday's unique application flow:\n * - Clicks \"Apply\" button\n * - Clicks \"Apply Manually\" button\n * - Waits for form pages to load\n * - Integrates with multi-page handler\n */\n\nfunction sleep(ms: number): Promise<void> {\n  return new Promise((r) => setTimeout(r, ms));\n}\n\nfunction isVisible(el: HTMLElement): boolean {\n  if (!el) return false;\n  const r = el.getBoundingClientRect();\n  return r.width > 0 && r.height > 0 && el.offsetParent !== null;\n}\n\nfunction realClick(el: HTMLElement): void {\n  if (!el) return;\n  el.scrollIntoView?.({ behavior: 'smooth', block: 'center' });\n  el.dispatchEvent(new MouseEvent('mouseover', { bubbles: true }));\n  el.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));\n  el.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));\n  el.click();\n}\n\nfunction waitFor(doc: Document, selector: string, timeout: number, xpath = false): Promise<HTMLElement | null> {\n  return new Promise((resolve) => {\n    const find = () => {\n      if (xpath) {\n        return doc.evaluate(selector, doc, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null).singleNodeValue as HTMLElement;\n      }\n      return doc.querySelector(selector) as HTMLElement;\n    };\n\n    const el = find();\n    if (el) { resolve(el); return; }\n\n    const observer = new MutationObserver(() => {\n      const el = find();\n      if (el) { observer.disconnect(); resolve(el); }\n    });\n\n    observer.observe(doc.body || doc.documentElement, { childList: true, subtree: true });\n    setTimeout(() => { observer.disconnect(); resolve(null); }, timeout);\n  });\n}\n\n/**\n * Navigate through Workday's initial apply flow.\n * Returns true if we successfully reached the application form.\n */\nexport async function workdayNavigateToForm(doc: Document): Promise<boolean> {\n  // Step 1: Click the \"Apply\" button\n  const allBtns = doc.querySelectorAll('a, button');\n  for (const b of allBtns) {\n    if (/^\\s*Apply\\s*$/i.test(b.textContent || '') && isVisible(b as HTMLElement)) {\n      realClick(b as HTMLElement);\n      await sleep(2000);\n      break;\n    }\n  }\n\n  // Step 2: Click \"Apply Manually\" if present\n  const applyManually = await waitFor(doc, \"//*[@data-automation-id='applyManually']\", 8000, true);\n  if (applyManually) {\n    await sleep(500);\n    realClick(applyManually);\n    await sleep(2000);\n  }\n\n  // Step 3: Wait for the form page to appear\n  const formPageSelectors = [\n    \"[data-automation-id='quickApplyPage']\",\n    \"[data-automation-id='applyFlowAutoFillPage']\",\n    \"[data-automation-id='contactInformationPage']\",\n    \"[data-automation-id='applyFlowMyInfoPage']\",\n    \"[data-automation-id='ApplyFlowPage']\",\n  ].join(',');\n\n  const formPage = await waitFor(doc, formPageSelectors, 10000);\n  if (formPage) {\n    await sleep(1000);\n    return true;\n  }\n\n  return false;\n}\n\n/**\n * Check if the current page is a Workday application page.\n */\nexport function isWorkdayPage(url: string): boolean {\n  return /myworkdayjobs\\.com|myworkdaysite\\.com|workday\\.com\\/.*\\/job/i.test(url);\n}\n", "/**\n * Content script - runs on every page.\n * Handles autofill orchestration, ATS detection, universal form detection,\n * AI tailoring, answer bank learning, fallback filling, multi-page form\n * handling, success detection, Workday automation, one-click queue button,\n * auto-apply, and MutationObserver for dynamic pages.\n */\n\nimport type { ExtMessage, FieldMatchResult, SavedResponse, ATSType, TailoringContext } from '../types/index';\nimport { detectATS, isApplicationPage, hasApplicationForm } from '../atsDetector/index';\nimport { getAdapter } from '../adapters/index';\nimport { matchFields } from '../fieldMatcher/index';\nimport { findMatches } from '../savedResponses/matcher';\nimport { extractJobContext, tailorResponse } from '../autoApply/tailoring';\nimport { loadAnswerBank, learnFromPage, loadProfile } from '../answerBank/index';\nimport { fallbackFill, getMissingRequired } from '../smartFill/fallbackFiller';\nimport { checkSuccess, findNextButton, findSubmitButton as findSubmitBtn } from '../smartFill/successDetector';\nimport { multiPageLoop, autoSubmitOrNext } from '../smartFill/multiPageHandler';\nimport { workdayNavigateToForm, isWorkdayPage } from '../smartFill/workdayAutomation';\n\nlet isRunning = false;\nlet observer: MutationObserver | null = null;\nlet autoApplyJobId: string | null = null;\nlet autoSubmitEnabled = false;\n\n// Anti-loop protection: track which pages we've already auto-detected\nconst autoDetectedPages = new Set<string>();\n\n// One-click button state\nlet queueButtonInjected = false;\n\n// \u2500\u2500\u2500 Message handling from background / popup \u2500\u2500\u2500\nchrome.runtime.onMessage.addListener((msg: ExtMessage, _sender, sendResponse) => {\n  if (msg.type === 'START_AUTOFILL') {\n    const payload = msg.payload as any;\n    autoSubmitEnabled = payload?.autoSubmit || false;\n    autoApplyJobId = payload?.jobId || null;\n    startAutofill().then(() => sendResponse({ ok: true })).catch((e) => sendResponse({ ok: false, error: String(e) }));\n    return true;\n  }\n  if (msg.type === 'STOP_AUTOFILL') {\n    stopAutofill();\n    sendResponse({ ok: true });\n  }\n  if (msg.type === 'DETECT_ATS') {\n    const result = detectATS(document);\n    sendResponse(result);\n  }\n  if (msg.type === 'AUTO_DETECT_FILL') {\n    handleAutoDetectFill().then(() => sendResponse({ ok: true })).catch((e) => sendResponse({ ok: false, error: String(e) }));\n    return true;\n  }\n});\n\nasync function send(msg: ExtMessage): Promise<any> {\n  return chrome.runtime.sendMessage(msg);\n}\n\nasync function getResponses(): Promise<SavedResponse[]> {\n  const domain = location.hostname;\n  const r = await send({ type: 'GET_RESPONSES', payload: { domain } });\n  return r?.data || [];\n}\n\n/**\n * Auto-detect ATS (or any application form) and immediately start autofill.\n * Works on ALL supported ATS platforms AND unknown company career sites.\n */\nasync function handleAutoDetectFill() {\n  const pageKey = location.href;\n\n  // Anti-loop: don't re-detect the same page\n  if (autoDetectedPages.has(pageKey)) return;\n  autoDetectedPages.add(pageKey);\n\n  const ats = detectATS(document);\n\n  // Accept known ATS, company sites, AND any page with an application form\n  const isKnownATS = ats.type !== 'generic' && ats.confidence >= 0.3;\n  const isCompanySite = ats.type === 'companysite' && ats.confidence >= 0.3;\n  const hasForm = hasApplicationForm(document);\n\n  if (!isKnownATS && !isCompanySite && !hasForm) {\n    // Still inject the one-click button if this looks remotely like a job page\n    maybeInjectQueueButton();\n    return;\n  }\n\n  // Check credits (always unlimited)\n  const credits = await send({ type: 'CHECK_CREDITS' });\n  if (!credits?.ok || (!credits.data?.unlimited && credits.data?.remaining <= 0)) return;\n\n  // Load answer bank for this session\n  await loadAnswerBank();\n\n  // Auto-start autofill\n  if (!isRunning) {\n    await startAutofill();\n  }\n\n  // Always inject the one-click queue button on job pages\n  maybeInjectQueueButton();\n}\n\nasync function startAutofill() {\n  if (isRunning) return;\n  isRunning = true;\n\n  showControlBar();\n\n  // Load answer bank\n  await loadAnswerBank();\n\n  const ats = detectATS(document);\n  const adapter = getAdapter(ats.type);\n  const responses = await getResponses();\n\n  // Extract job context for AI tailoring\n  const jobContext = extractJobContext(document);\n\n  // Workday-specific: navigate to the form first\n  if (isWorkdayPage(location.href)) {\n    updateControlBar(0, 0, 'Navigating Workday form...');\n    const reached = await workdayNavigateToForm(document);\n    if (!reached) {\n      updateControlBar(0, 0, 'Workday form not found - trying direct fill');\n    }\n  }\n\n  // Initial fill with tailoring\n  const fillResult = await fillPage(adapter, responses, ats.type, jobContext);\n\n  // Fallback fill to catch fields the primary autofill missed\n  const profile = await loadProfile();\n  await randomDelay(500, 1000);\n  const fallbackCount = await fallbackFill(document, profile);\n  if (fallbackCount > 0) {\n    updateControlBar(fillResult.filled + fallbackCount, fillResult.total + fallbackCount, `${fillResult.filled + fallbackCount} fields filled (${fallbackCount} by smart fill)`);\n  }\n\n  // Watch for dynamic changes (multi-step forms)\n  observer = new MutationObserver(async (mutations) => {\n    if (!isRunning) return;\n    const hasNewNodes = mutations.some((m) => m.addedNodes.length > 0);\n    if (hasNewNodes) {\n      await fillPage(adapter, responses, ats.type, jobContext);\n      // Run fallback on new content too\n      await fallbackFill(document, profile);\n    }\n  });\n\n  observer.observe(document.body, { childList: true, subtree: true });\n\n  // Auto-submit if enabled\n  if (autoSubmitEnabled && (fillResult.filled > 0 || fallbackCount > 0)) {\n    await handleAutoSubmitFlow(ats.type, fillResult.filled + fallbackCount, fillResult.total + fallbackCount, adapter, responses, jobContext, profile);\n  }\n}\n\n/**\n * Enhanced auto-submit flow with multi-page support and success detection.\n */\nasync function handleAutoSubmitFlow(\n  atsType: ATSType,\n  filledCount: number,\n  totalCount: number,\n  adapter: ReturnType<typeof getAdapter>,\n  responses: SavedResponse[],\n  jobContext: TailoringContext,\n  profile: Awaited<ReturnType<typeof loadProfile>>,\n) {\n  if (!autoSubmitEnabled) return;\n\n  // Wait for any dynamic updates to settle\n  await randomDelay(1000, 2000);\n\n  // Check if resume is required but missing\n  const resumeInput = document.querySelector('input[type=\"file\"][accept*=\".pdf\"], input[type=\"file\"][accept*=\".doc\"], input[name*=\"resume\"], input[name*=\"cv\"]');\n  if (resumeInput && !(resumeInput as HTMLInputElement).files?.length) {\n    const settingsR = await send({ type: 'GET_SETTINGS' });\n    if (settingsR?.ok && settingsR.data?.autoApply?.requireResumeForSubmit) {\n      updateControlBar(filledCount, totalCount, 'Resume required - manual upload needed');\n      reportCompletion('needs_input');\n      return;\n    }\n  }\n\n  // Use multi-page handler for the full flow\n  const fillPageFn = async () => {\n    const result = await fillPage(adapter, responses, atsType, jobContext);\n    const fb = await fallbackFill(document, profile);\n    return result.filled + fb;\n  };\n\n  const result = await multiPageLoop(document, fillPageFn, profile);\n\n  if (result.success) {\n    updateControlBar(result.totalFieldsFilled, result.totalFieldsFilled, 'Application submitted successfully!');\n    reportCompletion('applied');\n  } else if (result.finalAction === 'submitted') {\n    // Submitted but couldn't confirm success\n    updateControlBar(result.totalFieldsFilled, result.totalFieldsFilled, 'Application submitted!');\n    reportCompletion('applied');\n  } else if (result.finalAction === 'next_page') {\n    updateControlBar(result.totalFieldsFilled, result.totalFieldsFilled, `Processed ${result.pagesProcessed} pages`);\n    reportCompletion('prefilled');\n  } else {\n    // Check for success one more time\n    if (checkSuccess(document)) {\n      updateControlBar(result.totalFieldsFilled, result.totalFieldsFilled, 'Application submitted!');\n      reportCompletion('applied');\n    } else {\n      updateControlBar(result.totalFieldsFilled, result.totalFieldsFilled, 'Form filled - manual review needed');\n      reportCompletion('needs_input');\n    }\n  }\n\n  // Learn from the final page state\n  await learnFromPage(document);\n}\n\nfunction stopAutofill() {\n  isRunning = false;\n  if (observer) { observer.disconnect(); observer = null; }\n  removeControlBar();\n}\n\nasync function fillPage(\n  adapter: ReturnType<typeof getAdapter>,\n  responses: SavedResponse[],\n  atsType: ATSType,\n  jobContext: TailoringContext,\n): Promise<{ filled: number; total: number }> {\n  const fields = adapter.getFields(document);\n  const domain = location.hostname;\n  const matches = matchFields(fields, responses, { domain, atsType });\n\n  // Load tailoring settings\n  let tailoringSettings: any = null;\n  try {\n    const settingsR = await send({ type: 'GET_SETTINGS' });\n    if (settingsR?.ok) tailoringSettings = settingsR.data?.tailoring;\n  } catch {}\n\n  let filled = 0;\n  for (const match of matches) {\n    if (!isRunning) break;\n    if (isAlreadyFilled(match.field)) continue;\n\n    // Human-like pacing: small random delay between fields\n    await randomDelay(50, 200);\n\n    // \u2500\u2500\u2500 AI Tailoring: tailor the response to fit the job context \u2500\u2500\u2500\n    let responseText = match.response.response;\n    if (tailoringSettings?.enabled && jobContext.jobTitle) {\n      const fieldLabel = match.signals.find((s) => s.source === 'label-for' || s.source === 'label-wrap' || s.source === 'aria-label')?.value || '';\n      const tailored = tailorResponse(responseText, fieldLabel, jobContext, tailoringSettings);\n      responseText = tailored.tailoredResponse;\n    }\n\n    const ok = await adapter.fillField(match.field, responseText);\n    if (ok) {\n      filled++;\n      match.field.classList.add('ua-filled');\n      match.field.classList.add('ua-filled-flash');\n\n      // Record usage\n      send({ type: 'RECORD_USAGE', payload: { id: match.response.id } });\n\n      // Remove flash after animation\n      setTimeout(() => match.field.classList.remove('ua-filled-flash'), 600);\n    }\n  }\n\n  updateControlBar(filled, matches.length);\n  return { filled, total: matches.length };\n}\n\nfunction reportCompletion(status: string) {\n  send({\n    type: 'PAGE_AUTOFILL_COMPLETE',\n    payload: { status, jobId: autoApplyJobId, url: location.href },\n  });\n}\n\nfunction randomDelay(min: number, max: number): Promise<void> {\n  const ms = min + Math.random() * (max - min);\n  return new Promise((r) => setTimeout(r, ms));\n}\n\nfunction isAlreadyFilled(el: HTMLElement): boolean {\n  if (el.classList.contains('ua-filled')) return true;\n  if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) {\n    return el.value.trim().length > 0;\n  }\n  if (el instanceof HTMLSelectElement) {\n    return el.selectedIndex > 0;\n  }\n  return false;\n}\n\n// \u2500\u2500\u2500 Control Bar (floating UI) \u2500\u2500\u2500\n\nfunction showControlBar() {\n  removeControlBar();\n  const bar = document.createElement('div');\n  bar.id = 'ua-control-bar';\n  bar.className = 'ua-control-bar';\n  bar.innerHTML = `\n    <span class=\"ua-status\">Ultimate Autofill</span>\n    <span id=\"ua-fill-status\" style=\"font-size:12px;color:#868e96;\">Scanning...</span>\n    <button class=\"ua-btn-stop\" id=\"ua-btn-stop\">Stop</button>\n  `;\n  document.body.appendChild(bar);\n\n  bar.querySelector('#ua-btn-stop')?.addEventListener('click', () => {\n    stopAutofill();\n  });\n}\n\nfunction updateControlBar(filled: number, total: number, message?: string) {\n  const el = document.getElementById('ua-fill-status');\n  if (el) el.textContent = message || `${filled}/${total} fields filled`;\n}\n\nfunction removeControlBar() {\n  document.getElementById('ua-control-bar')?.remove();\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n//  ONE-CLICK \"ADD TO QUEUE\" BUTTON\n//  Injected as a floating button on any job page\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction maybeInjectQueueButton() {\n  if (queueButtonInjected) return;\n\n  // Check if this page looks like a job listing/posting (not necessarily an application form)\n  const url = location.href.toLowerCase();\n  const title = document.title.toLowerCase();\n  const h1 = document.querySelector('h1')?.textContent?.toLowerCase() || '';\n  const combined = url + ' ' + title + ' ' + h1;\n\n  const isJobPage = /job|career|position|opening|apply|hiring|vacancy|recruit|opportunity/i.test(combined);\n  const isAppPage = isApplicationPage(document);\n\n  if (!isJobPage && !isAppPage) return;\n\n  queueButtonInjected = true;\n  injectQueueButton();\n}\n\nfunction injectQueueButton() {\n  // Remove if already exists\n  document.getElementById('ua-queue-btn-wrapper')?.remove();\n\n  const wrapper = document.createElement('div');\n  wrapper.id = 'ua-queue-btn-wrapper';\n  wrapper.style.cssText = `\n    position: fixed;\n    bottom: 24px;\n    right: 24px;\n    z-index: 2147483647;\n    display: flex;\n    flex-direction: column;\n    gap: 8px;\n    align-items: flex-end;\n    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;\n  `;\n\n  // Main \"Add to Queue\" button\n  const btn = document.createElement('button');\n  btn.id = 'ua-add-queue-btn';\n  btn.innerHTML = `<span style=\"font-size:16px;margin-right:6px;\">+</span> Add to Queue`;\n  btn.style.cssText = `\n    display: flex;\n    align-items: center;\n    gap: 4px;\n    padding: 12px 20px;\n    background: linear-gradient(135deg, #667eea, #764ba2);\n    color: #fff;\n    border: none;\n    border-radius: 50px;\n    font-size: 14px;\n    font-weight: 600;\n    cursor: pointer;\n    box-shadow: 0 4px 15px rgba(102, 126, 234, 0.4);\n    transition: all 0.2s ease;\n    font-family: inherit;\n  `;\n  btn.addEventListener('mouseenter', () => {\n    btn.style.transform = 'scale(1.05)';\n    btn.style.boxShadow = '0 6px 20px rgba(102, 126, 234, 0.6)';\n  });\n  btn.addEventListener('mouseleave', () => {\n    btn.style.transform = 'scale(1)';\n    btn.style.boxShadow = '0 4px 15px rgba(102, 126, 234, 0.4)';\n  });\n\n  btn.addEventListener('click', async () => {\n    btn.disabled = true;\n    btn.innerHTML = '<span style=\"font-size:14px;\">&#8987;</span> Adding...';\n\n    try {\n      // Extract job info from the page\n      const jobContext = extractJobContext(document);\n\n      const r = await send({\n        type: 'ADD_CURRENT_PAGE_TO_QUEUE',\n        payload: {\n          url: location.href,\n          company: jobContext.companyName || undefined,\n          role: jobContext.jobTitle || undefined,\n          source: 'one_click',\n        },\n      });\n\n      if (r?.ok) {\n        btn.innerHTML = '<span style=\"font-size:16px;\">&#10003;</span> Added!';\n        btn.style.background = 'linear-gradient(135deg, #28a745, #20c997)';\n\n        // Show toast\n        showQueueToast(`Added to queue: ${jobContext.jobTitle || location.href.substring(0, 50)}...`);\n\n        // Reset after 3 seconds\n        setTimeout(() => {\n          btn.innerHTML = `<span style=\"font-size:16px;margin-right:6px;\">+</span> Add to Queue`;\n          btn.style.background = 'linear-gradient(135deg, #667eea, #764ba2)';\n          btn.disabled = false;\n        }, 3000);\n      } else {\n        btn.innerHTML = `<span style=\"font-size:16px;\">&#10007;</span> ${r?.error || 'Already in queue'}`;\n        btn.style.background = '#dc3545';\n        setTimeout(() => {\n          btn.innerHTML = `<span style=\"font-size:16px;margin-right:6px;\">+</span> Add to Queue`;\n          btn.style.background = 'linear-gradient(135deg, #667eea, #764ba2)';\n          btn.disabled = false;\n        }, 2000);\n      }\n    } catch (e) {\n      btn.innerHTML = `<span style=\"font-size:16px;\">&#10007;</span> Error`;\n      setTimeout(() => {\n        btn.innerHTML = `<span style=\"font-size:16px;margin-right:6px;\">+</span> Add to Queue`;\n        btn.style.background = 'linear-gradient(135deg, #667eea, #764ba2)';\n        btn.disabled = false;\n      }, 2000);\n    }\n  });\n\n  wrapper.appendChild(btn);\n  document.body.appendChild(wrapper);\n}\n\nfunction showQueueToast(message: string) {\n  const existing = document.getElementById('ua-queue-toast');\n  if (existing) existing.remove();\n\n  const toast = document.createElement('div');\n  toast.id = 'ua-queue-toast';\n  toast.textContent = message;\n  toast.style.cssText = `\n    position: fixed;\n    bottom: 80px;\n    right: 24px;\n    z-index: 2147483647;\n    padding: 12px 20px;\n    background: #343a40;\n    color: #fff;\n    border-radius: 8px;\n    font-size: 13px;\n    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;\n    box-shadow: 0 4px 15px rgba(0,0,0,0.2);\n    opacity: 0;\n    transform: translateY(10px);\n    transition: all 0.3s ease;\n  `;\n  document.body.appendChild(toast);\n\n  // Animate in\n  requestAnimationFrame(() => {\n    toast.style.opacity = '1';\n    toast.style.transform = 'translateY(0)';\n  });\n\n  // Remove after 3 seconds\n  setTimeout(() => {\n    toast.style.opacity = '0';\n    toast.style.transform = 'translateY(10px)';\n    setTimeout(() => toast.remove(), 300);\n  }, 3000);\n}\n\n// \u2500\u2500\u2500 Overlay for textarea / question suggestions \u2500\u2500\u2500\n// Attach focus listener to show suggestions on textareas and long text inputs\n\ndocument.addEventListener('focusin', async (e) => {\n  const el = e.target as HTMLElement;\n  if (!isTextareaLike(el)) return;\n\n  const label = getFieldLabel(el);\n  if (!label) return;\n\n  const r = await send({ type: 'GET_SUGGESTIONS', payload: { query: label, domain: location.hostname } });\n  if (r?.ok && r.data?.length) {\n    showSuggestionOverlay(el, r.data, label);\n  }\n}, true);\n\ndocument.addEventListener('focusout', (e) => {\n  setTimeout(() => {\n    const overlay = document.getElementById('ua-suggestion-overlay');\n    if (overlay && !overlay.matches(':hover')) overlay.remove();\n  }, 200);\n}, true);\n\nfunction isTextareaLike(el: HTMLElement): boolean {\n  if (el instanceof HTMLTextAreaElement) return true;\n  if (el.contentEditable === 'true') return true;\n  if (el instanceof HTMLInputElement && el.type === 'text') {\n    const label = getFieldLabel(el);\n    if (label && label.length > 30) return true;\n  }\n  return false;\n}\n\nfunction getFieldLabel(el: HTMLElement): string | null {\n  if (el.id) {\n    const lbl = document.querySelector(`label[for=\"${CSS.escape(el.id)}\"]`);\n    if (lbl?.textContent?.trim()) return lbl.textContent.trim();\n  }\n  const wrap = el.closest('label');\n  if (wrap?.textContent?.trim()) return wrap.textContent.trim();\n  const al = el.getAttribute('aria-label');\n  if (al?.trim()) return al.trim();\n  const ph = (el as HTMLInputElement).placeholder;\n  if (ph?.trim()) return ph.trim();\n  return null;\n}\n\nfunction showSuggestionOverlay(target: HTMLElement, suggestions: any[], label: string) {\n  document.getElementById('ua-suggestion-overlay')?.remove();\n\n  const overlay = document.createElement('div');\n  overlay.id = 'ua-suggestion-overlay';\n  overlay.className = 'ua-overlay';\n\n  const rect = target.getBoundingClientRect();\n  overlay.style.top = `${rect.bottom + window.scrollY + 4}px`;\n  overlay.style.left = `${rect.left + window.scrollX}px`;\n\n  let html = `<div class=\"ua-overlay-header\">\n    <span>Suggestions for: ${escapeHtml(label.slice(0, 40))}</span>\n    <button class=\"ua-overlay-close\" id=\"ua-close-overlay\">&times;</button>\n  </div><div class=\"ua-suggestion-list\">`;\n\n  for (const s of suggestions) {\n    const resp = s.response;\n    const preview = resp.response.length > 120 ? resp.response.slice(0, 120) + '...' : resp.response;\n    html += `<div class=\"ua-suggestion-item\" data-response-id=\"${escapeHtml(resp.id)}\">\n      <div class=\"ua-suggestion-question\">${escapeHtml(resp.question)}</div>\n      <div class=\"ua-suggestion-response\">${escapeHtml(preview)}</div>\n      <div class=\"ua-suggestion-meta\">Score: ${(s.score * 100).toFixed(0)}% | Used ${resp.appearances}x</div>\n      <button class=\"ua-suggestion-insert\" data-value=\"${escapeAttr(resp.response)}\" data-id=\"${escapeHtml(resp.id)}\">Insert</button>\n    </div>`;\n  }\n\n  html += '</div>';\n  overlay.innerHTML = html;\n  document.body.appendChild(overlay);\n\n  overlay.querySelector('#ua-close-overlay')?.addEventListener('click', () => overlay.remove());\n\n  overlay.querySelectorAll('.ua-suggestion-insert').forEach((btn) => {\n    btn.addEventListener('click', (e) => {\n      e.preventDefault();\n      e.stopPropagation();\n      const value = (btn as HTMLElement).dataset.value || '';\n      const id = (btn as HTMLElement).dataset.id || '';\n      insertValue(target, value);\n      send({ type: 'RECORD_USAGE', payload: { id } });\n      overlay.remove();\n    });\n  });\n}\n\nfunction insertValue(el: HTMLElement, value: string) {\n  if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) {\n    const setter = Object.getOwnPropertyDescriptor(\n      el instanceof HTMLTextAreaElement ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype, 'value'\n    )?.set;\n    if (setter) setter.call(el, value); else el.value = value;\n    el.dispatchEvent(new Event('input', { bubbles: true }));\n    el.dispatchEvent(new Event('change', { bubbles: true }));\n  } else if (el.contentEditable === 'true') {\n    el.textContent = value;\n    el.dispatchEvent(new Event('input', { bubbles: true }));\n  }\n  el.classList.add('ua-filled');\n}\n\nfunction escapeHtml(s: string): string {\n  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;');\n}\n\nfunction escapeAttr(s: string): string {\n  return s.replace(/&/g, '&amp;').replace(/\"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');\n}\n\n// \u2500\u2500\u2500 Auto-inject queue button on page load for job pages \u2500\u2500\u2500\n// Run after a short delay to let the page render\nsetTimeout(() => {\n  maybeInjectQueueButton();\n}, 1500);\n"],
