  "sources": ["../src/atsDetector/index.ts", "../src/utils/fuzzy.ts", "../src/savedResponses/matcher.ts", "../src/fieldMatcher/index.ts", "../src/adapters/workday/index.ts", "../src/adapters/greenhouse/index.ts", "../src/adapters/generic/index.ts", "../src/adapters/lever/index.ts", "../src/adapters/icims/index.ts", "../src/adapters/smartrecruiters/index.ts", "../src/adapters/taleo/index.ts", "../src/adapters/index.ts", "../src/fieldMatcher/smartGuesser.ts", "../src/content/formNavigator.ts", "../src/content/resumeUpload.ts", "../src/content/captchaSolver.ts", "../src/content/atsNavigator.ts", "../src/content/tailoringOrchestrator.ts", "../src/content/main.ts"],
  "sourcesContent": ["import type { ATSDetectionResult, ATSType } from '../types/index';\r\n\r\ninterface Sig {\r\n  type: ATSType;\r\n  urls: RegExp[];\r\n  dom: string[];\r\n  meta: { name: string; pat: RegExp }[];\r\n}\r\n\r\nconst SIGS: Sig[] = [\r\n  {\r\n    type: 'workday',\r\n    urls: [/myworkdayjobs\\.com/i, /myworkday\\.com/i],\r\n    dom: ['[data-automation-id]', '[data-uxi-element-id]'],\r\n    meta: [{ name: 'generator', pat: /workday/i }],\r\n  },\r\n  {\r\n    type: 'greenhouse',\r\n    urls: [/greenhouse\\.io/i, /boards\\.greenhouse\\.io/i],\r\n    dom: ['#greenhouse_application', '#grnhse_app', 'form#application_form'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'lever',\r\n    urls: [/lever\\.co/i, /jobs\\.lever\\.co/i],\r\n    dom: ['.lever-application-form', '[data-qa=\"application-form\"]', '.posting-headline'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'smartrecruiters',\r\n    urls: [/smartrecruiters\\.com/i],\r\n    dom: ['[class*=\"smartrecruiters\"]', '.st-apply-form'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'icims',\r\n    urls: [/icims\\.com/i],\r\n    dom: ['#icims_content', '[class*=\"icims\"]'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'taleo',\r\n    urls: [/taleo\\.net/i, /oraclecloud\\.com/i, /fa\\.oraclecloud\\.com/i],\r\n    dom: ['[class*=\"taleo\"]', '#requisitionDescriptionInterface', '#OracleFusionApp', 'oracle-apply-flow'],\r\n    meta: [{ name: 'generator', pat: /taleo/i }],\r\n  },\r\n  {\r\n    type: 'ashby',\r\n    urls: [/ashbyhq\\.com/i],\r\n    dom: ['[data-ashby-job-posting-id]', '.ashby-job-posting-brief-location'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'bamboohr',\r\n    urls: [/bamboohr\\.com/i],\r\n    dom: ['.BambooHR-ATS-board', '[class*=\"BambooHR\"]'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'indeed',\r\n    urls: [/indeed\\.com/i],\r\n    dom: ['#jobsearch-ViewJobButtons-container', '.jobsearch-IndeedApplyButton'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'linkedin',\r\n    urls: [/linkedin\\.com\\/jobs/i],\r\n    dom: ['.jobs-apply-button', '[data-control-name*=\"apply\"]'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'hiringcafe',\r\n    urls: [/hiring\\.cafe/i],\r\n    dom: [],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'jobvite',\r\n    urls: [/jobvite\\.com/i],\r\n    dom: ['[class*=\"jobvite\"]', '.jv-page-body'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'workable',\r\n    urls: [/apply\\.workable\\.com/i],\r\n    dom: ['[data-ui=\"application\"]'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'paylocity',\r\n    urls: [/paylocity\\.com/i],\r\n    dom: [],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'jazzhr',\r\n    urls: [/jazzhr\\.com/i],\r\n    dom: ['#jazz-apply-form'],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'ziprecruiter',\r\n    urls: [/ziprecruiter\\.com/i],\r\n    dom: [],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'dice',\r\n    urls: [/dice\\.com/i],\r\n    dom: [],\r\n    meta: [],\r\n  },\r\n  {\r\n    type: 'ukg',\r\n    urls: [/recruiting\\.ultipro\\.com/i],\r\n    dom: [],\r\n    meta: [],\r\n  },\r\n];\r\n\r\nexport function detectATS(doc: Document): ATSDetectionResult {\r\n  const url = doc.location?.href || '';\r\n  let best: ATSType = 'generic';\r\n  let bestConf = 0;\r\n  const bestSigs: string[] = [];\r\n\r\n  for (const s of SIGS) {\r\n    let conf = 0;\r\n    const found: string[] = [];\r\n\r\n    for (const p of s.urls) {\r\n      if (p.test(url)) { conf += 0.5; found.push(`url:${p.source}`); break; }\r\n    }\r\n    for (const sel of s.dom) {\r\n      try { if (doc.querySelector(sel)) { conf += 0.2; found.push(`dom:${sel}`); if (conf >= 0.9) break; } } catch { }\r\n    }\r\n    for (const m of s.meta) {\r\n      const el = doc.querySelector(`meta[name=\"${m.name}\"]`);\r\n      if (el && m.pat.test(el.getAttribute('content') || '')) { conf += 0.3; found.push(`meta:${m.name}`); }\r\n    }\r\n\r\n    conf = Math.min(conf, 1);\r\n    if (conf > bestConf) { bestConf = conf; best = s.type; bestSigs.length = 0; bestSigs.push(...found); }\r\n  }\r\n\r\n  return { type: best, confidence: bestConf, signals: bestSigs };\r\n}\r\n\r\nexport function atsName(type: ATSType): string {\r\n  const m: Record<ATSType, string> = {\r\n    workday: 'Workday', greenhouse: 'Greenhouse', lever: 'Lever',\r\n    smartrecruiters: 'SmartRecruiters', icims: 'iCIMS', taleo: 'Taleo/OracleCloud',\r\n    ashby: 'Ashby', bamboohr: 'BambooHR', generic: 'Generic',\r\n    indeed: 'Indeed', linkedin: 'LinkedIn', hiringcafe: 'HiringCafe',\r\n    jobvite: 'Jobvite', workable: 'Workable', paylocity: 'Paylocity',\r\n    jazzhr: 'JazzHR', ziprecruiter: 'ZipRecruiter', dice: 'Dice', ukg: 'UKG',\r\n  };\r\n  return m[type];\r\n}\r\n", "/** Normalize: lowercase, strip punctuation, collapse whitespace */\r\nexport function normalize(text: string): string {\r\n  return text.toLowerCase().replace(/[^\\w\\s]/g, ' ').replace(/\\s+/g, ' ').trim();\r\n}\r\n\r\n/** Tokenize normalized text */\r\nexport function tokenize(text: string): string[] {\r\n  return normalize(text).split(' ').filter(Boolean);\r\n}\r\n\r\n/** Levenshtein distance */\r\nexport function levenshtein(a: string, b: string): number {\r\n  const m = a.length, n = b.length;\r\n  if (m === 0) return n;\r\n  if (n === 0) return m;\r\n  let prev = Array.from({ length: n + 1 }, (_, i) => i);\r\n  let curr = new Array<number>(n + 1);\r\n  for (let i = 1; i <= m; i++) {\r\n    curr[0] = i;\r\n    for (let j = 1; j <= n; j++) {\r\n      curr[j] = Math.min(\r\n        prev[j] + 1,\r\n        curr[j - 1] + 1,\r\n        prev[j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1)\r\n      );\r\n    }\r\n    [prev, curr] = [curr, prev];\r\n  }\r\n  return prev[n];\r\n}\r\n\r\n/** Normalized similarity 0\u20131 */\r\nexport function stringSimilarity(a: string, b: string): number {\r\n  const na = normalize(a), nb = normalize(b);\r\n  if (na === nb) return 1;\r\n  const max = Math.max(na.length, nb.length);\r\n  return max === 0 ? 1 : 1 - levenshtein(na, nb) / max;\r\n}\r\n\r\n/** Token overlap (Jaccard) */\r\nexport function tokenOverlap(a: string[], b: string[]): number {\r\n  if (!a.length && !b.length) return 1;\r\n  if (!a.length || !b.length) return 0;\r\n  const sa = new Set(a), sb = new Set(b);\r\n  let inter = 0;\r\n  for (const t of sa) if (sb.has(t)) inter++;\r\n  return inter / new Set([...sa, ...sb]).size;\r\n}\r\n\r\n/** Fuzzy per-token match */\r\nexport function fuzzyTokenMatch(a: string[], b: string[]): number {\r\n  if (!a.length) return b.length === 0 ? 1 : 0;\r\n  let total = 0;\r\n  for (const ta of a) {\r\n    let best = 0;\r\n    for (const tb of b) best = Math.max(best, stringSimilarity(ta, tb));\r\n    total += best;\r\n  }\r\n  return total / a.length;\r\n}\r\n\r\n/** Combined hybrid similarity */\r\nexport function hybridSimilarity(query: string, target: string, keywords: string[]): number {\r\n  const qt = tokenize(query), tt = tokenize(target);\r\n  const direct = stringSimilarity(query, target) * 0.3;\r\n  const overlap = tokenOverlap(qt, tt) * 0.25;\r\n  const fuzzy = fuzzyTokenMatch(qt, tt) * 0.25;\r\n  let kw = 0;\r\n  if (keywords.length) {\r\n    const nq = normalize(query);\r\n    let hit = 0;\r\n    for (const k of keywords) if (nq.includes(normalize(k))) hit++;\r\n    kw = (hit / keywords.length) * 0.2;\r\n  }\r\n  return direct + overlap + fuzzy + kw;\r\n}\r\n\r\n/** Find near-duplicate pairs above threshold */\r\nexport function findDuplicates(\r\n  items: { id: string; question: string }[],\r\n  threshold = 0.75\r\n): { idA: string; idB: string; similarity: number }[] {\r\n  const out: { idA: string; idB: string; similarity: number }[] = [];\r\n  for (let i = 0; i < items.length; i++) {\r\n    for (let j = i + 1; j < items.length; j++) {\r\n      const sim = stringSimilarity(items[i].question, items[j].question);\r\n      if (sim >= threshold) out.push({ idA: items[i].id, idB: items[j].id, similarity: sim });\r\n    }\r\n  }\r\n  return out.sort((a, b) => b.similarity - a.similarity);\r\n}\r\n", "import type { SavedResponse, SuggestionItem, ATSType } from '../types/index';\r\nimport { hybridSimilarity, normalize, tokenize, tokenOverlap } from '../utils/fuzzy';\r\n\r\nexport interface MatchOptions {\r\n  domain?: string;\r\n  atsType?: ATSType;\r\n  maxResults?: number;\r\n}\r\n\r\n/** Score one response against a query string. Returns 0\u20131 and explanation. */\r\nexport function scoreResponse(\r\n  query: string,\r\n  resp: SavedResponse,\r\n  opts: MatchOptions = {}\r\n): { score: number; explanation: string } {\r\n  const parts: string[] = [];\r\n  let score = 0;\r\n\r\n  // 1. Hybrid text similarity vs question (0.45)\r\n  const qSim = hybridSimilarity(query, resp.question, resp.keywords);\r\n  score += qSim * 0.45;\r\n  parts.push(`q_sim=${qSim.toFixed(3)}`);\r\n\r\n  // 2. Key overlap (0.20)\r\n  const keyTokens = resp.key.split('|').filter(Boolean);\r\n  const qTokens = tokenize(query);\r\n  const keyOv = tokenOverlap(qTokens, keyTokens);\r\n  score += keyOv * 0.20;\r\n  parts.push(`key=${keyOv.toFixed(3)}`);\r\n\r\n  // 3. Popularity (0.10)\r\n  const pop = Math.min(Math.log2(1 + resp.appearances) / 10, 1);\r\n  score += pop * 0.10;\r\n  parts.push(`pop=${pop.toFixed(3)}`);\r\n\r\n  // 4. Recency (0.10)\r\n  let rec = 0;\r\n  if (resp.lastUsedAt) {\r\n    const days = (Date.now() - new Date(resp.lastUsedAt).getTime()) / 86_400_000;\r\n    rec = Math.max(0, 1 - days / 90);\r\n  }\r\n  score += rec * 0.10;\r\n  parts.push(`rec=${rec.toFixed(3)}`);\r\n\r\n  // 5. Domain / ATS hint (0.10)\r\n  let ctx = 0;\r\n  if (opts.domain && resp.domains?.includes(opts.domain)) { ctx += 0.5; parts.push('dom+'); }\r\n  if (opts.atsType && resp.atsTypes?.includes(opts.atsType)) { ctx += 0.5; parts.push('ats+'); }\r\n  score += Math.min(ctx, 1) * 0.10;\r\n\r\n  // 6. Keyword bonus (0.05)\r\n  let kwb = 0;\r\n  if (resp.keywords.length) {\r\n    const nq = normalize(query);\r\n    let hit = 0;\r\n    for (const k of resp.keywords) if (nq.includes(k.toLowerCase())) hit++;\r\n    kwb = hit / resp.keywords.length;\r\n  }\r\n  score += kwb * 0.05;\r\n  parts.push(`kw=${kwb.toFixed(3)}`);\r\n\r\n  return { score: Math.min(score, 1), explanation: parts.join(', ') };\r\n}\r\n\r\n/** Top N matches above threshold */\r\nexport function findMatches(query: string, responses: SavedResponse[], opts: MatchOptions = {}): SuggestionItem[] {\r\n  const max = opts.maxResults || 3;\r\n  if (!query.trim() || !responses.length) return [];\r\n  return responses\r\n    .map((r) => { const { score, explanation } = scoreResponse(query, r, opts); return { response: r, score, explanation }; })\r\n    .filter((s) => s.score > 0.15)\r\n    .sort((a, b) => b.score - a.score)\r\n    .slice(0, max);\r\n}\r\n\r\n/** Best single match for autofill (null if below confidence) */\r\nexport function findBestMatch(query: string, responses: SavedResponse[], opts: MatchOptions = {}): SuggestionItem | null {\r\n  const m = findMatches(query, responses, { ...opts, maxResults: 1 });\r\n  return m.length && m[0].score >= 0.3 ? m[0] : null;\r\n}\r\n", "import type { FieldInfo, FieldSignal, FieldMatchResult, SavedResponse } from '../types/index';\r\nimport { findBestMatch, type MatchOptions } from '../savedResponses/matcher';\r\n\r\n// \u2500\u2500\u2500 Signal Extraction \u2500\u2500\u2500\r\n\r\nexport function extractFieldSignals(element: HTMLElement): FieldSignal[] {\r\n  const signals: FieldSignal[] = [];\r\n\r\n  // 1. Explicit <label for>\r\n  if (element.id) {\r\n    const lbl = document.querySelector(`label[for=\"${CSS.escape(element.id)}\"]`);\r\n    if (lbl?.textContent?.trim()) signals.push({ source: 'label-for', value: lbl.textContent.trim(), weight: 1.0 });\r\n  }\r\n\r\n  // 2. Wrapping label\r\n  const wrap = element.closest('label');\r\n  if (wrap) {\r\n    const t = directText(wrap).trim();\r\n    if (t) signals.push({ source: 'label-wrap', value: t, weight: 0.95 });\r\n  }\r\n\r\n  // 3. aria-label\r\n  const al = element.getAttribute('aria-label');\r\n  if (al?.trim()) signals.push({ source: 'aria-label', value: al.trim(), weight: 0.9 });\r\n\r\n  // 4. aria-labelledby\r\n  const alb = element.getAttribute('aria-labelledby');\r\n  if (alb) {\r\n    const txt = alb.split(/\\s+/).map((id) => document.getElementById(id)?.textContent?.trim()).filter(Boolean).join(' ');\r\n    if (txt) signals.push({ source: 'aria-labelledby', value: txt, weight: 0.9 });\r\n  }\r\n\r\n  // 5. placeholder\r\n  if (element instanceof HTMLInputElement || element instanceof HTMLTextAreaElement) {\r\n    const ph = element.placeholder;\r\n    if (ph?.trim()) signals.push({ source: 'placeholder', value: ph.trim(), weight: 0.7 });\r\n  }\r\n\r\n  // 6. name\r\n  const name = element.getAttribute('name');\r\n  if (name?.trim()) signals.push({ source: 'name', value: humanize(name), weight: 0.6 });\r\n\r\n  // 7. id\r\n  if (element.id) signals.push({ source: 'id', value: humanize(element.id), weight: 0.5 });\r\n\r\n  // 8. autocomplete\r\n  const ac = element.getAttribute('autocomplete');\r\n  if (ac?.trim() && ac !== 'off') signals.push({ source: 'autocomplete', value: ac.trim(), weight: 0.85 });\r\n\r\n  // 9. role\r\n  const role = element.getAttribute('role');\r\n  if (role?.trim()) signals.push({ source: 'role', value: role.trim(), weight: 0.3 });\r\n\r\n  // 10. Group context (fieldset/legend, heading)\r\n  const gc = groupContext(element);\r\n  if (gc) signals.push({ source: 'group-context', value: gc, weight: 0.4 });\r\n\r\n  // 11. Nearby text\r\n  const nt = nearbyText(element);\r\n  if (nt) signals.push({ source: 'nearby-text', value: nt, weight: 0.35 });\r\n\r\n  return signals;\r\n}\r\n\r\nfunction directText(el: Element): string {\r\n  let t = '';\r\n  for (const n of el.childNodes) if (n.nodeType === Node.TEXT_NODE) t += n.textContent || '';\r\n  return t;\r\n}\r\n\r\nfunction humanize(name: string): string {\r\n  return name.replace(/[\\[\\]]/g, ' ').replace(/([a-z])([A-Z])/g, '$1 $2').replace(/[_\\-\\.]+/g, ' ').replace(/\\s+/g, ' ').trim();\r\n}\r\n\r\nfunction groupContext(el: HTMLElement): string | null {\r\n  const fs = el.closest('fieldset');\r\n  if (fs) { const lg = fs.querySelector('legend'); if (lg?.textContent?.trim()) return lg.textContent.trim(); }\r\n  let n: Element | null = el;\r\n  while (n && n !== document.body) {\r\n    const prev = n.previousElementSibling;\r\n    if (prev && /^h[1-6]$/i.test(prev.tagName)) return prev.textContent?.trim() || null;\r\n    n = n.parentElement;\r\n  }\r\n  return null;\r\n}\r\n\r\nfunction nearbyText(el: HTMLElement): string | null {\r\n  const prev = el.previousElementSibling;\r\n  if (prev && prev.textContent?.trim() && !isFormEl(prev)) {\r\n    const t = prev.textContent.trim();\r\n    if (t.length < 100) return t;\r\n  }\r\n  const par = el.parentElement;\r\n  if (par) { const t = directText(par).trim(); if (t && t.length < 100) return t; }\r\n  return null;\r\n}\r\n\r\nfunction isFormEl(el: Element): boolean {\r\n  return ['input', 'textarea', 'select', 'button'].includes(el.tagName.toLowerCase());\r\n}\r\n\r\n// \u2500\u2500\u2500 Discovery \u2500\u2500\u2500\r\n\r\nconst FIELD_SELECTOR = [\r\n  'input:not([type=\"hidden\"]):not([type=\"submit\"]):not([type=\"button\"]):not([type=\"reset\"]):not([type=\"image\"]):not([disabled])',\r\n  'textarea:not([disabled])',\r\n  'select:not([disabled])',\r\n  '[role=\"combobox\"]:not([disabled])',\r\n  '[role=\"listbox\"]:not([disabled])',\r\n  '[role=\"textbox\"]:not([disabled])',\r\n  '[contenteditable=\"true\"]',\r\n].join(', ');\r\n\r\nexport function discoverFields(doc: Document): FieldInfo[] {\r\n  const fields: FieldInfo[] = [];\r\n  for (const el of doc.querySelectorAll<HTMLElement>(FIELD_SELECTOR)) {\r\n    if (el.offsetParent === null && el.style.display !== 'contents') continue;\r\n    const type = fieldType(el);\r\n    const signals = extractFieldSignals(el);\r\n    fields.push({ element: el, type, signals, groupContext: signals.find((s) => s.source === 'group-context')?.value });\r\n  }\r\n  return fields;\r\n}\r\n\r\nfunction fieldType(el: HTMLElement): string {\r\n  const tag = el.tagName.toLowerCase();\r\n  if (tag === 'input') return (el as HTMLInputElement).type || 'text';\r\n  if (tag === 'textarea') return 'textarea';\r\n  if (tag === 'select') return 'select';\r\n  const r = el.getAttribute('role');\r\n  if (r) return r;\r\n  if (el.contentEditable === 'true') return 'contenteditable';\r\n  return 'unknown';\r\n}\r\n\r\n// \u2500\u2500\u2500 Matching \u2500\u2500\u2500\r\n\r\nexport function buildFieldQuery(fi: FieldInfo): string {\r\n  const sorted = [...fi.signals].sort((a, b) => b.weight - a.weight);\r\n  if (!sorted.length) return '';\r\n  const primary = sorted[0].value;\r\n  const parts = [primary];\r\n  for (let i = 1; i < Math.min(sorted.length, 3); i++) {\r\n    if (sorted[i].value !== primary) parts.push(sorted[i].value);\r\n  }\r\n  return parts.join(' ');\r\n}\r\n\r\nexport function matchFields(fields: FieldInfo[], responses: SavedResponse[], opts: MatchOptions = {}): FieldMatchResult[] {\r\n  const results: FieldMatchResult[] = [];\r\n  for (const f of fields) {\r\n    const q = buildFieldQuery(f);\r\n    if (!q) continue;\r\n    const m = findBestMatch(q, responses, opts);\r\n    if (m) results.push({ field: f.element, response: m.response, score: m.score, signals: f.signals, explanation: `Query: \"${q}\" | ${m.explanation}` });\r\n  }\r\n  return results.sort((a, b) => b.score - a.score);\r\n}\r\n\r\nexport function explainMatch(fi: FieldInfo, responses: SavedResponse[], opts: MatchOptions = {}): string {\r\n  const lines = [`Type: ${fi.type}`, 'Signals:'];\r\n  for (const s of fi.signals) lines.push(`  [${s.source}] w=${s.weight}: \"${s.value}\"`);\r\n  const q = buildFieldQuery(fi);\r\n  lines.push(`Query: \"${q}\"`);\r\n  if (!q) { lines.push('No query \u2014 no match'); return lines.join('\\n'); }\r\n  const m = findBestMatch(q, responses, opts);\r\n  if (m) { lines.push(`Match: \"${m.response.question}\" sc