er: 'Prefer not to say',\r\n    ethnicity: 'Prefer not to say',\r\n    race: 'Prefer not to say',\r\n    years: '5',\r\n    salary: '80000',\r\n    notice: '2 weeks',\r\n    availability: 'Immediately',\r\n    cover: `I am excited to apply for this role. My background and skills make me an excellent candidate and I look forward to contributing to your team.`,\r\n    why: 'I admire the company culture and the opportunity to make a meaningful impact.',\r\n    howHeard: 'LinkedIn',\r\n};\r\n\r\n// \u2500\u2500\u2500 Profile Normalizer \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport interface NormalizedProfile {\r\n    first_name?: string;\r\n    last_name?: string;\r\n    middle_name?: string;\r\n    preferred_name?: string;\r\n    email?: string;\r\n    phone?: string;\r\n    linkedin_profile_url?: string;\r\n    website_url?: string;\r\n    github_url?: string;\r\n    twitter_url?: string;\r\n    city?: string;\r\n    state?: string;\r\n    country?: string;\r\n    postal_code?: string;\r\n    address?: string;\r\n    current_title?: string;\r\n    current_company?: string;\r\n    school?: string;\r\n    university?: string;\r\n    degree?: string;\r\n    major?: string;\r\n    gpa?: string;\r\n    graduation_year?: string;\r\n    expected_salary?: string;\r\n    cover_letter?: string;\r\n    summary?: string;\r\n    languages?: string;\r\n    certifications?: string;\r\n    nationality?: string;\r\n    years_of_experience?: string;\r\n    resume_url?: string;\r\n    [key: string]: string | undefined;\r\n}\r\n\r\nfunction pickFirst(...vals: unknown[]): string {\r\n    for (const v of vals) {\r\n        if (typeof v === 'string' && v.trim()) return v.trim();\r\n        if (typeof v === 'number') return String(v);\r\n    }\r\n    return '';\r\n}\r\n\r\nexport function normalizeProfile(raw: Record<string, any> = {}): NormalizedProfile {\r\n    const p: Record<string, any> = { ...(raw || {}) };\r\n    p.first_name = pickFirst(p.first_name, p.firstName, p.firstname, p.given_name, p.givenName);\r\n    p.last_name = pickFirst(p.last_name, p.lastName, p.lastname, p.family_name, p.familyName);\r\n    p.email = pickFirst(p.email, p.emailAddress, p.email_address, p.primaryEmail, p.workEmail);\r\n    p.phone = pickFirst(p.phone, p.phoneNumber, p.phone_number, p.mobile, p.mobileNumber, p.contactNumber, p.telephone);\r\n    p.linkedin_profile_url = pickFirst(p.linkedin_profile_url, p.linkedin, p.linkedIn, p.linkedinUrl, p.linkedin_url);\r\n    p.website_url = pickFirst(p.website_url, p.website, p.portfolio, p.portfolio_url, p.personalWebsite);\r\n    p.github_url = pickFirst(p.github_url, p.github, p.githubUrl);\r\n    p.city = pickFirst(p.city, p.currentCity, p.locationCity);\r\n    p.state = pickFirst(p.state, p.region, p.province);\r\n    p.country = pickFirst(p.country, p.countryName);\r\n    p.postal_code = pickFirst(p.postal_code, p.zip, p.zipCode, p.postcode);\r\n    p.address = pickFirst(p.address, p.streetAddress, p.addressLine1);\r\n    p.current_title = pickFirst(p.current_title, p.currentTitle, p.title);\r\n    p.current_company = pickFirst(p.current_company, p.currentCompany, p.company);\r\n    p.school = pickFirst(p.school, p.university);\r\n    p.degree = pickFirst(p.degree);\r\n    p.major = pickFirst(p.major);\r\n    p.graduation_year = pickFirst(p.graduation_year, p.grad_year);\r\n    p.expected_salary = pickFirst(p.expected_salary, p.desired_pay, p.desiredPay);\r\n    p.cover_letter = pickFirst(p.cover_letter, p.coverLetter);\r\n    p.summary = pickFirst(p.summary, p.bio, p.objective);\r\n    p.resume_url = pickFirst(p.resume_url, p.resumeUrl, p.resume);\r\n\r\n    // Also check nested profile/candidate/user/basics objects\r\n    const nested = p.profile || p.candidate || p.user || p.basics || {};\r\n    p.first_name = pickFirst(p.first_name, nested.first_name, nested.firstName, nested.firstname);\r\n    p.last_name = pickFirst(p.last_name, nested.last_name, nested.lastName, nested.lastname);\r\n    p.email = pickFirst(p.email, nested.email, nested.emailAddress, nested.email_address);\r\n    p.phone = pickFirst(p.phone, nested.phone, nested.phoneNumber, nested.mobile, nested.mobileNumber);\r\n    p.linkedin_profile_url = pickFirst(p.linkedin_profile_url, nested.linkedin_profile_url, nested.linkedin, nested.linkedIn, nested.linkedinUrl);\r\n    p.website_url = pickFirst(p.website_url, nested.website_url, nested.website, nested.portfolio, nested.portfolio_url);\r\n\r\n    return p as NormalizedProfile;\r\n}\r\n\r\n// \u2500\u2500\u2500 Smart Value Guesser \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\n/** Given a field label and user profile, guess the most appropriate value. */\r\nexport function guessValue(label: string, p: NormalizedProfile = {}): string {\r\n    const l = label.toLowerCase().replace(/[^a-z0-9 ]/g, ' ');\r\n    if (/first.?name|given.?name|prenom/.test(l)) return p.first_name || '';\r\n    if (/last.?name|family.?name|surname/.test(l)) return p.last_name || '';\r\n    if (/middle.?name/.test(l)) return p.middle_name || '';\r\n    if (/preferred.?name|nick.?name/.test(l)) return p.preferred_name || p.first_name || '';\r\n    if (/full.?name|your name|name/.test(l) && !/company|last|first|user/.test(l)) return `${p.first_name || ''} ${p.last_name || ''}`.trim();\r\n    if (/\\bemail\\b/.test(l)) return p.email || '';\r\n    if (/phone|mobile|cell|telephone/.test(l)) return p.phone || '';\r\n    if (/^city$|\\bcity\\b|current.?city/.test(l)) return p.city || '';\r\n    if (/state|province|region/.test(l)) return p.state || '';\r\n    if (/zip|postal/.test(l)) return p.postal_code || '';\r\n    if (/country/.test(l)) return p.country || 'United States';\r\n    if (/address|street/.test(l)) return p.address || '';\r\n    if (/location|where.*(you|do you).*live/.test(l)) return p.city ? `${p.city}, ${p.state || ''}`.trim().replace(/,$/, '') : '';\r\n    if (/linkedin/.test(l)) return p.linkedin_profile_url || '';\r\n    if (/github/.test(l)) return p.github_url || '';\r\n    if (/website|portfolio|personal.?url/.test(l)) return p.website_url || '';\r\n    if (/twitter|x\\.com/.test(l)) return p.twitter_url || '';\r\n    if (/university|school|college|alma.?mater/.test(l)) return p.school || '';\r\n    if (/\\bdegree\\b|qualification/.test(l)) return p.degree || \"Bachelor's\";\r\n    if (/major|field.?of.?study|concentration|specialization/.test(l)) return p.major || '';\r\n    if (/gpa|grade.?point/.test(l)) return p.gpa || '';\r\n    if (/graduation|grad.?date|grad.?year/.test(l)) return p.graduation_year || '';\r\n    if (/title|position|role|current.?title|job.?title/.test(l) && !/company/.test(l)) return p.current_title || '';\r\n    if (/company|employer|org|current.?company/.test(l)) return p.current_company || '';\r\n    if (/salary|compensation|pay|desired.?pay|expected.?comp/.test(l)) return p.expected_salary || DEFAULTS.salary;\r\n    if (/cover.?letter|motivation|additional.?info|message.?to/.test(l)) return p.cover_letter || DEFAULTS.cover;\r\n    if (/summary|about.?(yourself|you|me)|bio|objective|profile.?summary/.test(l)) return p.summary || p.cover_letter || DEFAULTS.cover;\r\n    if (/why.*(compan|role|want|interest|position)/.test(l)) return DEFAULTS.why;\r\n    if (/how.*hear|where.*(find|learn|discover)|source|referred.?by|referral/.test(l)) return DEFAULTS.howHeard;\r\n    if (/years.*(exp|work)|exp.*years|total.*experience/.test(l)) return p.years_of_experience || DEFAULTS.years;\r\n    if (/availab|start.?date|notice|when.*start|earliest.*start/.test(l)) return DEFAULTS.availability;\r\n    if (/authoriz|eligible|work.*right|legal.*right|permitted.*work/.test(l)) return DEFAULTS.authorized;\r\n    if (/sponsor|visa|immigration|work.?permit/.test(l)) return DEFAULTS.sponsorship;\r\n    if (/relocat|willing.*move|open.*reloc/.test(l)) return DEFAULTS.relocation;\r\n    if (/remote|work.*home|hybrid|on.?site|work.?model|work.?arrangement/.test(l)) return DEFAULTS.remote;\r\n    if (/veteran|military|armed.?forces|served/.test(l)) return DEFAULTS.veteran;\r\n    if (/disabilit/.test(l)) return DEFAULTS.disability;\r\n    if (/gender|sex\\b|pronouns/.test(l)) return DEFAULTS.gender;\r\n    if (/ethnic|race|racial|heritage/.test(l)) return DEFAULTS.ethnicity;\r\n    if (/nationality|citizenship/.test(l)) return p.nationality || p.country || 'United States';\r\n    if (/language|fluency|fluent/.test(l)) return p.languages || 'English';\r\n    if (/certif|license|credential/.test(l)) return p.certifications || '';\r\n    if (/commute|travel|willing.*travel/.test(l)) return 'Yes';\r\n    if (/convicted|criminal|felony|background.?check/.test(l)) return 'No';\r\n    if (/drug.?test|screening/.test(l)) return 'Yes';\r\n    if (/\\bage\\b|18.*years|over.*18|at.*least.*18/.test(l)) return 'Yes';\r\n    if (/agree|acknowledge|certif|attest|confirm|consent/.test(l)) return 'Yes';\r\n    return '';\r\n}\r\n\r\n// \u2500\u2500\u2500 Field Helpers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport function getFieldLabel(el: HTMLElement): string {\r\n    if (el.getAttribute('aria-label')) return el.getAttribute('aria-label')!;\r\n    if (el.id) {\r\n        const lbl = document.querySelector(`label[for=\"${CSS.escape(el.id)}\"]`);\r\n        if (lbl?.textContent?.trim()) return lbl.textContent.trim();\r\n    }\r\n    if ((el as HTMLInputElement).placeholder) return (el as HTMLInputElement).placeholder;\r\n    const container = el.closest(\r\n        '.form-group,.field,.question,[class*=\"Field\"],[class*=\"Question\"],[class*=\"form-row\"]'\r\n    );\r\n    if (container) {\r\n        const lbl = container.querySelector('label,[class*=\"label\"],[class*=\"Label\"]');\r\n        if (lbl && lbl !== el) return lbl.textContent?.trim() || '';\r\n    }\r\n    const wrap = el.closest('label');\r\n    if (wrap?.textContent?.trim()) return wrap.textContent.trim();\r\n    return (el as HTMLInputElement).name?.replace(/[_\\-]/g, ' ') || '';\r\n}\r\n\r\nexport function isFieldRequired(el: HTMLElement): boolean {\r\n    if (!el) return false;\r\n    if ((el as HTMLInputElement).required || el.getAttribute('aria-required') === 'true') return true;\r\n    if (el.getAttribute('required') !== null) return true;\r\n    const container = el.closest(\r\n        '.field,.application-field,.question,[class*=\"field\"],[class*=\"Field\"],[class*=\"question\"],[class*=\"Question\"],li,div'\r\n    );\r\n    const label = getFieldLabel(el);\r\n    if (/\\*\\s*$|required/.test((label || '').toLowerCase())) return true;\r\n    if (container) {\r\n        if (container.classList.contains('required')) return true;\r\n        if (container.getAttribute('data-required') === 'true') return true;\r\n        if (container.querySelector('.required,.asterisk,[aria-label*=\"required\" i]')) return true;\r\n    }\r\n    return false;\r\n}\r\n\r\nexport function hasFieldValue(el: HTMLElement): boolean {\r\n    if (!el) return false;\r\n    if (el.tagName === 'SELECT') {\r\n        const sel = el as HTMLSelectElement;\r\n        const val = (sel.value || '').trim();\r\n        if (!val) return false;\r\n        const idx = sel.selectedIndex;\r\n        if (idx >= 0) {\r\n            const txt = (sel.options[idx]?.textContent || '').trim().toLowerCase();\r\n            if (!txt || /select|choose|please|--/.test(txt)) return false;\r\n        }\r\n        return true;\r\n    }\r\n    if ((el as HTMLInputElement).type === 'checkbox' || (el as HTMLInputElement).type === 'radio') return !!(el as HTMLInputElement).checked;\r\n    return !!(el as HTMLInputElement).value?.trim();\r\n}\r\n\r\nexport function isVisible(el: HTMLElement): boolean {\r\n    if (!el) return false;\r\n    const style = getComputedStyle(el);\r\n    if (style.display === 'none' || style.visibility === 'hidden' || style.opacity === '0') return false;\r\n    const rect = el.getBoundingClientRect();\r\n    return rect.width > 0 || rect.height > 0;\r\n}\r\n\r\n// \u2500\u2500\u2500 React-compatible value setter \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport function nativeSet(el: HTMLElement, val: string): void {\r\n    if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) {\r\n        const proto = el instanceof HTMLTextAreaElement ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype;\r\n        const setter = Object.getOwnPropertyDescriptor(proto, 'value')?.set;\r\n        if (setter) setter.call(el, val); else el.value = val;\r\n        el.dispatchEvent(new Event('input', { bubbles: true }));\r\n        el.dispatchEvent(new Event('change', { bubbles: true }));\r\n        el.dispatchEvent(new Event('blur', { bubbles: true }));\r\n        el.dispatchEvent(new Event('focus', { bubbles: true }));\r\n    } else if (el.contentEditable === 'true') {\r\n        el.textContent = val;\r\n        el.dispatchEvent(new Event('input', { bubbles: true }));\r\n    }\r\n}\r\n\r\n// \u2500\u2500\u2500 Real click with pointer events \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport function realClick(el: HTMLElement): void {\r\n    el.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true }));\r\n    el.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));\r\n    el.dispatchEvent(new PointerEvent('pointerup', { bubbles: true }));\r\n    el.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));\r\n    el.click();\r\n}\r\n\r\n// \u2500\u2500\u2500 Profile loader from chrome.storage \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport async function loadProfile(): Promise<NormalizedProfile> {\r\n    try {\r\n        const data = await chrome.storage.local.get(['candidateDetails', 'userDetails', 'profileData', 'ua_profile']);\r\n        let raw: Record<string, any> = {};\r\n\r\n        // Try multiple storage keys\r\n        for (const key of ['ua_profile', 'profileData', 'candidateDetails', 'userDetails']) {\r\n            if (data[key]) {\r\n                try {\r\n                    const parsed = typeof data[key] === 'string' ? JSON.parse(data[key]) : data[key];\r\n                    raw = { ...raw, ...parsed };\r\n                } catch { /* skip invalid JSON */ }\r\n            }\r\n        }\r\n        return normalizeProfile(raw);\r\n    } catch {\r\n        return {};\r\n    }\r\n}\r\n\r\n// \u2500\u2500\u2500 Response bank (cached Q&A from storage) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\ninterface ResponseEntry { key: string; value: string; }\r\n\r\nlet _responseBankCache: { loaded: boolean; entries: ResponseEntry[]; ts: number } = { loaded: false, entries: [], ts: 0 };\r\nconst RESPONSE_BANK_TTL_MS = 10_000;\r\n\r\nfunction normalizeText(v: unknown): string {\r\n    return String(v || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();\r\n}\r\n\r\nfunction addResponseEntry(entries: ResponseEntry[], keyText: unknown, response: unknown): void {\r\n    const key = normalizeText(keyText);\r\n    const val = String(response || '').trim();\r\n    if (!key || !val) return;\r\n    if (entries.some(e => e.key === key && e.value === val)) return;\r\n    entries.push({ key, value: val });\r\n}\r\n\r\nfunction collectResponseEntries(node: any, entries: ResponseEntry[]): void {\r\n    if (!node) return;\r\n    if (Array.isArray(node)) { node.forEach(item => collectResponseEntries(item, entries)); return; }\r\n    if (typeof node !== 'object') return;\r\n    const response = node.response || node.answer || node.value || node.selected || node.a || node.text;\r\n    if (response && (node.question || node.key || node.id || node.label)) {\r\n        addResponseEntry(entries, node.question, response);\r\n        addResponseEntry(entries, node.key, response);\r\n        addResponseEntry(entries, node.label, response);\r\n        addResponseEntry(entries, node.id, response);\r\n        if (Array.isArray(node.keywords)) node.keywords.forEach((k: string) => addResponseEntry(entries, k, response));\r\n    }\r\n    Object.values(node).forEach(v => collectResponseEntries(v, entries));\r\n}\r\n\r\nexport async function getResponseBank(): Promise<ResponseEntry[]> {\r\n    if (_responseBankCache.loaded && (Date.now() - _responseBankCache.ts) < RESPONSE_BANK_TTL_MS) {\r\n        return _responseBankCache.entries;\r\n    }\r\n    const keys = [\r\n        'applicationDetails', 'complexFormData', 'manualComplexInstructions',\r\n        'manualApplicationDetail', 'responses', 'questionAnswers', 'candidateDetails',\r\n        'missing_details', 'missingDetails', 'missingQuestionDetails', 'userDetails',\r\n        'ua_responses',\r\n    ];\r\n    const raw = await chrome.storage.local.get(keys);\r\n    const entries: ResponseEntry[] = [];\r\n    for (const val of Object.values(raw || {})) {\r\n        if (!val) continue;\r\n        try {\r\n            const parsed = typeof val === 'string' ? JSON.parse(val) : val;\r\n            collectResponseEntries(parsed, entries);\r\n        } catch { /* skip */ }\r\n    }\r\n    _responseBankCache = { loaded: true, entries, ts: Date.now() };\r\n    return entries;\r\n}\r\n\r\nexport function getResponseValue(label: string, el: HTMLElement | null, entries: ResponseEntry[]): string {\r\n    if (!entries?.length) return '';\r\n    const candidates = [\r\n        label,\r\n        el ? getFieldLabel(el) : '',\r\n        (el as HTMLInputElement)?.name || '',\r\n        el?.id || '',\r\n        (el as HTMLInputElement)?.placeholder || '',\r\n        el?.getAttribute?.('aria-label') || '',\r\n    ].map(normalizeText).filter(Boolean);\r\n\r\n    for (const c of candidates) {\r\n        const exact = entries.find(e => e.key === c);\r\n        if (exact) return exact.value;\r\n    }\r\n    for (const c of candidates) {\r\n        const matched = entries.find(e => c.includes(e.key) || e.key.includes(c));\r\n        if (matched) return matched.value;\r\n    }\r\n    return '';\r\n}\r\n\r\n/** Combined guesser: tries profile guess first, then response bank. */\r\nexport function guessFieldValue(label: string, profile: NormalizedProfile, el: HTMLElement | null, responseEntries: ResponseEntry[] = []): string {\r\n    return guessValue(label, profile) || getResponseValue(label, el, responseEntries) || '';\r\n}\r\n\r\n// \u2500\u2500\u2500 Missing Required Fields Tracker \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\n\r\n/** Get labels of all visible required fields that are still empty. */\r\nexport function getMissingRequiredFields(): string[] {\r\n    const required = Array.from(document.querySelectorAll<HTMLElement>(\r\n        'input:not([type=hidden]):not([type=submit]):not([type=button]),textarea,select'\r\n    )).filter(el => isVisible(el) && isFieldRequired(el));\r\n    const missing: string[] = [];\r\n    for (const el of required) {\r\n        if ((el as HTMLInputElement).type === 'radio' && (el as HTMLInputElement).name) {\r\n            const group = Array.from(document.querySelectorAll<HTMLInputElement>(\r\n                `input[type=\"radio\"][name=\"${CSS.escape((el as HTMLInputElement).name)}\"]`\r\n            )).filter(isVisible);\r\n            if (group.some(r => r.checked)) continue;\r\n        } else if ((el as HTMLInputElement).type === 'checkbox' && !(el as HTMLInputElement).checked) {\r\n            // required checkbox must be checked\r\n        } else if (hasFieldValue(el)) {\r\n            continue;\r\n        }\r\n        const lbl = getFieldLabel(el) || (el as HTMLInputElement).name || el.id || 'Required field';\r\n        if (!missing.includes(lbl)) missing.push(lbl);\r\n    }\r\n    return missing;\r\n}\r\n\r\n// \u2500\u2500\u2500 Sidebar Reporting \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\n\r\n/** Send field status updates to the sidebar via background relay */\r\nexport function reportFieldStatus(fields: { name: string; status: string; required: boolean }[]): void {\r\n    try {\r\n        chrome.runtime.sendMessage({\r\n            type: 'SIDEBAR_FIELD_LIST',\r\n            fields,\r\n        }).catch(() => { });\r\n    } catch { }\r\n}\r\n\r\nexport function reportFieldFilled(fieldName: string, status: 'filled' | 'pending' | 'failed'): void {\r\n    try {\r\n        chrome.runtime.sendMessage({\r\n            type: 'SIDEBAR_FIELD_UPDATE',\r\n            fieldName,\r\n            status,\r\n        }).catch(() => { });\r\n    } catch { }\r\n}\r\n\r\n// Invalidate response cache on storage changes\r\nif (typeof chrome !== 'undefined' && chrome.storage?.onChanged) {\r\n    chrome.storage.onChanged.addListener((changes, area) => {\r\n        if (area !== 'local') return;\r\n        const refreshKeys = [\r\n            'applicationDetails', 'complexFormData', 'manualComplexInstructions',\r\n            'manualApplicationDetail', 'responses', 'questionAnswers', 'candidateDetails',\r\n            'missing_details', 'missingDetails', 'missingQuestionDetails', 'userDetails',\r\n            'ua_responses',\r\n        ];\r\n        for (const k of refreshKeys) {\r\n            if (changes[k]) { _responseBankCache = { loaded: false, entries: [], ts: 0 }; break; }\r\n        }\r\n    });\r\n}\r\n", "/**\r\n * Form Navigator \u2013 handles submit/next button detection, multi-page forms,\r\n * and success detection. Ported from OptimHire patch.\r\n */\r\nimport { isVisible, realClick } from '../fieldMatcher/smartGuesser';\r\n\r\nconst sleep = (ms: number) => new Promise(r => setTimeout(r, ms));\r\n\r\n// \u2500\u2500\u2500 Submit / Next button detection \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nconst SUBMIT_SELECTORS = [\r\n    'button[type=\"submit\"]', 'input[type=\"submit\"]',\r\n    'button[data-automation-id=\"submit\"]',\r\n    '#submit_app', '.postings-btn-submit', 'button.application-submit',\r\n    'button[data-qa=\"btn-submit\"]',\r\n    'button[aria-label*=\"Submit\" i]',\r\n    '[data-testid=\"submit-application\"]',\r\n    'button.btn-submit', '#resumeSubmitForm',\r\n    // Workday\r\n    ...['btnSubmit', 'submitButton', 'bottom-navigation-submit-button', 'pageFooterSubmitButton']\r\n        .map(id => `[data-automation-id=\"${id}\"]`),\r\n];\r\n\r\nconst NEXT_SELECTORS = [\r\n    'button[data-automation-id=\"bottom-navigation-next-button\"]',\r\n    'button[data-automation-id=\"next-button\"]',\r\n    'button[data-automation-id=\"pageFooterNextButton\"]',\r\n    'button[aria-label*=\"Next\" i]', 'button[aria-label*=\"Continue\" i]',\r\n    '[data-testid=\"next-step\"]', '[data-testid=\"continue\"]',\r\n];\r\n\r\nexport type NavAction = 'submitted' | 'next_page' | false;\r\n\r\n/**\r\n * Find and click the submit button. Returns 'submitted' | 'next_page' | false.\r\n * Only clicks submit if all required fields are filled (missingCount === 0).\r\n */\r\nexport async function tryClickSubmitOrNext(missingRequiredCount: number): Promise<NavAction> {\r\n    // \u2500\u2500 Submit (only if no missing required fields) \u2500\u2500\r\n    if (missingRequiredCount === 0) {\r\n        for (const sel of SUBMIT_SELECTORS) {\r\n            const btn = document.querySelector<HTMLElement>(sel);\r\n            if (btn && isVisible(btn)) {\r\n                await sleep(500);\r\n                realClick(btn);\r\n                return 'submitted';\r\n            }\r\n        }\r\n        // Fallback: button by text\r\n        const btns = Array.from(document.querySelectorAll<HTMLElement>('button,a[role=\"button\"],input[type=\"submit\"]')).filter(isVisible);\r\n        const submitBtn = btns.find(b => {\r\n            const t = (b.textContent || (b as HTMLInputElement).value || '').trim().toLowerCase();\r\n            return /^(submit|apply|send|complete|finish)\\b/i.test(t) && !/cancel|back|prev|close/i.test(t);\r\n        });\r\n        if (submitBtn) {\r\n            await sleep(500);\r\n            realClick(submitBtn);\r\n            return 'submitted';\r\n        }\r\n    }\r\n\r\n    // \u2500\u2500 Next / Continue \u2500\u2500\r\n    for (const sel of NEXT_SELECTORS) {\r\n        const btn = document.querySelector<HTMLElement>(sel);\r\n        if (btn && isVisible(btn)) {\r\n            await sleep(500);\r\n            realClick(btn);\r\n            return 'next_page';\r\n        }\r\n    }\r\n    // Fallback: text match\r\n    const allBtns = Array.from(document.querySelectorAll<HTMLElement>('button,a[role=\"button\"]')).filter(isVisible);\r\n    const nextBtn = allBtns.find(b => {\r\n        const t = (b.textContent || (b as HTMLInputElement).value || '').trim().toLowerCase();\r\n        return /^(next|continue|proceed|save.*continue|review)\\b/i.test(t) && !/cancel|back|prev|close/i.test(t);\r\n    });\r\n    if (nextBtn) {\r\n        await sleep(500);\r\n        realClick(nextBtn);\r\n        return 'next_page';\r\n    }\r\n\r\n    // Last resort: if all fields filled, try any submit-like button\r\n    if (missingRequiredCount === 0) {\r\n        const lastResort = allBtns.find(b => {\r\n            const t = (b.textContent || (b as HTMLInputElement).value || '').trim().toLowerCase();\r\n            return /submit|apply|send|go|done/i.test(t) && !/cancel|back|close/i.test(t);\r\n        });\r\n        if (lastResort) {\r\n            await sleep(500);\r\n            realClick(lastResort);\r\n            return 'submitted';\r\n        }\r\n    }\r\n    return false;\r\n}\r\n\r\n// \u2500\u2500\u2500 Success Detection \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nconst SUCCESS_URL_PATTERNS = [\r\n    '/thanks', '/thank-you', '/success', '/confirmation',\r\n    '/complete', '/submitted', '/application-submitted',\r\n    '/applied', '/done', '/thank_you',\r\n];\r\n\r\nconst SUCCESS_TEXT_PATTERNS = /application submitted|thank you for applying|application received|we.ve received your|your application has been|successfully submitted|application complete|thanks for applying|we have received|application was submitted/i;\r\n\r\nconst ALREADY_APPLIED_PATTERNS = /already applied|already submitted|you.ve applied|you have already|previously applied|duplicate application/i;\r\n\r\n/** Get page text excluding extension-injected elements. */\r\nfunction getPageTextClean(): string {\r\n    const exclusions = '#ua-control-bar,#ua-suggestion-overlay,#ua-overlay-host,[data-oh-patch]';\r\n    const mainContent = document.querySelectorAll<HTMLElement>(\r\n        'main, article, form, [role=\"main\"], .content, .application, #content, #main, #app'\r\n    );\r\n    let text = '';\r\n    if (mainContent.length > 0) {\r\n        mainContent.forEach(el => {\r\n            const clone = el.cloneNode(true) as HTMLElement;\r\n            clone.querySelectorAll(exclusions).forEach(x => x.remove());\r\n            text += ' ' + clone.textContent;\r\n        });\r\n    } else {\r\n        const clone = document.body.cloneNode(true) as HTMLElement;\r\n        clone.querySelectorAll(exclusions).forEach(x => x.remove());\r\n        text = clone.textContent || '';\r\n    }\r\n    return text.toLowerCase();\r\n}\r\n\r\nexport type SuccessResult = 'success' | 'duplicate' | 'none';\r\n\r\n/** Check if the page indicates a successful application submission. */\r\nexport function detectSuccess(initialUrl: string, submitClickedTs: number): SuccessResult {\r\n    const href = location.href.toLowerCase();\r\n\r\n    // URL-based detection (most reliable)\r\n    if (SUCCESS_URL_PATTERNS.some(p => href.includes(p))) return 'success';\r\n\r\n    // ATS-specific confirmation elements\r\n    if (document.querySelector('#application_confirmation,.application-confirmation,.confirmation-text')) return 'success';\r\n    if (document.querySelector('.posting-confirmation,.application-confirmation')) return 'success';\r\n    if (document.querySelector('[data-automation-id=\"congratulationsMessage\"],[data-automation-id=\"confirmationMessage\"]')) return 'success';\r\n\r\n    // Text-based detection\r\n    const body = getPageTextClean();\r\n    if (SUCCESS_TEXT_PATTERNS.test(body)) return 'success';\r\n\r\n    // URL changed after submit\r\n    if (submitClickedTs > 0 && location.href !== initialUrl && (Date.now() - submitClickedTs > 2000)) {\r\n        const newPath = location.pathname.toLowerCase();\r\n        if (!/\\/apply|\\/step|\\/page\\d|\\/form/i.test(newPath)) return 'success';\r\n    }\r\n\r\n    // Already applied\r\n    if (ALREADY_APPLIED_PATTERNS.test(body)) return 'duplicate';\r\n\r\n    return 'none';\r\n}\r\n\r\n// \u2500\u2500\u2500 Deduplication via appliedJobs \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nfunction normalizeUrl(url: string): string {\r\n    try {\r\n        const u = new URL(url);\r\n        ['utm_source', 'utm_medium', 'utm_campaign', 'ref', 'referer', 'source', 'fbclid']\r\n            .forEach(p => u.searchParams.delete(p));\r\n        return u.origin + u.pathname;\r\n    } catch { return url; }\r\n}\r\n\r\nexport async function markApplied(): Promise<void> {\r\n    const norm = normalizeUrl(location.href);\r\n    const { appliedJobs = [] } = await chrome.storage.local.get('appliedJobs');\r\n    if (!appliedJobs.includes(norm)) {\r\n        appliedJobs.push(norm);\r\n        if (appliedJobs.length > 15_000) appliedJobs.shift();\r\n        await chrome.storage.local.set({ appliedJobs });\r\n    }\r\n}\r\n\r\nexport async function isAlreadyApplied(url: string): Promise<boolean> {\r\n    const { appliedJobs = [] } = await chrome.storage.local.get('appliedJobs');\r\n    return appliedJobs.includes(normalizeUrl(url));\r\n}\r\n", "/**\r\n * Resume Upload \u2013 detects file input fields and attaches stored resume.\r\n * Ported from OptimHire patch.\r\n */\r\nimport { getFieldLabel, isVisible } from '../fieldMatcher/smartGuesser';\r\n\r\nconst LOG = (...a: unknown[]) => console.log('[UA-Resume]', ...a);\r\n\r\n/**\r\n * Try to upload a stored resume to visible file input fields.\r\n * The resume must be stored in chrome.storage.local as a base64 data URI.\r\n */\r\nexport async function tryResumeUpload(): Promise<boolean> {\r\n    const fileInputs = Array.from(document.querySelectorAll<HTMLInputElement>('input[type=\"file\"]'));\r\n    if (fileInputs.length === 0) return false;\r\n\r\n    const { ua_resumeFile, ua_resumeFileName, resumeFile, resumeFileName } =\r\n        await chrome.storage.local.get(['ua_resumeFile', 'ua_resumeFileName', 'resumeFile', 'resumeFileName']);\r\n    const file = ua_resumeFile || resumeFile;\r\n    const fileName = ua_resumeFileName || resumeFileName || 'resume.pdf';\r\n    if (!file) {\r\n        LOG('No stored resume for upload');\r\n        return false;\r\n    }\r\n\r\n    let uploaded = false;\r\n    for (const fi of fileInputs) {\r\n        if (fi.files && fi.files.length > 0) continue; // Already has file\r\n        const lbl = getFieldLabel(fi) || fi.name || fi.accept || '';\r\n        const l = lbl.toLowerCase();\r\n        // Only attach to resume/CV fields\r\n        if (/resume|cv|curriculum|document|upload|attach|file/i.test(l) || fi.accept?.includes('.pdf') || fi.accept?.includes('.doc')) {\r\n            try {\r\n                const resp = await fetch(file);\r\n                const blob = await resp.blob();\r\n                const fileObj = new File([blob], fileName, { type: blob.type || 'application/pdf' });\r\n                const dt = new DataTransfer();\r\n                dt.items.add(fileObj);\r\n                fi.files = dt.files;\r\n                fi.dispatchEvent(new Event('change', { bubbles: true }));\r\n                fi.dispatchEvent(new Event('input', { bubbles: true }));\r\n                LOG('Resume uploaded to:', lbl);\r\n                uploaded = true;\r\n            } catch (e) {\r\n                LOG('Resume upload failed:', e);\r\n            }\r\n        }\r\n    }\r\n    return uploaded;\r\n}\r\n", "/**\r\n * Captcha Solver \u2013 handles simple captcha scenarios.\r\n * Ported from OptimHire patch.\r\n */\r\nimport { nativeSet, realClick, getFieldLabel } from '../fieldMatcher/smartGuesser';\r\n\r\nconst LOG = (...a: unknown[]) => console.log('[UA-Captcha]', ...a);\r\n\r\n/** Attempt to solve simple captcha types. */\r\nexport async function solveCaptcha(): Promise<void> {\r\n    // reCAPTCHA checkbox inside iframe\r\n    document.querySelectorAll<HTMLIFrameElement>('iframe[src*=\"recaptcha\"],iframe[src*=\"hcaptcha\"]').forEach(f => {\r\n        try {\r\n            const cb = f.contentDocument?.querySelector<HTMLElement>('.recaptcha-checkbox,#recaptcha-anchor');\r\n            if (cb && !cb.classList.contains('recaptcha-checkbox-checked')) realClick(cb);\r\n        } catch { /* cross-origin blocked */ }\r\n    });\r\n\r\n    // Math captchas\r\n    document.querySelectorAll<HTMLInputElement>('[class*=\"captcha\"] input,[id*=\"captcha\"] input,input[name*=\"captcha\"]').forEach(inp => {\r\n        const lbl = getFieldLabel(inp);\r\n        const m = lbl.match(/(\\d+)\\s*([\\+\\-\\*x\u00D7\u00F7\\/])\\s*(\\d+)/);\r\n        if (!m) return;\r\n        const [, a, op, b] = m;\r\n        const n1 = +a, n2 = +b;\r\n        const ops: Record<string, number | null> = {\r\n            '+': n1 + n2, '-': n1 - n2, '*': n1 * n2, 'x': n1 * n2,\r\n            '\u00D7': n1 * n2, '/': n2 ? Math.round(n1 / n2) : null, '\u00F7': n2 ? Math.round(n1 / n2) : null,\r\n        };\r\n        const result = ops[op];\r\n        if (result !== null && result !== undefined) {\r\n            nativeSet(inp, String(result));\r\n            LOG('Math captcha solved:', lbl, '=', result);\r\n        }\r\n    });\r\n\r\n    // \"I'm not a robot\" checkboxes\r\n    document.querySelectorAll<HTMLInputElement>('input[type=checkbox][id*=\"captcha\"],input[type=checkbox][name*=\"captcha\"]')\r\n        .forEach(cb => { if (!cb.checked) realClick(cb); });\r\n}\r\n\r\n/**\r\n * Watch for captcha elements via MutationObserver and auto-solve.\r\n */\r\nexport function watchForCaptchas(): void {\r\n    const observer = new MutationObserver(() => solveCaptcha());\r\n    observer.observe(document.body, { childList: true, subtree: true });\r\n    solveCaptcha();\r\n}\r\n", "/**\r\n * ATS Navigator \u2013 platform-specific navigation handlers.\r\n * Clicks through Apply buttons, redirects, and modals before the autofill can run.\r\n * Ported from OptimHire patch.\r\n */\r\n\r\nimport type { ATSType } from '../types/index';\r\n\r\nconst LOG = (...a: unknown[]) => console.log('[UA-Nav]', ...a);\r\nconst sleep = (ms: number) => new Promise<void>(r => setTimeout(r, ms));\r\nconst $$ = <T extends Element>(s: string, c: ParentNode = document): T[] => Array.from(c.querySelectorAll(s));\r\n\r\nfunction isVisible(el: HTMLElement): boolean {\r\n    if (!el) return false;\r\n    const r = el.getBoundingClientRect();\r\n    return r.width > 0 && r.height > 0 && el.offsetParent !== null;\r\n}\r\n\r\nfunction realClick(el: HTMLElement): void {\r\n    if (!el) return;\r\n    el.dispatchEvent(new MouseEvent('mouseover', { bubbles: true }));\r\n    el.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));\r\n    el.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));\r\n    el.click();\r\n}\r\n\r\n// \u2500\u2500\u2500 Indeed: \"Apply on company site\" navigation \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport function handleIndeed(): void {\r\n    if (!location.hostname.includes('indeed.com')) return;\r\n    const click = () => {\r\n        const btn = $$<HTMLElement>('button,a').find(el =>\r\n            /apply on company site|apply externally|apply now/i.test(el.textContent || '') ||\r\n            el.getAttribute('data-testid') === 'company-site-apply-button'\r\n        );\r\n        if (btn && isVisible(btn)) { LOG('Indeed: clicking Apply on company site'); realClick(btn); }\r\n\r\n        const confirm = $$<HTMLElement>('button').find(el =>\r\n            /continue|proceed|yes|ok/i.test(el.textContent || '') &&\r\n            !!el.closest('[class*=\"modal\"],[class*=\"dialog\"],[role=\"dialog\"]')\r\n        );\r\n        if (confirm) realClick(confirm);\r\n    };\r\n    setTimeout(click, 1500);\r\n    new MutationObserver(click).observe(document.body, { childList: true, subtree: true });\r\n}\r\n\r\n// \u2500\u2500\u2500 LinkedIn: Easy Apply + direct apply \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport function handleLinkedIn(): void {\r\n    if (!location.hostname.includes('linkedin.com')) return;\r\n    if (!location.pathname.startsWith('/jobs')) return;\r\n\r\n    let acting = false;\r\n    const act = async () => {\r\n        if (acting) return;\r\n        acting = true;\r\n        try {\r\n            // Direct apply button (non-Easy Apply)\r\n            const direct = $$<HTMLElement>('.jobs-apply-button,.apply-button,[data-control-name*=\"apply\"]')\r\n                .find(el => {\r\n                    const t = (el.textContent || '').trim().toLowerCase();\r\n                    return t.includes('apply') && !t.includes('easy');\r\n                });\r\n            if (direct && isVisible(direct)) { LOG('LinkedIn: direct apply'); realClick(direct); return; }\r\n\r\n            // Easy Apply button\r\n            const easy = $$<HTMLElement>('.jobs-apply-button,[aria-label*=\"Easy Apply\"]')\r\n                .find(el => /easy apply/i.test(el.textContent || ''));\r\n            if (easy && isVisible(easy)) {\r\n                LOG('LinkedIn: Easy Apply');\r\n                realClick(easy);\r\n                await sleep(1500);\r\n            }\r\n        } finally {\r\n            setTimeout(() => { acting = false; }, 3000);\r\n        }\r\n    };\r\n\r\n    setTimeout(act, 2000);\r\n    new MutationObserver(act).observe(document.body, { childList: true, subtree: false });\r\n}\r\n\r\n// \u2500\u2500\u2500 HiringCafe: \"Apply Directly\" + company-size filter \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nconst GOOD_SIZES = [\r\n    '51-200', '201-500', '501-1000', '501-1,000', '1001-2000', '1,001-2,000',\r\n    '2001-5000', '2,001-5,000', '5001-10000', '5,001-10,000', '10001+', '10,001+',\r\n    '51 to 200', '201 to 500', '501 to 1000',\r\n];\r\n\r\nexport function handleHiringCafe(): void {\r\n    if (!location.hostname.includes('hiring.cafe')) return;\r\n\r\n    const sizeEl = $$<HTMLElement>('[class*=\"size\"],[class*=\"employees\"],[data-field*=\"size\"]')\r\n        .find(el => /\\d/.test(el.textContent || ''));\r\n    if (sizeEl) {\r\n        const txt = (sizeEl.textContent || '').replace(/\\s/g, '');\r\n        const ok = GOOD_SIZES.some(s => txt.includes(s.replace(/\\s/g, '')));\r\n        if (!ok) {\r\n            LOG('HiringCafe: company size not preferred \u2014 skipping');\r\n            try { chrome.runtime.sendMessage({ type: 'JOB_SKIPPED', reason: 'company_size' }).catch(() => { }); } catch { }\r\n            return;\r\n        }\r\n    }\r\n\r\n    const tryClick = () => {\r\n        const btn = $$<HTMLElement>('a,button').find(el =>\r\n            /apply directly|apply now|apply for this/i.test(el.textContent || '')\r\n        );\r\n        if (btn && isVisible(btn)) { LOG('HiringCafe: Apply Directly'); realClick(btn); }\r\n    };\r\n    setTimeout(tryClick, 2000);\r\n    new MutationObserver(tryClick).observe(document.body, { childList: true, subtree: true });\r\n}\r\n\r\n// \u2500\u2500\u2500 Workday: Apply \u2192 Apply Manually button flow \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nlet _wdApplyFlowDone = false;\r\nexport async function workdayApplyButtonFlow(): Promise<void> {\r\n    if (_wdApplyFlowDone) return;\r\n    const host = location.hostname.toLowerCase();\r\n    if (!host.includes('myworkdayjobs.com') && !host.includes('workday.com')) return;\r\n\r\n    // Step 1: Click the primary \"Apply\" button\r\n    const applySelectors = [\r\n        '[data-automation-id=\"applyButton\"]',\r\n        '[data-automation-id=\"jobAction-apply\"]',\r\n        'button[data-automation-id=\"applyBtn\"]',\r\n        'a[data-automation-id*=\"apply\"]',\r\n    ];\r\n    let applyBtn: HTMLElement | null = null;\r\n    for (const sel of applySelectors) {\r\n        const el = document.querySelector<HTMLElement>(sel);\r\n        if (el && isVisible(el)) { applyBtn = el; break; }\r\n    }\r\n    if (!applyBtn) {\r\n        applyBtn = $$<HTMLElement>('button, a[role=\"button\"], a').find(el => {\r\n            if (!isVisible(el)) return false;\r\n            const t = (el.textContent || '').trim().toLowerCase();\r\n            return t === 'apply' || t === 'apply now';\r\n        }) || null;\r\n    }\r\n    if (applyBtn) {\r\n        LOG('Workday: Clicking Apply button');\r\n        realClick(applyBtn);\r\n        await sleep(2000);\r\n    }\r\n\r\n    // Step 2: Click \"Apply Manually\" if it appears\r\n    const manualSelectors = [\r\n        '[data-automation-id=\"applyManually\"]',\r\n        '[data-automation-id=\"applyManuallyButton\"]',\r\n        '[data-automation-id=\"manuallyApply\"]',\r\n    ];\r\n    let manualBtn: HTMLElement | null = null;\r\n    for (const sel of manualSelectors) {\r\n        const el = document.querySelector<HTMLElement>(sel);\r\n        if (el && isVisible(el)) { manualBtn = el; break; }\r\n    }\r\n    if (!manualBtn) {\r\n        manualBtn = $$<HTMLElement>('button, a[role=\"button\"], a').find(el => {\r\n            if (!isVisible(el)) return false;\r\n            const t = (el.textContent || '').trim().toLowerCase();\r\n            return t.includes('apply manually') || t.includes('manual apply');\r\n        }) || null;\r\n    }\r\n    if (manualBtn) {\r\n        LOG('Workday: Clicking Apply Manually');\r\n        realClick(manualBtn);\r\n        await sleep(3000);\r\n    }\r\n\r\n    _wdApplyFlowDone = true;\r\n}\r\n\r\n// \u2500\u2500\u2500 Generic: Click visible Apply button on unknown career pages \u2500\r\nexport async function clickApplyButton(): Promise<boolean> {\r\n    const applyPatterns = ['apply', 'apply now', 'apply directly', 'easy apply',\r\n        'apply for this job', 'submit application', 'start application'];\r\n    const candidates = $$<HTMLElement>('a, button, [role=\"button\"], input[type=\"submit\"]');\r\n    for (const el of candidates) {\r\n        if (!isVisible(el)) continue;\r\n        const text = ((el.textContent || (el as HTMLInputElement).value || '')).trim().toLowerCase();\r\n        const aria = (el.getAttribute('aria-label') || '').toLowerCase();\r\n        const combined = text + ' ' + aria;\r\n        if (applyPatterns.some(p => combined === p || combined.startsWith(p + ' ') || combined.includes(p))) {\r\n            const r = el.getBoundingClientRect();\r\n            if (r.width >= 40 && r.height >= 20) {\r\n                LOG('Generic page: Clicking Apply button');\r\n                realClick(el);\r\n                await sleep(3000);\r\n                return true;\r\n            }\r\n        }\r\n    }\r\n    return false;\r\n}\r\n\r\n// \u2500\u2500\u2500 Run platform-specific navigation \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\nexport async function runAtsNavigation(atsType: ATSType): Promise<void> {\r\n    switch (atsType) {\r\n        case 'indeed': handleIndeed(); break;\r\n        case 'linkedin': handleLinkedIn(); break;\r\n        case 'hiringcafe': handleHiringCafe(); break;\r\n        case 'workday': await workdayApplyButtonFlow(); break;\r\n        default:\r\n            // For unknown ATS / generic pages, try clicking an Apply button\r\n            if (atsType === 'generic') await clickApplyButton();\r\n            break;\r\n    }\r\n}\r\n", "/**\r\n * Tailoring Orchestrator \u2013 automates the Jobright sidebar tailoring workflow.\r\n * Flow: ATS detected \u2192 Generate Custom Resume \u2192 Improve My Resume \u2192 Full Edit\r\n *       \u2192 Select all skills \u2192 Generate My New Resume \u2192 Continue to Autofill\r\n */\r\n\r\nconst LOG = (...a: unknown[]) => console.log('[UA-Tailor]', ...a);\r\nconst sleep = (ms: number) => new Promise<void>(r => setTimeout(r, ms));\r\n\r\n// \u2500\u2500\u2500 DOM helpers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\n\r\nfunction isVisible(el: HTMLElement): boolean {\r\n    if (!el) return false;\r\n    const r = el.getBoundingClientRect();\r\n    return r.width > 0 && r.height > 0;\r\n}\r\n\r\nfunction realClick(el: HTMLElement): void {\r\n    if (!el) return;\r\n    el.scrollIntoView({ behavior: 'smooth', block: 'center' });\r\n    el.dispatchEvent(new MouseEvent('mouseover', { bubbles: true }));\r\n    el.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));\r\n    el.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));\r\n    el.click();\r\n}\r\n\r\n/** Find a visible button/link by text pattern across the entire page */\r\nfunction findButtonByText(pattern: RegExp, scope: ParentNode = document): HTMLElement | null {\r\n    const candidates = Array.from(scope.querySelectorAll<HTMLElement>(\r\n        'button, a, [role=\"button\"], div[class*=\"btn\"], span[class*=\"btn\"]'\r\n    ));\r\n    return candidates.find(el => isVisible(el) && pattern.test((el.textContent || '').trim())) || null;\r\n}\r\n\r\n/** Wait for a button matching a pattern to appear on screen */\r\nasync function waitForButton(pattern: RegExp, timeoutMs: number = 60_000): Promise<HTMLElement | null> {\r\n    const start = Date.now();\r\n    while (Date.now() - start < timeoutMs) {\r\n        const btn = findButtonByText(pattern);\r\n        if (btn) return btn;\r\n        await sleep(1000);\r\n    }\r\n    return null;\r\n}\r\n\r\n/** Wait for an element matching a selector to appear */\r\nasync function waitForSelector(sel: string, timeoutMs: number = 30_000): Promise<HTMLElement | null> {\r\n    const start = Date.now();\r\n    while (Date.now() - start < timeoutMs) {\r\n        const el = document.querySelector<HTMLElement>(sel);\r\n        if (el && isVisible(el)) return el;\r\n        await sleep(500);\r\n    }\r\n    return null;\r\n}\r\n\r\n// \u2500\u2500\u2500 Jobright Sidebar Detection \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\n\r\n/** Check if the Jobright sidebar/extension is present on the page */\r\nexport function detectJobrightSidebar(): HTMLElement | null {\r\n    // The Jobright sidebar injects its UI into the page.\r\n    // It may be in the regular DOM or inside a shadow root.\r\n    // Try multiple known selectors:\r\n    const selectors = [\r\n        '#jobright-sidebar',\r\n        '[class*=\"jobright\"]',\r\n        '[data-jobright]',\r\n        '[id*=\"jobright\"]',\r\n        // The sidebar may also use a container with specific classes\r\n        '.jr-sidebar',\r\n        '#jr-extension-root',\r\n    ];\r\n    for (const s of selectors) {\r\n        const el = document.querySelector<HTMLElement>(s);\r\n        if (el) return el;\r\n    }\r\n\r\n    // Check for Jobright iframe\r\n    const iframes = document.querySelectorAll('iframe');\r\n    for (const iframe of iframes) {\r\n        const src = iframe.src || '';\r\n        if (/jobright/i.test(src)) return iframe as HTMLElement;\r\n    }\r\n\r\n    return null;\r\n}\r\n\r\n/** Check if the tailoring UI is available (Generate Custom Resume, etc.) */\r\nexport function isTailoringAvailable(): boolean {\r\n    // Only detect actual tailoring UI \u2014 do NOT match the Autofill button\r\n    return !!(\r\n        findButtonByText(/generate.*custom.*resume/i) ||\r\n        findButtonByText(/improve.*resume.*this.*job/i) ||\r\n        document.querySelector('[class*=\"resume-tailor\"],[data-testid*=\"tailor\"]')\r\n    );\r\n}\r\n\r\n// \u2500\u2500\u2500 Tailoring Flow Steps \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\r\n\r\n/**\r\n * Run the complete Jobright tailoring workflow:\r\n * 1. Click \"Generate Custom Resume\" (or trigger tailoring)\r\n * 2. Wait for \"Improve My Resume for This Job\" \u2192 click\r\n * 3. Select \"Full Edit\" \u2192 click\r\n * 4. Click \"Select all\" for skill keywords\r\n * 5. Click \"Generate My New Resume\"\r\n * 6. Wait for generation to complete\r\n * 7. Click \"Continue to Autofill\"\r\n *\r\n * Returns true if tailoring was completed successfully, false if skipped/failed.\r\n */\r\nexport async function runTailoringSteps(): Promise<boolean> {\r\n    LOG('Starting tailoring workflow...');\r\n\r\n    // Step 1: Look for \"Generate Custom Resume\" or similar tailoring trigger\r\n    // IMPORTANT: Do NOT fall back to clicking the Autofill button \u2014 that causes a loop!\r\n    let genBtn = findButtonByText(/generate.*custom.*resume/i);\r\n\r\n    if (genBtn) {\r\n        LOG('Step 1: Clicking Generate Custom Resume');\r\n        realClick(genBtn);\r\n        await sleep(3000);\r\n    } else {\r\n        LOG('No tailoring trigger found \u2014 checking if already in tailoring flow');\r\n    }\r\n\r\n    // Step 2: Wait for and click \"Improve My Resume for This Job\"\r\n    const improveBtn = await waitForButton(/improve.*resume.*this.*job|improve.*my.*resume/i, 30_000);\r\n    if (improveBtn) {\r\n        LOG('Step 2: Clicking Improve My Resume');\r\n        realClick(improveBtn);\r\n        await sleep(2000);\r\n    } else {\r\n        LOG('Step 2: No \"Improve My Resume\" button found \u2014 continuing');\r\n    }\r\n\r\n    // Step 3: Select \"Full Edit\" option\r\n    const fullEditBtn = await waitForButton(/full.*edit|all.*experiences/i, 15_000);\r\n    if (fullEditBtn) {\r\n        LOG('Step 3: Selecting Full Edit');\r\n        realClick(fullEditBtn);\r\n        await sleep(2000);\r\n    } else {\r\n        LOG('Step 3: No Full Edit option \u2014 continuing');\r\n    }\r\n\r\n    // Step 4: Click \"Select all\" for skill keywords\r\n    const selectAllBtn = await waitForButton(/select\\s*(all|everything)/i, 15_000);\r\n    if (selectAllBtn) {\r\n        LOG('Step 4: Clicking Select All for skills');\r\n        realClick(selectAllBtn);\r\n        await sleep(1000);\r\n    } else {\r\n        // Try clicking individual skill checkboxes\r\n        const skillChecks = Array.from(document.querySelectorAll<HTMLInputElement>(\r\n            'input[type=\"checkbox\"]:not(:checked)'\r\n        )).filter(cb => {\r\n            const container = cb.closest('[class*=\"skill\"],[class*=\"keyword\"]');\r\n            return container && isVisible(cb);\r\n        });\r\n        if (skillChecks.length > 0) {\r\n            LOG(`Step 4: Clicking ${skillChecks.length} individual skill checkboxes`);\r\n            for (const cb of skillChecks) {\r\n                realClick(cb);\r\n                await sleep(100);\r\n            }\r\n        } else {\r\n            LOG('Step 4: No skill checkboxes found \u2014 continuing');\r\n        }\r\n    }\r\n\r\n    // Step 5: Click \"Generate My New Resume\"\r\n    const generateBtn = await waitForButton(/generate.*new.*resume|generate.*resume|create.*resume/i, 15_000);\r\n    if (generateBtn) {\r\n        LOG('Step 5: Clicking Generate My New Resume');\r\n        realClick(generateBtn);\r\n        // Wait for generation to complete (this can take 10-60s)\r\n        LOG('Step 5: Waiting for resume generation...');\r\n        await waitForGenerationComplete(120_000);\r\n    } else {\r\n        LOG('Step 5: No Generate button found \u2014 continuing');\r\n    }\r\n\r\n    // Step 6: Click \"Continue to Autofill\"\r\n    const continueBtn = await waitForButton(/continue.*auto\\s*fill|continue.*to.*auto/i, 60_000);\r\n    if (continueBtn) {\r\n        LOG('Step 6: Clicking Continue to Autofill');\r\n        realClick(continueBtn);\r\n        await sleep(2000);\r\n        LOG('Tailoring workflow complete!');\r\n        return true;\r\n    }\r\n\r\n    // Fallback: look for \"Download Resume\" as an indicator tailoring is done\r\n    const downloadBtn = findButtonByText(/download.*resume/i);\r\n    if (downloadBtn) {\r\n        LOG('Step 6: Resume generated (Download available) \u2014 looking for Continue');\r\n        // One more try for Continue to Autofill\r\n        await sleep(3000);\r\n        const retry = findButtonByText(/continue.*auto\\s*fill|continue.*to.*auto/i);\r\n        if (retry) {\r\n            realClick(retry);\r\n            await sleep(2000);\r\n            return true;\r\n        }\r\n    }\r\n\r\n    LOG('Tailoring workflow: could not complete all steps \u2014 proceeding to autofill anyway');\r\n    return false;\r\n}\r\n\r\n/** Wait for resume generation to complete (loading indicator disappears) */\r\nasync function waitForGenerationComplete(timeoutMs: number): Promise<void> {\r\n    const start = Date.now();\r\n    let spinnerSeen = false;\r\n\r\n    while (Date.now() - start < timeoutMs) {\r\n        // Check for loading spinners / progress indicators\r\n        const spinner = document.querySelector(\r\n            '[class*=\"loading\"],[class*=\"spinner\"],[class*=\"progress\"],[class*=\"generating\"],' +\r\n            '[role=\"progressbar\"],.animate-spin,[class*=\"pulse\"]'\r\n        );\r\n        const isLoading = spinner && isVisible(spinner as HTMLElement);\r\n\r\n        if (isLoading) {\r\n            spinnerSeen = true;\r\n        } else if (spinnerSeen) {\r\n            // Spinner was visible and now it's gone \u2192 generation complete\r\n            LOG('Resume generation complete (spinner disappeared)');\r\n            await sleep(1000); // Brief pause for UI to settle\r\n            return;\r\n        }\r\n\r\n        // Also check if \"Continue to Autofill\" or \"Download Resume\" appeared\r\n        if (findButtonByText(/continue.*auto\\s*fill|download.*resume/i)) {\r\n            LOG('Resume generation complete (action buttons appeared)');\r\n            return;\r\n        }\r\n\r\n        await sleep(1000);\r\n    }\r\n    LOG('Resume generation: timeout reached');\r\n}\r\n\r\n/**\r\n * Wait for the tailoring to be complete, then click \"Continue to Autofill\"\r\n * and then click the Autofill button.\r\n */\r\nexport async function waitForTailoringAndTriggerAutofill(): Promise<boolean> {\r\n    // First run all tailoring steps\r\n    const tailored = await runTailoringSteps();\r\n\r\n    // After tailoring, find and click the Autofill button\r\n    await sleep(1500);\r\n    const autofillBtn = findButtonByText(/^autofill$|^auto\\s*fill$|start.*autofill/i);\r\n    if (autofillBtn) {\r\n        LOG('Clicking the Autofill button after tailoring');\r\n        realClick(autofillBtn);\r\n        await sleep(2000);\r\n        return true;\r\n    }\r\n\r\n    return tailored;\r\n}\r\n", "/**\r\n * Content script - runs on every page.\r\n * Enhanced with: tailoring-first flow, auto-trigger on ATS detection, smart field guesser,\r\n * multi-page form handling, CSV queue integration, resume upload,\r\n * captcha solving, ATS-specific navigation, and missing dialog handling.\r\n */\r\n\r\nimport type { ExtMessage, FieldMatchResult, SavedResponse, ATSType } from '../types/index';\r\nimport { detectATS } from '../atsDetector/index';\r\nimport { getAdapter } from '../adapters/index';\r\nimport { matchFields } from '../fieldMatcher/index';\r\nimport {\r\n  guessValue, normalizeProfile, loadProfile, getFieldLabel as smartGetLabel,\r\n  isFieldRequired, hasFieldValue, nativeSet, isVisible, realClick,\r\n  getResponseBank, guessFieldValue, NormalizedProfile,\r\n  getMissingRequiredFields, reportFieldStatus, reportFieldFilled,\r\n} from '../fieldMatcher/smartGuesser';\r\nimport { tryClickSubmitOrNext, detectSuccess, markApplied, NavAction } from './formNavigator';\r\nimport { tryResumeUpload } from './resumeUpload';\r\nimport { solveCaptcha, watchForCaptchas } from './captchaSolver';\r\nimport { runAtsNavigation } from './atsNavigator';\r\nimport { runTailoringSteps, isTailoringAvailable, detectJobrightSidebar } from './tailoringOrchestrator';\r\n\r\nconst LOG = (...a: unknown[]) => console.log('[UA]', ...a);\r\nconst sleep = (ms: number) => new Promise<void>(r => setTimeout(r, ms));\r\nconst $$ = <T extends Element>(s: string): T[] => Array.from(document.querySelectorAll(s));\r\n\r\nlet isRunning = false;\r\nlet observer: MutationObserver | null = null;\r\nlet _autoTriggered = false;\r\nlet _autoTriggerRunning = false;\r\n\r\n// \u2500\u2500\u2500 Message handling from background / popup \u2500\u2500\u2500\r\nchrome.runtime.onMessage.addListener((msg: any, _sender, sendResponse) => {\r\n  if (msg.type === 'START_AUTOFILL') {\r\n    startAutofill().then(() => sendResponse({ ok: true })).catch((e) => sendResponse({ ok: false, error: String(e) }));\r\n    return true;\r\n  }\r\n  if (msg.type === 'STOP_AUTOFILL') {\r\n    stopAutofill();\r\n    sendResponse({ ok: true });\r\n  }\r\n  if (msg.type === 'DETECT_ATS') {\r\n    const result = detectATS(document);\r\n    sendResponse(result);\r\n  }\r\n  // CSV queue / automation trigger\r\n  if (msg.type === 'TRIGGER_AUTOFILL') {\r\n    runFullAutofill().then(() => sendResponse({ ok: true })).catch(e => sendResponse({ ok: false, error: String(e) }));\r\n    return true;\r\n  }\r\n  // OptimHire-compatible message: FILL_COMPLEX_FORM\r\n  if (msg.type === 'FILL_COMPLEX_FORM') {\r\n    runFullAutofill().then(() => sendResponse({ ok: true })).catch(e => sendResponse({ ok: false, error: String(e) }));\r\n    return true;\r\n  }\r\n  if (msg.type === 'TRIGGER_TAILORING') {\r\n    runTailoringSteps().then(ok => sendResponse({ ok })).catch(e => sendResponse({ ok: false, error: String(e) }));\r\n    return true;\r\n  }\r\n  if (msg.type === 'PING') {\r\n    sendResponse({ ready: true });\r\n  }\r\n  if (msg.type === 'SOLVE_CAPTCHA') {\r\n    solveCaptcha().then(() => sendResponse({ ok: true }));\r\n    return true;\r\n  }\r\n});\r\n\r\nasync function send(msg: ExtMessage | Record<string, any>): Promise<any> {\r\n  try { return await chrome.runtime.sendMessage(msg); } catch { return null; }\r\n}\r\n\r\nasync function getResponses(): Promise<SavedResponse[]> {\r\n  const domain = location.hostname;\r\n  const r = await send({ type: 'GET_RESPONSES', payload: { domain } });\r\n  return r?.data || [];\r\n}\r\n\r\n// \u2500\u2500\u2500 Original autofill (field-by-field with suggestions) \u2500\u2500\u2500\r\nasync function startAutofill() {\r\n  if (isRunning) return;\r\n  isRunning = true;\r\n  _autoTriggered = true; // Prevent auto-trigger from firing concurrently\r\n  _autoTriggerRunning = false;\r\n  showControlBar();\r\n\r\n  const ats = detectATS(document);\r\n  const adapter = getAdapter(ats.type);\r\n  const responses = await getResponses();\r\n\r\n  // Run ATS-specific navigation first (click Apply buttons, etc.)\r\n  await runAtsNavigation(ats.type);\r\n\r\n  // ATS-specific fill\r\n  await atsSpecificFill(ats.type);\r\n\r\n  // Initial fill with existing saved responses\r\n  await fillPage(adapter, responses, ats.type);\r\n\r\n  // Enhanced: also run the smart guesser for any remaining empty fields\r\n  await enhancedFillPass();\r\n\r\n  // Watch for dynamic changes\r\n  observer = new MutationObserver(async (mutations) => {\r\n    if (!isRunning) return;\r\n    const hasNewNodes = mutations.some((m) => m.addedNodes.length > 0);\r\n    if (hasNewNodes) {\r\n      await fillPage(adapter, responses, ats.type);\r\n      await enhancedFillPass();\r\n    }\r\n  });\r\n  observer.observe(document.body, { childList: true, subtree: true });\r\n}\r\n\r\nfunction stopAutofill() {\r\n  isRunning = false;\r\n  if (observer) { observer.disconnect(); observer = null; }\r\n  removeControlBar();\r\n}\r\n\r\nasync function fillPage(adapter: ReturnType<typeof getAdapter>, responses: SavedResponse[], atsType: ATSType) {\r\n  const fields = adapter.getFields(document);\r\n  const domain = location.hostname;\r\n  const matches = matchFields(fields, responses, { domain, atsType });\r\n\r\n  let filled = 0;\r\n  for (const match of matches) {\r\n    if (!isRunning) break;\r\n    if (isAlreadyFilled(match.field)) continue;\r\n\r\n    const ok = await adapter.fillField(match.field, match.response.response);\r\n    if (ok) {\r\n      filled++;\r\n      match.field.classList.add('ua-filled');\r\n      match.field.classList.add('ua-filled-flash');\r\n      send({ type: 'RECORD_USAGE', payload: { id: match.response.id } });\r\n      setTimeout(() => match.field.classList.remove('ua-filled-flash'), 600);\r\n    }\r\n  }\r\n  updateControlBar(filled, matches.length);\r\n}\r\n\r\n// \u2500\u2500\u2500 ATS-Specific Fill (ported from OptimHire) \u2500\u2500\u2500\r\n\r\n// Workday comprehensive field mapping\r\nconst WD_FIELDS: Record<string, string> = {\r\n  legalNameSection_firstName: 'first_name', legalNameSection_lastName: 'last_name',\r\n  legalNameSection_middleName: 'middle_name',\r\n  infoFirstName: 'first_name', infoLastName: 'last_name',\r\n  infoEmail: 'email', infoCellPhone: 'phone', infoLinkedIn: 'linkedin_profile_url',\r\n  email: 'email', phone: 'phone',\r\n  addressSection_addressLine1: 'address', addressSection_addressLine2: 'address2',\r\n  addressSection_city: 'city', addressSection_postalCode: 'postal_code',\r\n  workHistoryCompanyName: 'current_company', workHistoryPosition: 'current_title',\r\n  educationHistoryName: 'school', degree: 'degree',\r\n  linkedIn: 'linkedin_profile_url', website: 'website_url', github: 'github_url',\r\n  jobTitle: 'current_title', company: 'current_company', school: 'school',\r\n  major: 'major', postalCode: 'postal_code', city: 'city', state: 'state',\r\n  country: 'country', yearsOfExperience: 'years_of_experience',\r\n  salary: 'expected_salary', coverLetter: 'cover_letter', howDidYouHear: 'how_did_you_hear',\r\n};\r\n\r\nconst WD_TEXTAREA_AIDS = new Set([\r\n  'formField-roleDescription', 'formField-summary',\r\n  'formField-coverLetter', 'formField-additionalInfo',\r\n]);\r\n\r\nasync function atsSpecificFill(atsType: ATSType): Promise<void> {\r\n  const host = location.hostname.toLowerCase();\r\n  const profile = await loadProfile();\r\n\r\n  if (atsType === 'workday' || host.includes('myworkdayjobs.com') || host.includes('workday.com')) {\r\n    await workdayFill(profile);\r\n  } else if (atsType === 'greenhouse' || host.includes('greenhouse.io')) {\r\n    await greenhouseFill(profile);\r\n  } else if (atsType === 'taleo' || host.includes('oraclecloud.com') || host.includes('taleo.net')) {\r\n    await oracleFill(profile);\r\n  } else if (atsType === 'smartrecruiters' || host.includes('smartrecruiters.com')) {\r\n    await smartRecruitersFill(profile);\r\n  }\r\n}\r\n\r\nasync function workdayFill(p: NormalizedProfile): Promise<void> {\r\n  LOG('Running Workday-specific fill');\r\n  const responseEntries = await getResponseBank();\r\n\r\n  // Account flow (create account / sign-in)\r\n  await workdayAccountFlow(p);\r\n\r\n  // Fill all data-automation-id fields\r\n  const containers = $$<HTMLElement>('[data-automation-id]:not([data-automation-id=\"\"])');\r\n  for (const el of containers) {\r\n    const aid = el.getAttribute('data-automation-id') || '';\r\n\r\n    // Textarea fields\r\n    if (WD_TEXTAREA_AIDS.has(aid)) {\r\n      const ta = el.querySelector<HTMLTextAreaElement>('textarea') || (el.tagName === 'TEXTAREA' ? el as HTMLTextAreaElement : null);\r\n      if (ta && !ta.value?.trim()) {\r\n        const val = p.cover_letter || guessValue('cover letter', p);\r\n        if (val) { ta.focus(); nativeSet(ta, val); }\r\n      }\r\n      continue;\r\n    }\r\n\r\n    const profileKey = WD_FIELDS[aid];\r\n    if (!profileKey) continue;\r\n    const val = p[profileKey];\r\n    if (!val) continue;\r\n\r\n    const input = el.querySelector<HTMLInputElement>('input:not([type=hidden]):not([type=file]),textarea');\r\n    if (input && !input.value?.trim()) {\r\n      input.focus(); nativeSet(input, val); await sleep(80);\r\n      continue;\r\n    }\r\n\r\n    // Combobox handling\r\n    const combo = el.querySelector<HTMLElement>('[role=combobox],[data-automation-id*=\"combobox\"]');\r\n    if (combo) {\r\n      realClick(combo); await sleep(400);\r\n      const si = combo.querySelector<HTMLInputElement>('input');\r\n      if (si) { nativeSet(si, val); await sleep(700); }\r\n      const opt = document.querySelector<HTMLElement>('[role=option]');\r\n      if (opt) realClick(opt);\r\n      continue;\r\n    }\r\n\r\n    // Radio buttons\r\n    $$<HTMLInputElement>('input[type=radio]').forEach(r => {\r\n      const t = (document.querySelector(`label[for=\"${CSS.escape(r.id)}\"]`)?.textContent || '').toLowerCase();\r\n      if (t.includes(val.toLowerCase())) realClick(r);\r\n    });\r\n  }\r\n\r\n  // EEO fields\r\n  await workdayEeoFields();\r\n\r\n  // Agreement checkboxes\r\n  $$<HTMLInputElement>('[data-automation-id=\"agreementCheckbox\"] input[type=checkbox]')\r\n    .filter(cb => !cb.checked).forEach(cb => realClick(cb));\r\n\r\n  LOG('Workday fill done');\r\n}\r\n\r\nasync function workdayAccountFlow(p: NormalizedProfile): Promise<void> {\r\n  const { appAccountEmail, appAccountPassword } = await chrome.storage.local.get(['appAccountEmail', 'appAccountPassword']);\r\n  const acctEmail = appAccountEmail || p.email || '';\r\n  const acctPassword = appAccountPassword || '';\r\n\r\n  // Create Account checkbox\r\n  const createCb = document.querySelector<HTMLInputElement>(\r\n    '[data-automation-id=\"createAccountCheckbox\"] input[type=checkbox],input[data-automation-id=\"createAccountCheckbox\"]'\r\n  );\r\n  if (createCb && !createCb.checked) { realClick(createCb); await sleep(600); }\r\n\r\n  // Fill email\r\n  const emailField = document.querySelector<HTMLInputElement>(\r\n    '[data-automation-id=\"createAccountEmail\"] input,[data-automation-id=\"accountCreationEmail\"] input,input[data-automation-id=\"email\"],input[name=\"email\"][type=\"email\"]'\r\n  );\r\n  if (emailField && !emailField.value?.trim() && acctEmail) {\r\n    emailField.focus(); nativeSet(emailField, acctEmail); await sleep(200);\r\n  }\r\n\r\n  // Fill password\r\n  if (acctPassword) {\r\n    const pwFields = Array.from(document.querySelectorAll<HTMLInputElement>('input[type=password]')).filter(el => isVisible(el));\r\n    for (const pw of pwFields) {\r\n      if (!pw.value?.trim()) { pw.focus(); nativeSet(pw, acctPassword); await sleep(200); }\r\n    }\r\n  }\r\n\r\n  // Click Create Account or Sign In\r\n  const createBtn = document.querySelector<HTMLElement>('[data-automation-id=\"createAccountSubmitButton\"]');\r\n  if (createBtn && isVisible(createBtn)) { await sleep(400); realClick(createBtn); await sleep(1500); return; }\r\n  const signInBtn = document.querySelector<HTMLElement>('[data-automation-id=\"signInSubmitButton\"]');\r\n  if (signInBtn && isVisible(signInBtn)) { await sleep(400); realClick(signInBtn); await sleep(1500); }\r\n}\r\n\r\nasync function workdayEeoFields(): Promise<void> {\r\n  const eeoSelectors: [string, RegExp][] = [\r\n    ['[data-automation-id=\"gender\"] select,select[data-automation-id=\"gender\"]', /decline|prefer not|not to say/i],\r\n    ['[data-automation-id=\"veteranStatus\"] select,select[data-automation-id=\"veteranStatus\"]', /not a protected|i am not|decline|prefer not/i],\r\n    ['[data-automation-id=\"disability\"] select,select[data-automation-id=\"disability\"]', /do not have|decline|prefer not/i],\r\n    ['[data-automation-id=\"ethnicityDropdown\"] select,select[data-automation-id=\"ethnicityDropdown\"]', /decline|prefer not|not to say/i],\r\n  ];\r\n  for (const [sel, pat] of eeoSelectors) {\r\n    const el = document.querySelector<HTMLSelectElement>(sel);\r\n    if (el && !el.value) {\r\n      const opt = Array.from(el.options).find(o => pat.test(o.textContent || ''));\r\n      if (opt) { el.value = opt.value; el.dispatchEvent(new Event('change', { bubbles: true })); }\r\n    }\r\n  }\r\n}\r\n\r\nasync function greenhouseFill(p: NormalizedProfile): Promise<void> {\r\n  LOG('Running Greenhouse-specific fill');\r\n  const responseEntries = await getResponseBank();\r\n  const GH_MAP: [string, string][] = [\r\n    ['#first_name,input[id*=\"first_name\"],input[name*=\"first_name\"]', p.first_name || ''],\r\n    ['#last_name,input[id*=\"last_name\"],input[name*=\"last_name\"]', p.last_name || ''],\r\n    ['#email,input[type=\"email\"],input[id*=\"email\"]', p.email || ''],\r\n    ['#phone,input[type=\"tel\"],input[id*=\"phone\"]', p.phone || ''],\r\n    ['input[id*=\"location\"],input[name*=\"location\"]', p.city || ''],\r\n    ['input[id*=\"linkedin\"],input[name*=\"linkedin\"]', p.linkedin_profile_url || ''],\r\n    ['input[id*=\"website\"],input[name*=\"website\"],input[id*=\"portfolio\"]', p.website_url || ''],\r\n    ['input[id*=\"github\"],input[name*=\"github\"]', p.github_url || ''],\r\n    ['textarea[id*=\"cover\"],textarea[name*=\"cover\"]', p.cover_letter || guessValue('cover letter', p)],\r\n  ];\r\n  for (const [sel, val] of GH_MAP) {\r\n    if (!val) continue;\r\n    const el = document.querySelector<HTMLInputElement>(sel);\r\n    if (el && isVisible(el) && !el.value?.trim()) { el.focus(); nativeSet(el, val); await sleep(50); }\r\n  }\r\n\r\n  // EEO selects\r\n  $$<HTMLSelectElement>('select[id*=\"gender\"],select[id*=\"disability\"],select[id*=\"veteran\"],select[id*=\"race\"],select[id*=\"ethnicity\"]')\r\n    .filter(sel => isVisible(sel) && !sel.value).forEach(sel => {\r\n      const opt = Array.from(sel.options).find(o =>\r\n        /decline|prefer not|not to say|not a protected|do not have/i.test(o.textContent || '')\r\n      );\r\n      if (opt) { sel.value = opt.value; sel.dispatchEvent(new Event('change', { bubbles: true })); }\r\n    });\r\n  LOG('Greenhouse fill done');\r\n}\r\n\r\nasync function oracleFill(p: NormalizedProfile): Promise<void> {\r\n  LOG('Running Oracle/Taleo-specific fill');\r\n  const fields: [string, string][] = [\r\n    ['#firstName,input[id*=\"firstName\"],input[name*=\"firstName\"]', p.first_name || ''],\r\n    ['#lastName,input[id*=\"lastName\"],input[name*=\"lastName\"]', p.last_name || ''],\r\n    ['input[type=\"email\"],input[id*=\"email\"]', p.email || ''],\r\n    ['input[type=\"tel\"],input[id*=\"phone\"],input[name*=\"phone\"]', p.phone || ''],\r\n    ['input[id*=\"city\"],input[name*=\"city\"]', p.city || ''],\r\n    ['input[id*=\"zip\"],input[name*=\"postal\"]', p.postal_code || ''],\r\n  ];\r\n  for (const [sel, val] of fields) {\r\n    if (!val) continue;\r\n    const el = document.querySelector<HTMLInputElement>(sel);\r\n    if (el && isVisible(el) && !el.value?.trim()) { el.focus(); nativeSet(el, val); await sleep(60); }\r\n  }\r\n  LOG('Oracle fill done');\r\n}\r\n\r\nasync function smartRecruitersFill(p: NormalizedProfile): Promise<void> {\r\n  LOG('Running SmartRecruiters-specific fill');\r\n  const fields: [string, string][] = [\r\n    ['input[name=\"first_name\"],#firstName', p.first_name || ''],\r\n    ['input[name=\"last_name\"],#lastName', p.last_name || ''],\r\n    ['input[name=\"email\"],input[type=\"email\"]', p.email || ''],\r\n    ['input[name=\"phone\"],input[type=\"tel\"]', p.phone || ''],\r\n    ['input[name=\"city\"]', p.city || ''],\r\n    ['input[name=\"web\"],input[name=\"website\"]', p.website_url || ''],\r\n    ['textarea[name=\"message\"],textarea[name=\"cover_letter\"]', p.cover_letter || guessValue('cover letter', p)],\r\n  ];\r\n  for (const [sel, val] of fields) {\r\n    if (!val) continue;\r\n    const el = document.querySelector<HTMLInputElement>(sel);\r\n    if (el && isVisible(el) && !el.value?.trim()) { el.focus(); nativeSet(el, val); await sleep(60); }\r\n  }\r\n  LOG('SmartRecruiters fill done');\r\n}\r\n\r\n// \u2500\u2500\u2500 Enhanced Fill Pass (Smart Guesser) \u2500\u2500\u2500\r\n// Fills any remaining empty fields using the smart guesser profile + response bank\r\nasync function enhancedFillPass(): Promise<number> {\r\n  const profile = await loadProfile();\r\n  const responseEntries = await getResponseBank();\r\n  let filled = 0;\r\n\r\n  // Text inputs and textareas\r\n  $$<HTMLInputElement | HTMLTextAreaElement>(\r\n    'input:not([type=hidden]):not([type=file]):not([type=submit]):not([type=checkbox]):not([type=radio]),textarea'\r\n  ).forEach(el => {\r\n    if (!isVisible(el) || hasFieldValue(el) || el.classList.contains('ua-filled')) return;\r\n    const label = smartGetLabel(el);\r\n    if (!label) return;\r\n    const val = guessFieldValue(label, profile, el, responseEntries);\r\n    if (val) {\r\n      el.focus();\r\n      nativeSet(el, val);\r\n      el.classList.add('ua-filled');\r\n      reportFieldFilled(label, 'filled');\r\n      filled++;\r\n    }\r\n  });\r\n\r\n  // Select dropdowns\r\n  $$<HTMLSelectElement>('select').forEach(sel => {\r\n    if (!isVisible(sel) || hasFieldValue(sel) || sel.classList.contains('ua-filled')) return;\r\n    const label = smartGetLabel(sel);\r\n    if (!label) return;\r\n    const val = guessValue(label, profile);\r\n    const opts = Array.from(sel.options);\r\n    let match: HTMLOptionElement | undefined;\r\n\r\n    if (val) {\r\n      // Exact match first\r\n      match = opts.find(o => (o.textContent || '').trim().toLowerCase() === val.toLowerCase());\r\n      // Partial match\r\n      if (!match) match = opts.find(o => (o.textContent || '').trim().toLowerCase().includes(val.toLowerCase()));\r\n    }\r\n\r\n    // EEO fallback: select \"Prefer not to say\" / \"Decline\"\r\n    if (!match) {\r\n      const l = label.toLowerCase();\r\n      if (/gender|ethnic|race|veteran|disabil|sex\\b|heritage/i.test(l)) {\r\n        match = opts.find(o => /prefer not|decline|not (wish|want)|choose not|do not have|i am not/i.test(o.textContent || ''));\r\n      }\r\n    }\r\n\r\n    // Last resort: pick the first valid option (non-placeholder)\r\n    if (!match) {\r\n      const validOpts = opts.filter(o => o.value && o.value !== '' && o.index > 0 &&\r\n        !/select|choose|please|--/i.test((o.textContent || '').trim()));\r\n      if (validOpts.length > 0 && isFieldRequired(sel)) {\r\n        match = validOpts[0];\r\n      }\r\n    }\r\n\r\n    if (match) {\r\n      sel.value = match.value;\r\n      sel.dispatchEvent(new Event('change', { bubbles: true }));\r\n      sel.classList.add('ua-filled');\r\n      reportFieldFilled(label, 'filled');\r\n      filled++;\r\n    }\r\n  });\r\n\r\n  // Radio button groups\r\n  const radioGroups = new Map<string, HTMLInputElement[]>();\r\n  $$<HTMLInputElement>('input[type=radio]').forEach(r => {\r\n    if (!isVisible(r)) return;\r\n    const name = r.name;\r\n    if (!name) return;\r\n    if (!radioGroups.has(name)) radioGroups.set(name, []);\r\n    radioGroups.get(name)!.push(r);\r\n  });\r\n  for (const [name, radios] of radioGroups) {\r\n    if (radios.some(r => r.checked)) continue; // Already selected\r\n    const label = smartGetLabel(radios[0]) || name;\r\n    const val = guessValue(label, profile);\r\n    let matched = false;\r\n\r\n    if (val) {\r\n      for (const radio of radios) {\r\n        const radioLabel = (radio.closest('label')?.textContent ||\r\n          document.querySelector(`label[for=\"${CSS.escape(radio.id)}\"]`)?.textContent ||\r\n          radio.value || '').trim().toLowerCase();\r\n        if (radioLabel.includes(val.toLowerCase()) || (val.toLowerCase() === 'yes' && /yes|true|accept/i.test(radioLabel))) {\r\n          realClick(radio);\r\n          reportFieldFilled(label, 'filled');\r\n          filled++;\r\n          matched = true;\r\n          break;\r\n        }\r\n      }\r\n    }\r\n\r\n    // Fallback: default to \"Yes\" for yes/no questions\r\n    if (!matched) {\r\n      const yesRadio = radios.find(r => {\r\n        const t = (r.closest('label')?.textContent ||\r\n          document.querySelector(`label[for=\"${CSS.escape(r.id)}\"]`)?.textContent ||\r\n          r.value || '').trim().toLowerCase();\r\n        return ['yes', 'true', '1'].includes(t);\r\n      });\r\n      if (yesRadio) {\r\n        realClick(yesRadio);\r\n        reportFieldFilled(label, 'filled');\r\n        filled++;\r\n      }\r\n    }\r\n  }\r\n\r\n  // Agreement checkboxes\r\n  $$<HTMLInputElement>('input[type=checkbox]').forEach(cb => {\r\n    if (cb.checked || !isVisible(cb)) return;\r\n    const label = smartGetLabel(cb);\r\n    if (/agree|acknowledge|certif|attest|confirm|consent|accept|terms|privacy/i.test(label)) {\r\n      realClick(cb);\r\n      reportFieldFilled(label, 'filled');\r\n      filled++;\r\n    }\r\n  });\r\n\r\n  // Required checkboxes that are still unchecked\r\n  $$<HTMLInputElement>('input[type=checkbox][required],input[type=checkbox][aria-required=\"true\"]')\r\n    .filter(cb => isVisible(cb) && !cb.checked)\r\n    .forEach(cb => { realClick(cb); filled++; });\r\n\r\n  return filled;\r\n}\r\n\r\n// \u2500\u2500\u2500 Full Autofill (for CSV queue / auto-trigger) \u2500\u2500\u2500\r\n// Runs the complete pipeline: tailoring \u2192 ATS fill \u2192 enhanced fill \u2192 resume upload \u2192 captcha \u2192 submit/next\r\nasync function runFullAutofill(): Promise<void> {\r\n  LOG('Starting full autofill pipeline');\r\n  const ats = detectATS(document);\r\n  const adapter = getAdapter(ats.type);\r\n  const responses = await getResponses();\r\n  const initialUrl = location.href;\r\n  let submitClickedTs = 0;\r\n  let reported = false;\r\n\r\n  const MAX_PAGES = 10;\r\n  const checkAndReport = () => {\r\n    if (reported) return;\r\n    const result = detectSuccess(initialUrl, submitClickedTs);\r\n    if (result === 'success') {\r\n      reported = true;\r\n      markApplied();\r\n      send({ type: 'COMPLEX_FORM_SUCCESS', message: 'Application submitted successfully' } as any);\r\n      LOG('Application submitted successfully!');\r\n    } else if (result === 'duplicate') {\r\n      reported = true;\r\n      send({ type: 'COMPLEX_FORM_ERROR', errorType: 'alreadyApplied', message: 'Already applied to this job' } as any);\r\n      LOG('Already applied to this job');\r\n    }\r\n  };\r\n\r\n  // Watch for success via MutationObserver\r\n  const successObserver = new MutationObserver(checkAndReport);\r\n  successObserver.observe(document.body, { childList: true, subtree: true });\r\n  const successInterval = setInterval(checkAndReport, 3000);\r\n  checkAndReport(); // Initial check\r\n\r\n  // Wait for page to settle\r\n  await sleep(3000);\r\n\r\n  // Notify sidebar\r\n  send({ type: 'SIDEBAR_STATUS', event: 'filling_form', atsName: ats.type, url: location.href } as any);\r\n\r\n  // Run ATS-specific navigation (click Apply buttons, etc.)\r\n  await runAtsNavigation(ats.type);\r\n\r\n  for (let page = 1; page <= MAX_PAGES; page++) {\r\n    if (reported) break;\r\n    LOG(`\u2500\u2500 Page ${page}/${MAX_PAGES}: Filling fields \u2500\u2500`);\r\n\r\n    // 1. ATS-specific fill\r\n    await atsSpecificFill(ats.type);\r\n\r\n    // 2. Standard adapter fill\r\n    await fillPage(adapter, responses, ats.type);\r\n\r\n    // 3. Enhanced fill (smart guesser for missed fields)\r\n    await enhancedFillPass();\r\n\r\n    // 4. Resume upload\r\n    await tryResumeUpload();\r\n\r\n    // 5. Captcha solving\r\n    await solveCaptcha();\r\n\r\n    // 6. Wait and retry for lazy-rendered fields\r\n    await sleep(2000);\r\n    if (reported) break;\r\n    await enhancedFillPass();\r\n\r\n    // 7. Count missing required fields\r\n    const missingLabels = getMissingRequiredFields();\r\n    const missingCount = missingLabels.length;\r\n\r\n    // Report missing fields\r\n    if (missingCount > 0) {\r\n      LOG(`${missingCount} required fields still missing:`, missingLabels);\r\n      missingLabels.forEach(n => reportFieldFilled(n, 'failed'));\r\n    }\r\n\r\n    // 8. Click submit or next\r\n    await sleep(1000);\r\n    if (reported) break;\r\n    const action = await tryClickSubmitOrNext(missingCount);\r\n\r\n    if (action === 'submitted') {\r\n      LOG('Submit clicked \u2014 waiting for success confirmation');\r\n      submitClickedTs = Date.now();\r\n      for (let i = 0; i < 15; i++) {\r\n        await sleep(1000);\r\n        if (reported) break;\r\n        checkAndReport();\r\n      }\r\n      if (!reported) {\r\n        LOG('No success confirmation after 15s \u2014 reporting done (submit was clicked)');\r\n        reported = true;\r\n        markApplied();\r\n        send({ type: 'COMPLEX_FORM_SUCCESS', message: 'Application submitted (submit clicked)' } as any);\r\n      }\r\n      break;\r\n    } else if (action === 'next_page') {\r\n      LOG('Next/Continue clicked \u2014 waiting for page transition');\r\n      send({ type: 'SIDEBAR_STATUS', event: 'filling_form', atsName: ats.type, url: location.href, page: page + 1 } as any);\r\n      await sleep(3000);\r\n      continue; // Loop to fill next page\r\n    } else {\r\n      LOG('No submit/next button found \u2014 final fill attempt');\r\n      await sleep(2000);\r\n      await enhancedFillPass();\r\n      const retry = await tryClickSubmitOrNext(0);\r\n      if (retry === 'submitted') {\r\n        submitClickedTs = Date.now();\r\n        for (let i = 0; i < 10; i++) {\r\n          await sleep(1000);\r\n          if (reported) break;\r\n          checkAndReport();\r\n        }\r\n        if (!reported) {\r\n          reported = true;\r\n          markApplied();\r\n          send({ type: 'COMPLEX_FORM_SUCCESS', message: 'Application submitted (final attempt)' } as any);\r\n        }\r\n      }\r\n      break;\r\n    }\r\n  }\r\n\r\n  // Cleanup\r\n  successObserver.disconnect();\r\n  clearInterval(successInterval);\r\n  LOG('Full autofill pipeline complete');\r\n}\r\n\r\nfunction countMissingRequired(): number {\r\n  return getMissingRequiredFields().length;\r\n}\r\n\r\n// \u2500\u2500\u2500 Auto-Trigger on ATS Detection \u2500\u2500\u2500\r\n// When the user lands on a supported ATS application page, manages tailoring-first flow.\r\n\r\nasync function autoTriggerAutofill(): Promise<void> {\r\n  if (_autoTriggerRunning || _autoTriggered || isRunning) return;\r\n\r\n  // Check if auto-trigger is enabled\r\n  const { ua_autoTrigger } = await chrome.storage.local.get('ua_autoTrigger');\r\n  if (ua_autoTrigger === false) return;\r\n\r\n  // Don't auto-trigger if CSV queue is managing this tab\r\n  const { csvActiveJobId } = await chrome.storage.local.get('csvActiveJobId');\r\n  if (csvActiveJobId) return;\r\n\r\n  const ats = detectATS(document);\r\n  if (ats.confidence < 0.3) return; // Not an ATS page\r\n\r\n  // Check if this is actually an application form\r\n  if (!isApplicationPage(ats.type)) {\r\n    LOG(`Auto-trigger: ${ats.type} detected but no application form yet`);\r\n    return;\r\n  }\r\n\r\n  _autoTriggerRunning = true;\r\n  _autoTriggered = true;\r\n  LOG(`Auto-trigger: ${ats.type} application form detected \u2014 starting pipeline`);\r\n\r\n  showControlBar();\r\n  updateControlBar(0, 0);\r\n  const statusEl = document.getElementById('ua-fill-status');\r\n  if (statusEl) statusEl.textContent = `${ats.type} detected \u2014 preparing...`;\r\n\r\n  try {\r\n    isRunning = true;\r\n\r\n    // \u2500\u2500\u2500 When Jobright sidebar is present, DO NOT auto-fill \u2500\u2500\u2500\r\n    // Our nativeSet fills corrupt the form's React state, causing Jobright's\r\n    // own Autofill to see fields as already filled while the form state says empty.\r\n    // This results in \"1 out of 14 required fields filled\". Let Jobright handle it.\r\n    const sidebar = detectJobrightSidebar();\r\n    if (sidebar || isTailoringAvailable()) {\r\n      LOG('Auto-trigger: Jobright sidebar detected \u2014 deferring to Jobright Autofill (no interference)');\r\n      isRunning = false;\r\n      _autoTriggerRunning = false;\r\n      return;\r\n    }\r\n\r\n    // \u2500\u2500\u2500 Run ATS navigation (click Apply buttons, etc.) \u2500\u2500\u2500\r\n    await runAtsNavigation(ats.type);\r\n\r\n    // \u2500\u2500\u2500 ATS-specific fill \u2500\u2500\u2500\r\n    await atsSpecificFill(ats.type);\r\n\r\n    // \u2500\u2500\u2500 Standard fill pass \u2500\u2500\u2500\r\n    const adapter = getAdapter(ats.type);\r\n    const responses = await getResponses();\r\n    await fillPage(adapter, responses, ats.type);\r\n    await enhancedFillPass();\r\n    await tryResumeUpload();\r\n    await solveCaptcha();\r\n\r\n    // Retry after 3s for lazy-rendering fields\r\n    await sleep(3000);\r\n    await enhancedFillPass();\r\n\r\n    // \u2500\u2500\u2500 Auto-submit / next page \u2500\u2500\u2500\r\n    const missingCount = countMissingRequired();\r\n    if (missingCount === 0) {\r\n      if (statusEl) statusEl.textContent = 'All fields filled \u2014 submitting...';\r\n      await sleep(1000);\r\n      const action = await tryClickSubmitOrNext(0);\r\n      if (action === 'submitted') {\r\n        if (statusEl) statusEl.textContent = 'Application submitted!';\r\n        markApplied();\r\n        send({ type: 'COMPLEX_FORM_SUCCESS', message: 'Application submitted' } as any);\r\n      } else if (action === 'next_page') {\r\n        if (statusEl) statusEl.textContent = 'Proceeding to next page...';\r\n        // Reset auto-trigger for next page\r\n        _autoTriggered = false;\r\n        _autoTriggerRunning = false;\r\n        await sleep(3000);\r\n        autoTriggerAutofill(); // Re-run for next page\r\n        return;\r\n      } else {\r\n        if (statusEl) statusEl.textContent = 'Autofill complete \u2014 review and submit';\r\n      }\r\n    } else {\r\n      if (statusEl) statusEl.textContent = `Autofill complete (${missingCount} fields need review)`;\r\n    }\r\n\r\n    LOG('Auto-trigger: complete');\r\n  } catch (err) {\r\n    LOG('Auto-trigger: error', err);\r\n  } finally {\r\n    _autoTriggerRunning = false;\r\n  }\r\n}\r\n\r\nfunction isApplicationPage(atsType: ATSType): boolean {\r\n  const url = location.href.toLowerCase();\r\n  const path = location.pathname.toLowerCase();\r\n\r\n  // URL-based detection\r\n  if (/\\/apply|\\/application|\\/jobs\\/\\d|\\/requisition/i.test(path)) return true;\r\n\r\n  // ATS-specific\r\n  if (atsType === 'workday') {\r\n    return url.includes('/apply') || document.querySelectorAll('[data-automation-id]').length > 2;\r\n  }\r\n  if (atsType === 'greenhouse') {\r\n    return !!document.querySelector('#application_form,form[action*=\"greenhouse\"],[data-provided-by=\"greenhouse\"]') ||\r\n      location.hostname.includes('boards.greenhouse.io');\r\n  }\r\n  if (atsType === 'lever') {\r\n    return !!document.querySelector('.posting-apply,.postings-form,.application-form') ||\r\n      location.hostname.includes('jobs.lever.co');\r\n  }\r\n  if (atsType === 'icims') {\r\n    return document.querySelectorAll('input:not([type=hidden])').length > 2;\r\n  }\r\n  if (atsType === 'smartrecruiters') {\r\n    return url.includes('/apply') || document.querySelectorAll('input[name]').length > 2;\r\n  }\r\n  if (atsType === 'taleo') {\r\n    return url.includes('/apply') || !!document.querySelector('#OracleFusionApp,oracle-apply-flow');\r\n  }\r\n  if (atsType === 'indeed') {\r\n    return path.includes('/viewjob') || path.includes('/applystart') ||\r\n      !!document.querySelector('#indeedApplyModal,.ia-container,[id*=\"indeedApply\"]');\r\n  }\r\n  if (atsType === 'linkedin') {\r\n    return path.includes('/jobs/view/') || path.includes('/jobs/collections/') ||\r\n      !!document.querySelector('.jobs-easy-apply-modal,[data-test-modal],.jobs-apply-button');\r\n  }\r\n  if (atsType === 'hiringcafe') {\r\n    return !!Array.from(document.querySelectorAll('a, button')).find(el =>\r\n      /apply directly|apply now/i.test((el as HTMLElement).textContent || '') && isVisible(el as HTMLElement)\r\n    );\r\n  }\r\n  if (atsType === 'ashby') {\r\n    return path.includes('/application') || !!document.querySelector('[data-ashby-form]');\r\n  }\r\n\r\n  // Generic: check for Apply button or form with name/email inputs\r\n  const hasApply = $$<HTMLElement>('a, button, [role=\"button\"]').some(el => {\r\n    const t = (el.textContent || '').trim().toLowerCase();\r\n    return /^(apply|apply now|apply directly|easy apply)\\b/.test(t) && isVisible(el);\r\n  });\r\n  if (hasApply) return true;\r\n\r\n  const hasName = !!document.querySelector('input[name*=\"name\" i],input[autocomplete=\"given-name\"]');\r\n  const hasEmail = !!document.querySelector('input[type=\"email\"],input[name*=\"email\" i],input[autocomplete=\"email\"]');\r\n  return hasName && hasEmail;\r\n}\r\n\r\n// \u2500\u2500\u2500 Missing Details Dialog Watcher \u2500\u2500\u2500\r\n// Auto-fills \"Add Missing Details\" dialogs that appear as modals\r\n\r\nlet _dialogFillDebounce: ReturnType<typeof setTimeout> | null = null;\r\nfunction watchMissingDetailsDialog(): void {\r\n  new MutationObserver(async () => {\r\n    if (_dialogFillDebounce) return;\r\n\r\n    const dialog = Array.from(document.querySelectorAll<HTMLElement>(\r\n      '[class*=\"missing\"],[id*=\"missing\"],[role=\"dialog\"],[class*=\"modal\"]'\r\n    )).find(el =>\r\n      isVisible(el) && /missing details|fill.*details|add.*details|fill.*form/i.test(el.textContent || '')\r\n    );\r\n\r\n    if (dialog) {\r\n      _dialogFillDebounce = setTimeout(() => { _dialogFillDebounce = null; }, 3000);\r\n      LOG('Missing details dialog detected \u2014 auto-filling');\r\n      await sleep(300);\r\n      await enhancedFillPass();\r\n      await sleep(700);\r\n      const btn = Array.from(dialog.querySelectorAll<HTMLElement>('button')).find(\r\n        el => isVisible(el) && /save|submit|continue|done|next|confirm/i.test(el.textContent || '')\r\n      );\r\n      if (btn) realClick(btn);\r\n    }\r\n  }).observe(document.body, { childList: true, subtree: true, attributes: false });\r\n}\r\n\r\n// \u2500\u2500\u2500 SPA Navigation Watcher \u2500\u2500\u2500\r\nlet _lastHref = location.href;\r\nsetInterval(() => {\r\n  if (location.href !== _lastHref) {\r\n    _lastHref = location.href;\r\n    _autoTriggered = false;\r\n    _autoTriggerRunning = false;\r\n    sleep(2000).then(() => autoTriggerAutofill());\r\n  }\r\n}, 1000);\r\n\r\n// \u2500\u2500\u2500 DOM Mutation Watcher for auto-trigger \u2500\u2500\u2500\r\nlet _mutationDebounce: ReturnType<typeof setTimeout> | null = null;\r\nconst _autoTriggerObserver = new MutationObserver(mutations => {\r\n  if (_autoTriggered || _autoTriggerRunning) return;\r\n  const added = mutations.reduce((n, m) => n + m.addedNodes.length, 0);\r\n  if (added < 2) return;\r\n  if (_mutationDebounce) clearTimeout(_mutationDebounce);\r\n  _mutationDebounce = setTimeout(() => autoTriggerAutofill(), 1500);\r\n});\r\nif (document.body) {\r\n  _autoTriggerObserver.observe(document.body, { childList: true, subtree: true });\r\n}\r\n\r\n// Initial auto-trigger after page load\r\nsleep(2500).then(() => autoTriggerAutofill());\r\n\r\n// Start watching for missing details dialogs\r\nif (document.body) watchMissingDetailsDialog();\r\n\r\n// \u2500\u2500\u2500 CSV Bridge Storage Listener (race-condition fallback) \u2500\u2500\u2500\r\nlet _csvBridgeStarted = false;\r\nif (typeof chrome !== 'undefined' && chrome.storage?.onChanged) {\r\n  chrome.storage.onChanged.addListener(async (changes, area) => {\r\n    if (area !== 'local' || _csvBridgeStarted) return;\r\n    const newJobId = changes.csvActiveJobId?.newValue;\r\n    const newTabId = changes.csvActiveTabId?.newValue;\r\n    if (newJobId && newTabId) {\r\n      _csvBridgeStarted = true;\r\n      LOG('CSV bridge: storage change detected \u2014 triggering autofill');\r\n      await sleep(3000);\r\n      runFullAutofill().catch(() => { });\r\n    }\r\n  });\r\n}\r\n\r\n// \u2500\u2500\u2500 DOM Mutation Fill Debounce (CSV mode) \u2500\u2500\u2500\r\nlet _csvFillDebounce: ReturnType<typeof setTimeout> | null = null;\r\nif (typeof chrome !== 'undefined' && chrome.storage?.local) {\r\n  new MutationObserver(async () => {\r\n    try {\r\n      const { csvActiveJobId } = await chrome.storage.local.get('csvActiveJobId');\r\n      if (!csvActiveJobId) return;\r\n      if (_csvFillDebounce) clearTimeout(_csvFillDebounce);\r\n      _csvFillDebounce = setTimeout(async () => {\r\n        await enhancedFillPass();\r\n        await solveCaptcha();\r\n      }, 800);\r\n    } catch { }\r\n  }).observe(document.body, { childList: true, subtree: false });\r\n}\r\n\r\nfunction isAlreadyFilled(el: HTMLElement): boolean {\r\n  if (el.classList.contains('ua-filled')) return true;\r\n  if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) {\r\n    return el.value.trim().length > 0;\r\n  }\r\n  if (el instanceof HTMLSelectElement) {\r\n    return el.selectedIndex > 0;\r\n  }\r\n  return false;\r\n}\r\n\r\n// \u2500\u2500\u2500 Control Bar (floating UI) \u2500\u2500\u2500\r\n\r\nfunction showControlBar() {\r\n  removeControlBar();\r\n  const bar = document.createElement('div');\r\n  bar.id = 'ua-control-bar';\r\n  bar.className = 'ua-control-bar';\r\n  bar.innerHTML = `\r\n    <span class=\"ua-status\">Ultimate Autofill</span>\r\n    <span id=\"ua-fill-status\" style=\"font-size:12px;color:#868e96;\">Scanning...</span>\r\n    <button class=\"ua-btn-stop\" id=\"ua-btn-stop\">Stop</button>\r\n  `;\r\n  document.body.appendChild(bar);\r\n  bar.querySelector('#ua-btn-stop')?.addEventListener('click', () => {\r\n    stopAutofill();\r\n  });\r\n}\r\n\r\nfunction updateControlBar(filled: number, total: number) {\r\n  const el = document.getElementById('ua-fill-status');\r\n  if (el) el.textContent = `${filled}/${total} fields filled`;\r\n}\r\n\r\nfunction removeControlBar() {\r\n  document.getElementById('ua-control-bar')?.remove();\r\n}\r\n\r\n// \u2500\u2500\u2500 Overlay for textarea / question suggestions \u2500\u2500\u2500\r\n\r\ndocument.addEventListener('focusin', async (e) => {\r\n  const el = e.target as HTMLElement;\r\n  if (!isTextareaLike(el)) return;\r\n  const label = getFieldLabel(el);\r\n  if (!label) return;\r\n  const r = await send({ type: 'GET_SUGGESTIONS', payload: { query: label, domain: location.hostname } });\r\n  if (r?.ok && r.data?.length) {\r\n    showSuggestionOverlay(el, r.data, label);\r\n  }\r\n}, true);\r\n\r\ndocument.addEventListener('focusout', (e) => {\r\n  setTimeout(() => {\r\n    const overlay = document.getElementById('ua-suggestion-overlay');\r\n    if (overlay && !overlay.matches(':hover')) overlay.remove();\r\n  }, 200);\r\n}, true);\r\n\r\nfunction isTextareaLike(el: HTMLElement): boolean {\r\n  if (el instanceof HTMLTextAreaElement) return true;\r\n  if (el.contentEditable === 'true') return true;\r\n  if (el instanceof HTMLInputElement && el.type === 'text') {\r\n    const label = getFieldLabel(el);\r\n    if (label && label.length > 30) return true;\r\n  }\r\n  return false;\r\n}\r\n\r\nfunction getFieldLabel(el: HTMLElement): string | null {\r\n  if (el.id) {\r\n    const lbl = document.querySelector(`label[for=\"${CSS.escape(el.id)}\"]`);\r\n    if (lbl?.textContent?.trim()) return lbl.textContent.trim();\r\n  }\r\n  const wrap = el.closest('label');\r\n  if (wrap?.textContent?.trim()) return wrap.textContent.trim();\r\n  const al = el.getAttribute('aria-label');\r\n  if (al?.trim()) return al.trim();\r\n  const ph = (el as HTMLInputElement).placeholder;\r\n  if (ph?.trim()) return ph.trim();\r\n  return null;\r\n}\r\n\r\nfunction showSuggestionOverlay(target: HTMLElement, suggestions: any[], label: string) {\r\n  document.getElementById('ua-suggestion-overlay')?.remove();\r\n  const overlay = document.createElement('div');\r\n  overlay.id = 'ua-suggestion-overlay';\r\n  overlay.className = 'ua-overlay';\r\n\r\n  const rect = target.getBoundingClientRect();\r\n  overlay.style.top = `${rect.bottom + window.scrollY + 4}px`;\r\n  overlay.style.left = `${rect.left + window.scrollX}px`;\r\n\r\n  let html = `<div class=\"ua-overlay-header